-- Poems batch 289
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('80d4b6c0-3cfb-409a-bdb1-d40b28439e40','過周墩堡','陳裔長','宋','宋诗','song-poetry','','[]','地坦容車馬，城空絕戍樓。',24,'全唐诗/poet.song.253000.json','["地坦容車馬，城空絕戍樓。", "幾家烟火在，風露冷松楸。"]'),
('bcdfd0c4-769f-47ad-94ee-ac9207d1b988','題鶴林宮','江南劍客','宋','宋诗','song-poetry','','[]','暑往寒來造化間，誰將大药駐朱顔。',64,'全唐诗/poet.song.253000.json','["暑往寒來造化間，誰將大药駐朱顔。", "騎鯨客去天連水，跨鶴人歸月滿山。", "爐火焰燒情慾境，劍峰割斷利名關。", "烟花隨分巖頭綠，猿鳥不驚春色閒。"]'),
('4515caad-0f6b-44c2-a47c-d4e58ed58a81','延福寺','張守質','宋','宋诗','song-poetry','','[]','步入禪關一徑賒，攝衣登眺夕陽斜。',64,'全唐诗/poet.song.253000.json','["步入禪關一徑賒，攝衣登眺夕陽斜。", "金谿碧落千條練，紫塔光涵五色霞。", "月繫扁舟漁火渡，風清古碣隠君家。", "遊人亦卧東山麓，醉倚烟蘿學種瓜。"]'),
('7294b295-0e43-42ab-8953-22a6a0f1d29f','秦君亭','傅宗教','宋','宋诗','song-poetry','','[]','隠君在何許，遺跡此山阿。',24,'全唐诗/poet.song.253000.json','["隠君在何許，遺跡此山阿。", "春風閉門處，回首空烟蘿。"]'),
('a3944180-247f-4140-90d4-d466d57792c4','思古堂','傅宗教','宋','宋诗','song-poetry','','[]','何人鑿山腹，高堂跨崔嵬。',36,'全唐诗/poet.song.253000.json','["何人鑿山腹，高堂跨崔嵬。", "悠悠百年事，滾滾隨塵埃。", "棄置君莫問，且復共此杯。"]'),
('766fc18f-b674-4a2d-951e-ca3c3ef18602','無名木','傅宗教','宋','宋诗','song-poetry','','[]','峨峨九日峰，下有千年木。',72,'全唐诗/poet.song.253000.json','["峨峨九日峰，下有千年木。", "正異歲寒姿，命受茲也獨。", "十圍鐵幹古，百尺虬髯矗。", "不以姓名顯，肯爲封爵辱。", "畏名如畏虎，終焉託巖伏。", "何當大厦求，一枝亦自足。"]'),
('2fc24d47-7738-4613-a78e-dbf9203a630b','廓然亭','梁知錄','宋','宋诗','song-poetry','','[]','危亭縹渺斗星傍，俯檻連雲掛碧蒼。',64,'全唐诗/poet.song.253000.json','["危亭縹渺斗星傍，俯檻連雲掛碧蒼。", "航快遠隨飛鳥下，樹穠陰覆酒樽凉。", "胡床坐久景方見，詩句評多味最長。", "况有青山對揮麈，每逢高論賞仇香。"]'),
('6718311e-60e3-49c6-91a0-9b58a0432347','普照寺','滕翔','宋','宋诗','song-poetry','','[]','海翻波浪遶危峰，無盡巖前此界空。',32,'全唐诗/poet.song.253000.json','["海翻波浪遶危峰，無盡巖前此界空。", "不是灰心求佛者，片時艱住寂寥中。"]'),
('37f539a7-1096-47af-b639-e6dbc1ae64a1','晉檜行','許彌安','宋','宋诗','song-poetry','','[]','紫極宮中晉朝檜，故老語我今千年。',112,'全唐诗/poet.song.253000.json','["紫極宮中晉朝檜，故老語我今千年。", "盤根厚地龍蛇走，榦薄霄漢星斗懸。", "玄冬飛雪斷人跡，貞姿不改平時妍。", "虬枝香葉翠如幄，一子不落含蒼煙。", "胡爲廣厦構梁棟，如此大材乃棄捐。", "伊昔晉朝紛亂日，衣冠南渡依江堧。", "風流王謝各幻化，肝膽鐵石還依然。"]'),
('d785a639-9eba-4808-89fc-8fb3fba4037b','大澤山','秦元似','宋','宋诗','song-poetry','','[]','古木巢遼鶴，陰崖溜石泉。',48,'全唐诗/poet.song.253000.json','["古木巢遼鶴，陰崖溜石泉。", "登臨多意緒，深邃好風烟。", "嘯傲欣離俗，徘徊覺近天。", "熒煌逼霄漢，疑是繼張騫。"]'),
('a20b5086-dbd3-475d-b343-5e0fb8119d9e','田橫墓','嬾雲','宋','宋诗','song-poetry','','[]','荒冢臨歧尚隠然，春風吹綠草芊芊。',32,'全唐诗/poet.song.253000.json','["荒冢臨歧尚隠然，春風吹綠草芊芊。", "牧兒亂唱黄昏後，猶似悲歌薤露篇。"]'),
('ca0345c1-8077-4a37-ad91-34f214a238c9','百家巖','竹林吟叟','宋','宋诗','song-poetry','','[]','明月池邊酌玉罍，玉罍未倒玉山頹。',32,'全唐诗/poet.song.253000.json','["明月池邊酌玉罍，玉罍未倒玉山頹。", "秋風吹斷華胥夢，卧看飛雲過嶺來。"]'),
('d3675681-b998-4c61-9bf3-d4f41c9b3638','遊天平山  其一','王疏','宋','宋诗','song-poetry','','[]','春雨新晴上翠微，三年兩過洞天扉。',32,'全唐诗/poet.song.253000.json','["春雨新晴上翠微，三年兩過洞天扉。", "塵蹤不得多時住，又向雲間一宿歸。"]'),
('91ccd6de-afb7-4f9b-a64a-9be8e973c99d','遊天平山  其二','王疏','宋','宋诗','song-poetry','','[]','勝景奇蹤爛漫遊，歸鞍欲上重回頭。',32,'全唐诗/poet.song.253000.json','["勝景奇蹤爛漫遊，歸鞍欲上重回頭。", "山禽於我情何厚，逐馬聲聲似見留。"]'),
('38742f39-c0ee-492d-9905-961577ad409e','流杯池','徐蘭皋','宋','宋诗','song-poetry','','[]','楚王宮闕馬王宮，惟有江山带舊風。',32,'全唐诗/poet.song.253000.json','["楚王宮闕馬王宮，惟有江山带舊風。", "屬玉不知興廢事，雙雙飛入藕花叢。"]'),
('b70e139c-8922-468e-969a-b6561e998203','過象州','蔣山卿','宋','宋诗','song-poetry','','[]','秦皇開象郡，茲事已千年。',48,'全唐诗/poet.song.253000.json','["秦皇開象郡，茲事已千年。", "臺古埋秋草，城荒起暮烟。", "江天雲漠漠，石嶺月娟娟。", "萬里慚漂泊，因風懷昔賢。"]'),
('3e190e72-4a53-451a-b217-750be280a61c','真仙巖','松庵道人','宋','宋诗','song-poetry','','[]','千巖萬壑倚晴空，此洞真奇迥不同。',32,'全唐诗/poet.song.253000.json','["千巖萬壑倚晴空，此洞真奇迥不同。", "未數洞天三十六，想移當日太清宮。"]'),
('cd65257b-31a6-4f59-879e-f2201df71457','萬春洞','李宗道','宋','宋诗','song-poetry','','[]','何山鑿出洞巖深，置屋懸崖映竹林。',64,'全唐诗/poet.song.253000.json','["何山鑿出洞巖深，置屋懸崖映竹林。", "像設金園崇梵宇，壁間石室塑觀音。", "接天遠岫巍千古，跨磵飛虹映百尋。", "極目憑欄多少景，一回到此一寒心。"]'),
('1be623c6-7e6e-459c-bdcd-a84a8cb122d4','沙岡待潮','游君傳','宋','宋诗','song-poetry','','[]','待潮舟閣淺邊岡，少憩田園竹樹凉。',32,'全唐诗/poet.song.253000.json','["待潮舟閣淺邊岡，少憩田園竹樹凉。", "數點弄秋疏雨過，槿花籬落带斜陽。"]'),
('dce841da-a943-4858-91b5-aebc3b846266','吳塘晚泊','游君傳','宋','宋诗','song-poetry','','[]','西風吹客鬢，孤坐欲銷魂。',48,'全唐诗/poet.song.253000.json','["西風吹客鬢，孤坐欲銷魂。", "野櫂他鄉客，酒旗何處村。", "稻隨秋雨熟，水带晚潮渾。", "寂寞吳塘路，塵沙望眼昏。"]'),
('a5995572-16d8-4728-9667-0e3180133183','遊圓通寺  其一','馬仲珍','宋','宋诗','song-poetry','','[]','十步九憩息，行行不計程。',48,'全唐诗/poet.song.253000.json','["十步九憩息，行行不計程。", "徑長人未盡，寺近地差平。", "古井知潮候，重雲隔磬聲。", "榴花半零落，碎糝石棋枰。"]'),
('f5912773-1987-43cd-9b20-ce01a527c80a','遊圓通寺  其二','馬仲珍','宋','宋诗','song-poetry','','[]','一筇吾事足，身世付科頭。',48,'全唐诗/poet.song.253000.json','["一筇吾事足，身世付科頭。", "漸長石間筍，半遮林杪樓。", "雲飛山欲動，木落塔如浮。", "遊客未歸去，松陰入茗甌。"]'),
('314a33a3-ab98-4171-b770-4212e899cba8','遊圓通寺  其三','馬仲珍','宋','宋诗','song-poetry','','[]','山空不隠響，一葉落還聞。',48,'全唐诗/poet.song.253000.json','["山空不隠響，一葉落還聞。", "龍去遺荒井，僧歸禮白雲。", "蟲絲昏畫壁，嵐氣濕爐薰。", "睡思渾無奈，茶甌易策勛。"]'),
('6b2cab38-214a-4750-a1a9-d41ae086fafb','遊圓通寺  其四','馬仲珍','宋','宋诗','song-poetry','','[]','欲坐又還起，白雲隨我行。',48,'全唐诗/poet.song.253000.json','["欲坐又還起，白雲隨我行。", "一空皆佛性，群動共秋聲。", "崩石斜分路，支岡半入城。", "明朝山下去，平地見朱甍。"]'),
('3bd1e588-9b71-4220-b2ac-093e454b52a7','遊圓通寺  其五','馬仲珍','宋','宋诗','song-poetry','','[]','老僧頭擁雪，領客下階行。',48,'全唐诗/poet.song.253000.json','["老僧頭擁雪，領客下階行。", "盡日坐山影，有時聞市聲。", "千峰平裹寺，一徑背通城。", "幽訪未成返，水中新月生。"]'),
('d18d118e-09f8-4832-82bd-db5b7aa583b5','舟次嚴灘','金涓','宋','宋诗','song-poetry','','[]','八月桐江曲，青蘋未著花。',48,'全唐诗/poet.song.253000.json','["八月桐江曲，青蘋未著花。", "亂雲低壓樹，細水淺流沙。", "到郭無多路，依山有幾家。", "故人成遠別，相望各天涯。"]'),
('379b9ae0-ef18-4eab-bdc3-e81f99537209','桐君山','李仲驤','宋','宋诗','song-poetry','','[]','水盡露嵌嶔，紅塵雜市音。',48,'全唐诗/poet.song.253000.json','["水盡露嵌嶔，紅塵雜市音。", "西來天日遠，東望白雲深。", "塔□中流見，漁燈半夜沉。", "烟波競名利，應負指桐心。"]'),
('312110e6-46df-43c4-81d1-4814b641a8d8','合江亭','李恭','宋','宋诗','song-poetry','','[]','一絲風下碧雲天，亭上窗開霽色鮮。',64,'全唐诗/poet.song.253000.json','["一絲風下碧雲天，亭上窗開霽色鮮。", "嚴子釣臺青樹裏，桐君丹竈白雲邊。", "千家畫棟前朝屋，百里清江過客船。", "瀟灑桐廬幾興廢，野花山鳥自年年。"]'),
('9cbfa78e-11e3-4b91-9aa8-1a6341b226d9','送葉大尹廷衡','盧茂','宋','宋诗','song-poetry','','[]','雞犬無譁四境同，桑麻百里長春風。',32,'全唐诗/poet.song.253000.json','["雞犬無譁四境同，桑麻百里長春風。", "熙熙安養知誰力，父老相逢說魯恭。"]'),
('c1540b2d-cdcc-4592-9bd2-e89305c3072d','訪陶山寺','石世英','宋','宋诗','song-poetry','','[]','深谷不易到，烟霞真勝遊。',48,'全唐诗/poet.song.253000.json','["深谷不易到，烟霞真勝遊。", "翻身渺雲海，長嘯落滄洲。", "曙色楓林曉，天香桂子秋。", "更期南澗石，重約泛浮丘。"]'),
('59fa5919-d7f0-4417-92d6-85ae03483a4b','游均慶寺','李咸','宋','宋诗','song-poetry','','[]','一方靈跡兩峰間，左右芒山與碭山。',64,'全唐诗/poet.song.253000.json','["一方靈跡兩峰間，左右芒山與碭山。", "勝地昔曾鍾王氣，高僧誰此掩柴關。", "翬飛巍殿烟瓴碧，翠削層崖苔蘚斑。", "千古英雄無處問，嶺頭依舊白雲閒。"]'),
('a39aa364-50e4-48ee-a3d1-b6effb146ff9','松嶺','丁大容','宋','宋诗','song-poetry','','[]','十里城西松嶺庵，每經過此便懷慚。',32,'全唐诗/poet.song.253000.json','["十里城西松嶺庵，每經過此便懷慚。", "此山若有歸耕地，肯墜嵇康七不堪。"]'),
('d3471484-0610-4dee-91aa-b7ad45771642','題九仙閣','康鼎成','宋','宋诗','song-poetry','','[]','久學秦人避，空聞漢主求。',48,'全唐诗/poet.song.253000.json','["久學秦人避，空聞漢主求。", "丹鑪無鳳髓，石室有龍湫。", "谷挾千峰雨，湖生六月秋。", "塵蹤應自息，長嘯下溪鷗。"]'),
('00fd50eb-3457-4562-9157-62ec4d76f524','題九仙宮','高獻民','宋','宋诗','song-poetry','','[]','迢遞尋真到紫壇，參差樓閣倚層巒。',64,'全唐诗/poet.song.253000.json','["迢遞尋真到紫壇，參差樓閣倚層巒。", "三株樹古巢玄鶴，五粒松低下素鸞。", "烟暖芝田應有玉，樹封藥竈已無丹。", "昔人跨鯉歸何處，彷彿中天月影寒。"]'),
('74669d64-68e5-4069-b102-2c4251a06895','題九仙宮','龔伯摴','宋','宋诗','song-poetry','','[]','桃花流水隔人間，千古高風不可攀。',64,'全唐诗/poet.song.253000.json','["桃花流水隔人間，千古高風不可攀。", "綠樹陰中孤鶴宿，碧潭深處九龍蟠。", "雨餘芝朮香丹室，夜半風雲繞石壇。", "富貴由來天有命，何勞清夢到邯鄲。"]'),
('4c4a23b5-e7ad-4379-8060-a217e8c66c3f','題九仙宮','李德馨','宋','宋诗','song-poetry','','[]','倚天峭壁屹崔巍，觸石飛湍怒震雷。',64,'全唐诗/poet.song.253000.json','["倚天峭壁屹崔巍，觸石飛湍怒震雷。", "一鏡澄清涵宇宙，四圍空翠映樓臺。", "煉丹道士老無寐，跨鯉仙人去不來。", "掃却平生塵土夢，此身便是小蓬萊。"]'),
('be9c9fdf-ef49-4c10-b067-67c95e239bc4','行部仙遊','陳效','宋','宋诗','song-poetry','','[]','碧山如畫豁吟眸，信是神仙此地遊。',64,'全唐诗/poet.song.253000.json','["碧山如畫豁吟眸，信是神仙此地遊。", "九鯉有人爭乞夢，一麾無事獨登樓。", "田中水白秧初雨，隴上雲黄麥已秋。", "民困祇今蘇息否，我來端不爲花謀。"]'),
('df137d7f-f731-4217-bd68-78cec203121e','蕉溪溫泉','顔克宗','宋','宋诗','song-poetry','','[]','陰陽炭兮天地爐，融液好景人間無。',96,'全唐诗/poet.song.253000.json','["陰陽炭兮天地爐，融液好景人間無。", "木酸火炎兩不用，清流自沸跳明珠。", "何當揚波激滄溟，大塊不許氛翳生。", "何當翻波湔酷吏，群黎坐使心眼明。", "堯舜君民均一視，匹夫匹婦皆使被。", "洗除煩苛不擇地，奚止一泓而已矣。"]'),
('2d3158ad-27ef-4db0-80bc-51cc3a4e0c6e','康仙祠','釋寶玄','宋','宋诗','song-poetry','','[]','南望青山十里賒，五雲深處問琵琶。',32,'全唐诗/poet.song.253000.json','["南望青山十里賒，五雲深處問琵琶。", "從知天子封侯廟，原是神仙賣藥家。"]'),
('7a7469c2-6285-4725-8f45-cc028b4c047c','題崇明寺','魯千之','宋','宋诗','song-poetry','','[]','心情稍覺難如舊，勝迹依然日月新。',32,'全唐诗/poet.song.253000.json','["心情稍覺難如舊，勝迹依然日月新。", "鶴怨猿驚嗟往事，再來山色似迎人。"]'),
('c8f5b099-1cd3-4626-8adf-490a61926aef','黄龍洞','謝圖南','宋','宋诗','song-poetry','','[]','山水盤桓天地中，幾多異事出仙宮。',32,'全唐诗/poet.song.253000.json','["山水盤桓天地中，幾多異事出仙宮。", "玉龍嘶斷黄龍現，劍氣曾凌上大空。"]'),
('330d2c3d-aefd-4107-bd44-23eb7d9fff2c','題明皇','徐秋雲','宋','宋诗','song-poetry','','[]','太平風月屬三郎，羯鼓聲高思轉長。',64,'全唐诗/poet.song.253000.json','["太平風月屬三郎，羯鼓聲高思轉長。", "天子錦纏娛虢國，貴妃音律教寧王。", "人歸巫峽山容在，花落溫泉水更香。", "誰信蓬萊青鳥使，回來無語怨漁陽。"]'),
('b4d2f389-ada9-4ee2-8432-fc682f02a563','恩德寺','朴通','宋','宋诗','song-poetry','','[]','平昔常聞風水洞，重山複水去無窮。',32,'全唐诗/poet.song.253000.json','["平昔常聞風水洞，重山複水去無窮。", "因緣偶入雲泉路，林下先聞接客鐘。"]'),
('4e99bb2d-5e0e-4200-b5ca-db2a4e2f7c24','寧國院','烏允卿','宋','宋诗','song-poetry','','[]','精舍蕭然絕世塵，登臨漸覺爽精神。',64,'全唐诗/poet.song.253000.json','["精舍蕭然絕世塵，登臨漸覺爽精神。", "庭連翠島松篁暗，沼接清流瀑布新。", "高潔白雲長作侶，幽閒明月每爲親。", "開窗更有消煩景，猿鶴無機解伴人。"]'),
('d81926c3-a29c-425a-9fc9-2411a9070095','東鶩山石洞','劉浚','宋','宋诗','song-poetry','','[]','滿山雲雨蛟龍走，萬壑風烟虎豹通。',32,'全唐诗/poet.song.253000.json','["滿山雲雨蛟龍走，萬壑風烟虎豹通。", "巖竇石泉流出冷，草庵禪影坐來空。"]'),
('f4e75f31-ae93-4088-ade1-3adf4a59b97b','墨','鄧熛','宋','宋诗','song-poetry','','[]','一寸龍香一寸金，仙家傳藥不傳心。',32,'全唐诗/poet.song.253000.json','["一寸龍香一寸金，仙家傳藥不傳心。", "得來莫作尋常看，千載文光翰苑林。"]'),
('8fe71583-bbd1-4397-95e6-ddbfa3f7e643','題玉翠樓','吳虎','宋','宋诗','song-poetry','','[]','玉樓高倚漢昌城，處士閒居不可名。',64,'全唐诗/poet.song.253000.json','["玉樓高倚漢昌城，處士閒居不可名。", "天際山青疑泰岱，雲邊木落見長庚。", "開簾曉挹晴光滿，策杖秋吟爽氣迎。", "我欲巢雲向西竺，何時風月話三生。"]'),
('c38c8e8b-ab12-43c1-9098-1e9300537fc7','自吟','徐釣者','宋','宋诗','song-poetry','','[]','曾見秦王架石橋，海仙忙迫漲驚潮。',32,'全唐诗/poet.song.253000.json','["曾見秦王架石橋，海仙忙迫漲驚潮。", "蓬萊隔海雖難到，直好三清却不遥。"]'),
('555cf2a1-2481-4a11-b9d9-0c5fa44c3178','龍巖山','石泳堅','宋','宋诗','song-poetry','','[]','茫茫天地老洪崖，太樸何年此鑿開。',32,'全唐诗/poet.song.253000.json','["茫茫天地老洪崖，太樸何年此鑿開。", "一派靈源流不盡，教人疑是九天來。"]'),
('749df98c-dfef-47ed-8500-273a9c2c2da5','龍隠洞','林穀','宋','宋诗','song-poetry','','[]','崢嶸頭角隠何年，直露靈光在此間。',32,'全唐诗/poet.song.253000.json','["崢嶸頭角隠何年，直露靈光在此間。", "天下蒼生方引領，好施膏雨潤人寰。"]'),
('003fc92a-6cc5-4afd-84d9-27e4329ff1a6','湘山寺','郝顯','宋','宋诗','song-poetry','','[]','偃蹇蒼松鎖翠巖，邦人云是古湘山。',64,'全唐诗/poet.song.253000.json','["偃蹇蒼松鎖翠巖，邦人云是古湘山。", "寺穿石磴高低處，塔聳雲烟吞吐間。", "物外豈知塵世事，箇中只許老僧閒。", "我來策杖登臨罷，落日歸鴉自往還。"]'),
('3efe37f7-9d68-41cc-af13-4bd1a97c53cb','周公亭留題','無名氏','宋','宋诗','song-poetry','','[]','人言周公來結宇，不知建立何年中。',32,'全唐诗/poet.song.253000.json','["人言周公來結宇，不知建立何年中。", "撰詞仍是謫御史，殘缺欲讀嗟難通。"]'),
('eb0a571f-5cef-4760-a317-f3f609d0a05c','題几','谷客','宋','宋诗','song-poetry','','[]','蓬島三山在寸心，先生何事混凡塵。',32,'全唐诗/poet.song.253000.json','["蓬島三山在寸心，先生何事混凡塵。", "不因門外家人謹，還是無緣遇洞賓。"]'),
('4ef461ea-2785-43df-8493-1e15d817c609','吟','牧得清','宋','宋诗','song-poetry','','[]','完得一局棋，除此一襲衣。',24,'全唐诗/poet.song.253000.json','["完得一局棋，除此一襲衣。", "何去何來兮，白雲共依稀。"]'),
('0b5714b5-a412-4867-95a8-ead900d7adde','望太湖','蘇頔','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','杳杳波濤閲古今，四邊無際莫知深。',64,'全唐诗/poet.song.253000.json','["杳杳波濤閲古今，四邊無際莫知深。", "潤通曉月爲清露，氣入霜天作溟陰。", "笠澤鱸肥人膾玉，洞庭柑熟客分金。", "風烟觸目相招隠，聊爲停橈一楚吟。"]'),
('926fd363-c0e3-42b0-a0a9-89311d649450','題荆溪圖','張監','宋','宋诗','song-poetry','','[]','斬蛟橋北玉樞府，高樹連雲第一家。',32,'全唐诗/poet.song.253000.json','["斬蛟橋北玉樞府，高樹連雲第一家。", "欲向新圖問何處，客窗風雨對梨花。"]'),
('b571ae93-989a-4378-aff2-7395beff28b4','題宜興迎華驛','無名氏','宋','宋诗','song-poetry','','[]','家問不來秋夜長，白鷗眠處倚牙檣。',64,'全唐诗/poet.song.253000.json','["家問不來秋夜長，白鷗眠處倚牙檣。", "風摇湖水動山影，天壓隴雲低雁行。", "菊老過時猶嚼蕊，魚逃無水尚鳴榔。", "洗兵馬詔何時下，免遣農夫坐女牆。"]'),
('4e0201f7-049d-4f58-a8a4-f9ed63f1913b','𠙶山曉雲歌','袁正','宋','宋诗','song-poetry','','[]','大坤濕氣蒸嵷巃，油然勃然連蒼穹。',192,'全唐诗/poet.song.253000.json','["大坤濕氣蒸嵷巃，油然勃然連蒼穹。", "曙窗注望東𠙶峰，須臾不見青芙蓉。", "初疑博山噴出紫烟縷，又疑蜃精海底推起龍王宮。", "東西模糊總一色，上下變幻知幾重。", "既非芒碭山中隠劉季，又非陽臺神女遥相通。", "養文玄豹隠丹壑，失巢老鶴迷青松。", "忽見千株萬株老枯檜，化作千丈萬丈蒼精龍。", "斷崖滴翠時灑灑，落花細雨春濛濛。", "金烏欲上海水赤，神光盪射生青紅。", "狂飈捲地忽吹散，依然繡出金屏風。", "奇奇怪怪渺無際，且將浩興收拾填心胸。"]'),
('3744c2d6-7149-4486-8091-5415fd345bc3','貞義女祠','蔣時中','宋','宋诗','song-poetry','','[]','幼年曾讀貞女碑，坐想瀨水清漣漪。',64,'全唐诗/poet.song.253000.json','["幼年曾讀貞女碑，坐想瀨水清漣漪。", "試來江東弔李白，瓣香敬謁貞女祠。", "平生不數子胥子，鞭平進諸何至此。", "有金投瀨竟何爲，當時豈爲將軍死。"]'),
('aa3f0034-1744-496d-b888-0c397a8775e9','黄山觀','蔣時中','宋','宋诗','song-poetry','','[]','黄鶴山中黄鶴觀，黄鶴仙人此修煉。',64,'全唐诗/poet.song.253000.json','["黄鶴山中黄鶴觀，黄鶴仙人此修煉。", "功成羽化歸丹丘，環佩珊珊度遥漢。", "昔聞有鳥名令威，去家千年今來歸。", "仙人一去不復返，長松落雪秋霏霏。"]'),
('dc301544-a53a-486a-920e-248898a798ab','雲湖山','任安','宋','宋诗','song-poetry','','[]','雲中丹井出天然，白石當年煮尚堅。',32,'全唐诗/poet.song.253000.json','["雲中丹井出天然，白石當年煮尚堅。", "洗耳不留塵世事，松陰高居伴神仙。"]'),
('2a24c8ed-2103-4a7d-9705-7a5afeabf1c0','妙相寺方丈','徐銳','宋','宋诗','song-poetry','','[]','脚力無窮爲好山，直須勾引到禪關。',64,'全唐诗/poet.song.253000.json','["脚力無窮爲好山，直須勾引到禪關。", "柳堤雪後摇金縷，竹徑風前弄翠環。", "宦業始知紅葉落，清游終羨白雲閑。", "此來不見文殊面，多謝巖花慰我顔。"]'),
('6ee7e6a1-6664-41ca-97c2-9a4a9d799786','次太白水西韻','陳柄','宋','宋诗','song-poetry','','[]','涇巘翠插天，涇溪清繞郭。',96,'全唐诗/poet.song.253000.json','["涇巘翠插天，涇溪清繞郭。", "巒環松竹裏，崖磴自樓閣。", "是時秋陽驕，三日此棲泊。", "曉色林端來，晴雲巖際落。", "飛梯接絕壁，畫柱裹枯籜。", "誰拂梁間塵，謫仙久不作。", "予生捉月姿，方寸頗明廓。", "思君騎鯨魚，赴我千金諾。"]'),
('4dd0229f-d7bc-4c34-89f0-f52aead0eacd','句','哀謙','宋','宋诗','song-poetry','','[]','時人不識田園樂，只羨相如駟馬歸。',16,'全唐诗/poet.song.253000.json','["時人不識田園樂，只羨相如駟馬歸。"]'),
('df46fcd3-36d6-4db4-9545-a09bb89fe39b','磨崖頌','吳杭','宋','宋诗','song-poetry','','[]','周雅久不復，楚騷方獨鳴。',108,'全唐诗/poet.song.253000.json','["周雅久不復，楚騷方獨鳴。", "溪蛙弄氣態，污我瀟湘清。", "二公好奇古，大筆時縱橫。", "磨崖勒唐頌，字字飛瓊英。", "雲烟借體勢，水石生光精。", "浯溪在僻地，自是聞正聲。", "名傳播夷夏，孰貴燕然銘。", "絃歌入商魯，永與神仙聽。", "江流不可竭，此文如日星。"]'),
('79f63c52-05e4-4a51-8d22-f4774127ad7f','題澹巖','朱正一','宋','宋诗','song-poetry','','[]','秦曾羽客駐真跧，唐有禪翁嗣結緣。',64,'全唐诗/poet.song.253000.json','["秦曾羽客駐真跧，唐有禪翁嗣結緣。", "石竇宏深開洞府，天門明顯逗風煙。", "香山聳迹停危壁，怪木盤根長絕巔。", "千古靈蹤誰可問，踟躕瞻想不知還。"]'),
('b9df41fe-f057-4ab4-919f-f51f9e3f2a60','寄呂伯祐','周錫','宋','宋诗','song-poetry','','[]','龍門居士隠江濱，老去風流樂事真。',64,'全唐诗/poet.song.253000.json','["龍門居士隠江濱，老去風流樂事真。", "觴詠又臨三月暮，李桃初種一溪春。", "眼中信我無餘子，名下如君有幾人。", "淯溪不盡東流水，兩字平安託錦鱗。"]'),
('2692b70a-c3d6-4e98-aaf5-4cc6a9fcb4c6','采蓮曲','俞君宣','宋','宋诗','song-poetry','','[]','小姨學采蓮，兩腕白於雪。',110,'全唐诗/poet.song.253000.json','["小姨學采蓮，兩腕白於雪。", "花色妬緗裙，瓣瓣紅如血。", "西鄰小姑亦采蓮，隔岸徒聞語笑喧。", "從來不相識，相呼好並船。", "停橈花下勤把手，他年何處投箕帚。", "苦樂參差不可言，此日花開得來否。", "難割藕絲腸，怕逢遊冶郎。", "歸去風吹小簟凉，時聞花外香。"]'),
('94888132-fe5a-438c-9aaa-d67f5c72cc69','登翠微亭  其一','余迪','宋','宋诗','song-poetry','','[]','數年樂此宦池城，每愛湖光分外清。',64,'全唐诗/poet.song.253000.json','["數年樂此宦池城，每愛湖光分外清。", "遠浦落霞秋水闊，亂山斜日碧雲橫。", "牧吹牛背歸林晚，漁唱舟中對月明。", "同覽翠微重弔古，謾將詩酒逐交情。"]'),
('6a662b8d-eeee-4c07-8ab7-37398e398ccd','登翠微亭  其二','余迪','宋','宋诗','song-poetry','','[]','池陽勝跡翠微峰，今古才人咏不窮。',64,'全唐诗/poet.song.253000.json','["池陽勝跡翠微峰，今古才人咏不窮。", "僧寺宛如仙仗裏，人家儼若畫圖中。", "迎風楊柳依依綠，带雨桃花淡淡紅。", "沉醉不知歸去晚，匆匆回首月升東。"]'),
('9367eb83-b250-4d77-9bc5-fd6d48a4d1ea','白鶴梁觀石魚','高應乾','宋','宋诗','song-poetry','','[]','訪勝及春遊，雙魚古石留。',48,'全唐诗/poet.song.253000.json','["訪勝及春遊，雙魚古石留。", "能觀時顯晦，不逐浪沉浮。", "守介難投餌，呈祥類躍舟。", "胥歸霖雨望，千載砥中流。"]'),
('24311625-a318-4141-bff0-635848bba494','題涪州石魚','楊郡守','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','邀客西津上，觀魚出水初。',72,'全唐诗/poet.song.253000.json','["邀客西津上，觀魚出水初。", "長江多巨石，此地近仙居。", "所記皆名筆，爲祥舊□書。", "豐年知有驗，遺秉利將舒。", "戲草春波靜，雙鱗樂意徐。", "不才叨郡寄，燕喜愧蕭疏。"]'),
('116c89cc-a7a5-4bc9-a553-0b4a9405ce92','題九龍巖','李得之','宋','宋诗','song-poetry','','[]','靄靄雲□爛，岑岑洞穴幽。',48,'全唐诗/poet.song.253000.json','["靄靄雲□爛，岑岑洞穴幽。", "黄衣無□士，陳迹□千秋。", "本爲征途憩，還因爽氣留。", "塵緣吾未斷，歸路晚颼飀。"]'),
('530e631b-2c9a-4428-b955-ee8478482fa3','留題九龍巖','陳某','宋','宋诗','song-poetry','','[]','里俗相傳有九龍，昔年栖隠此巖中。',64,'全唐诗/poet.song.253000.json','["里俗相傳有九龍，昔年栖隠此巖中。", "煙霄一去□□隔，石戶雙開舊徑通。", "月影日光東北近，泉聲山色古今同。", "何當便脫卑凡累，來伴僧閑論苦空。"]'),
('b7bf7b66-68d2-4587-bb10-1ba7231986e4','寄子','章某','宋','宋诗','song-poetry','','[]','九十衰翁七十兒，此時那可兩分離。',64,'全唐诗/poet.song.253000.json','["九十衰翁七十兒，此時那可兩分離。", "客鄉已是三年別，人世應無百歲期。", "春雁北飛頻送目，夕陽西下幾顰眉。", "何如及早成歸計，莫待山榴開滿枝。"]'),
('ec5176ac-f9da-4816-a333-7c49623001a1','詠古樹','無名氏','宋','宋诗','song-poetry','','[]','四圍喬木盡兒孫，曾見吳宮幾度春。',32,'全唐诗/poet.song.253000.json','["四圍喬木盡兒孫，曾見吳宮幾度春。", "若使當年成大厦，也應隨例作灰塵。"]'),
('99702b2a-c022-44cb-b7fd-d06a98f64a85','寄家書','無名氏','宋','宋诗','song-poetry','','[]','南軒北牖又東扉，取次園林待我歸。',32,'全唐诗/poet.song.253000.json','["南軒北牖又東扉，取次園林待我歸。", "當路莫栽荆棘草，他年免掛子孫衣。"]'),
('519e208c-2044-4b23-8210-f71d5c90ea5d','留題宣聖廟石壁','張紳','宋','宋诗','song-poetry','','[]','前枕清流後倚山，殿堂高創白雲間。',32,'全唐诗/poet.song.253000.json','["前枕清流後倚山，殿堂高創白雲間。", "幸因供職頻經此，及過三年鬢漸班。"]'),
('b9957368-2d33-45fc-9a91-c2842e2b3e82','句','李伯先','宋','宋诗','song-poetry','','[]','一門萃忠孝，竹帛寫家聲。',12,'全唐诗/poet.song.253000.json','["一門萃忠孝，竹帛寫家聲。"]'),
('a955cbf2-19dc-4020-9240-6627dba1dfff','堆婆石','許仕叔','宋','宋诗','song-poetry','','[]','撐空疊石何嵯峨，世傳其名曰堆婆。',247,'全唐诗/poet.song.253000.json','["撐空疊石何嵯峨，世傳其名曰堆婆。", "乃在淛嶺之巔，吳山之阿。", "我來於此少憩息，借問父老元如何。", "父老爲言五代時，有婆姓方氏結茅嶺巔兩鬢皤。", "爲念往來渴，均施湯水無偏頗。", "行人以此盡感激，婆言吾亦期無他。", "早晚吾骨只堆此，願將一石堆吾坡。", "爾來迄今四百載，行人堆石不少差。", "我亦拾石堆其冢，既行且歎復逶迤。", "今冢之高過百尺，堆石亦已豈虛過。", "乃知一飲一滴水，恩至久遠不可磨。", "古人一飲在必報，如此傳說夫豈訛。", "吁嗟俗世人，乃道無恩波。", "反恩以爲讎，此語愚已多。", "我適來此秋向晚，滿屨霜葉仍吟哦。", "因筆記此堆婆石，慷慨爲賦堆婆歌。"]'),
('bae5688a-bc6b-44e7-bb44-735226723c93','漢嚴將軍廟','聞肇瑝','宋','宋诗','song-poetry','','[]','漢史標名氏，宕梁存慕丘。',96,'全唐诗/poet.song.253000.json','["漢史標名氏，宕梁存慕丘。", "非惟能抗節，更獨抱先憂。", "全蜀悲銜璧，孤身欲斷頭。", "湍奔砥柱屹，果碩剝陽留。", "片語消威猛，三軍盡輯柔。", "詞嚴偏藹若，氣正一何遒。", "廟貌旒垂冕，祀將春復秋。", "我來虔展拜，匪敢謂遨遊。"]'),
('e3eb80ec-8748-4cbb-86ea-fa20bb24640b','武侯祠','張瓚','宋','宋诗','song-poetry','','[]','帝城誰送應商金，故壘蕭蕭歲月深。',64,'全唐诗/poet.song.253000.json','["帝城誰送應商金，故壘蕭蕭歲月深。", "山勢北來連鳥道，水聲東去作龍吟。", "西風老樹惟寒鵲，落日荒郊只暮砧。", "不有少陵詩句在，草堂何處共追尋。"]'),
('a5eb4e73-749f-493d-a319-c7ad92a2585d','遊南山賦五十六言呈書記郎中教授大著','馬某','宋','宋诗','song-poetry','','[]','暇時結客小舂容，路值重巖紫翠峰。',64,'全唐诗/poet.song.253000.json','["暇時結客小舂容，路值重巖紫翠峰。", "雲閣翬飛翼鸞鳳，石柟盤屈老虬龍。", "林扉雨過便秋菊，山寺風清度晚鐘。", "快展眉頭須劇飲，天開霽色不妨農。"]'),
('0eaa7928-99f1-4ca8-8362-75d4dee275c4','懷古','□庭倚','宋','宋诗','song-poetry','','[]','宦海漂浮若轉蓬，唯餘訪古意無窮。',64,'全唐诗/poet.song.253000.json','["宦海漂浮若轉蓬，唯餘訪古意無窮。", "曾觀老柏懷諸葛，今對古柟思鄭公。", "遺憾已隨流水遠，英名仍伴故山雄。", "後來碌碌空千輩，誰許登臨繼此風。"]'),
('209d7aa2-da15-4d7a-8e23-86d4a2028b40','次庭倚懷古韻','□公才','宋','宋诗','song-poetry','','[]','一本修柟出萬蓬，挺生綿邈尚誰窮。',64,'全唐诗/poet.song.253000.json','["一本修柟出萬蓬，挺生綿邈尚誰窮。", "胡爲壯烈思嚴老，雅愛甘棠學召公。", "懷德自應存芘蔭，企賢那不念英雄。", "要知遺躅傳無盡，時聽龕巖度遠風。"]'),
('1d4e4ef7-7cf7-46ad-9bc4-f7897f4aa407','和郭使君韻','無名氏','宋','宋诗','song-poetry','','[]','郭侯凜凜氣橫秋，管領江山作勝遊。',64,'全唐诗/poet.song.253000.json','["郭侯凜凜氣橫秋，管領江山作勝遊。", "痛飲不知烏景墜，清歌更覺鳥聲幽。", "誦君崖畔神仙句，淡我胸中浩蕩愁。", "萬里相逢更相失，他年卜築共歸休。"]'),
('0518841b-0dcd-4e34-b7a6-21ef9ace9931','新月','黄蛾','宋','宋诗','song-poetry','','[]','初出如弓未上弦，分明掛在碧雲邊。',32,'全唐诗/poet.song.253000.json','["初出如弓未上弦，分明掛在碧雲邊。", "時人莫道蛾眉小，十五團圓照滿天。"]'),
('6a94b74c-8b45-43a6-be33-8f406f47e5ef','題三洞','張大直','宋','宋诗','song-poetry','','[]','雨過薰風吹面凉，芒鞋終日水雲鄉。',64,'全唐诗/poet.song.253000.json','["雨過薰風吹面凉，芒鞋終日水雲鄉。", "可憐塵緒縈人久，頼有仙源引興長。", "山鳥無心時自語，林花有意解留香。", "村醪不惜杖頭費，渴似虹霓飲練光。"]'),
('33326e74-6f3b-482b-8a7c-1da05e85baf1','題慶雲東洞','張大直','宋','宋诗','song-poetry','','[]','箇中別是一乾坤，藹藹祥雲擁洞門。',64,'全唐诗/poet.song.253000.json','["箇中別是一乾坤，藹藹祥雲擁洞門。", "天柱遥知鎖金闕，絳橋仍想接崑崙。", "仙人幻出珊瑚木，玉女妝成錦繡墩。", "石室霜臺更奇絕，桃源從此不須論。"]'),
('ea7fb315-d9fa-4657-8af9-cbdc691357f6','題蓮華西洞  其一','張大直','宋','宋诗','song-poetry','','[]','先生自是大羅仙，一去塵寰不記年。',64,'全唐诗/poet.song.253000.json','["先生自是大羅仙，一去塵寰不記年。", "道室只今丹竈在，石窗依舊碧蘿纏。", "空來蓮洞聞仙樂，那得桃源駕鐵船。", "欲覓當年天井路，雲蒸霧罩水潺湲。"]'),
('6a5e37dd-a457-4e8f-9a4b-bd26370e86da','題蓮華西洞  其二','張大直','宋','宋诗','song-poetry','','[]','巖洞嵌空路險巘，神仙窟宅故應奇。',64,'全唐诗/poet.song.253000.json','["巖洞嵌空路險巘，神仙窟宅故應奇。", "湧雲巧作蓮幢仰，滴乳翻成石筍垂。", "瓊樹千年生異果，玉田四季産靈芝。", "真人隠壁君休問，駕鶴驂鸞自有時。"]'),
('cd012a3d-3b76-4bab-a4d9-0f9fc6762cee','題含虛南洞','張大直','宋','宋诗','song-poetry','','[]','雲嶺嵯峨掛夕陽，含虛南洞更徜徉。',64,'全唐诗/poet.song.253000.json','["雲嶺嵯峨掛夕陽，含虛南洞更徜徉。", "書堂猶覺寶薰在，石銚微聞仙茗香。", "遥想釣魚臺上客，飄然駕鶴白雲鄉。", "洪崖有路通仙島，當日無人報始皇。"]'),
('1a4a5061-eac0-4358-84ba-5952e346bfa5','拜婺源文公祠','李奎','宋','宋诗','song-poetry','','[]','天肇文明贊治平，萬年宗主頼先生。',64,'全唐诗/poet.song.253000.json','["天肇文明贊治平，萬年宗主頼先生。", "經窮六籍開來學，道繼諸儒集大成。", "祠枕星源青嶂合，亭臨虹井綵雲橫。", "乘驄遠謁逢秋祀，瞻拜偏興景仰情。"]'),
('762f2e1b-b228-4308-ab39-9518be636531','登樓吟','潘初','宋','宋诗','song-poetry','','[]','朝向蓬萊遊，暮歸蕊珠宿。',28,'全唐诗/poet.song.253000.json','["朝向蓬萊遊，暮歸蕊珠宿。", "偶然折斷玉龍腰，降下凡間三十六。"]'),
('c75848b0-ba51-46e7-8bbb-1506068ea0b5','句','陳雄飛','宋','宋诗','song-poetry','','[]','處順心恒逸，無求道乃高。',12,'全唐诗/poet.song.253000.json','["處順心恒逸，無求道乃高。"]'),
('87d950b1-08d2-4f5d-b4a0-99100651967e','遊靈巖','張昌祖','宋','宋诗','song-poetry','','[]','深壑敞禪扉，獨魁天下奇。',48,'全唐诗/poet.song.253000.json','["深壑敞禪扉，獨魁天下奇。", "烟雲藏不盡，花木秀無時。", "誰謂神仙去，我疑蛟壘移。", "沉吟玷佳景，有句不成詩。"]'),
('f9b177c1-84aa-4ac6-ac4f-9bb327a7bda7','中秋','龍輔','宋','宋诗','song-poetry','','[]','寂寂中秋夜，含情出玉閨。',24,'全唐诗/poet.song.253000.json','["寂寂中秋夜，含情出玉閨。", "河長看雁遠，月皎覺雲低。"]'),
('723bd883-ca65-4b6d-9cb4-a1aa59c8e33b','暮閨','龍輔','宋','宋诗','song-poetry','','[]','暮閨翹首覺愁添，鑿壁書生隔翠烟。',32,'全唐诗/poet.song.253000.json','["暮閨翹首覺愁添，鑿壁書生隔翠烟。", "獨向嫦娥再三拜，殷勤爲我到郎邊。"]'),
('6ca9b40b-27c5-484d-bfa8-508e08589180','鏡','龍輔','宋','宋诗','song-poetry','','[]','徐淑古銅鏡，背多青綠花。',24,'全唐诗/poet.song.253000.json','["徐淑古銅鏡，背多青綠花。", "收藏敢輕慢，曾得照秦嘉。"]'),
('7b03ac92-3b5e-442d-aae2-2a5344ca7eaa','戲示女伴','龍輔','宋','宋诗','song-poetry','','[]','誰道孤眠苦，孤眠却自强。',24,'全唐诗/poet.song.253000.json','["誰道孤眠苦，孤眠却自强。", "請看隔宿髻，常是不勞妝。"]'),
('c4563977-0edd-4de2-9458-1c9ae797e94c','偶成','龍輔','宋','宋诗','song-poetry','','[]','繡窗同刺繡，女伴喜天晴。',24,'全唐诗/poet.song.253000.json','["繡窗同刺繡，女伴喜天晴。", "剪刀當日暖，妝鏡隠霜明。"]'),
('a0b1d3f3-c692-48c9-bca5-d62830295f82','曉景','龍輔','宋','宋诗','song-poetry','','[]','春日映朝霞，新妝出絳紗。',24,'全唐诗/poet.song.253000.json','["春日映朝霞，新妝出絳紗。", "開簾驚宿鳥，倚樹落危花。"]'),
('2181ad96-4247-4ac7-8fd9-af75df3bbe50','答外','龍輔','宋','宋诗','song-poetry','','[]','金徽只自秘，玉匣不曾開。',24,'全唐诗/poet.song.253000.json','["金徽只自秘，玉匣不曾開。", "梅花難獨弄，袖手待郎來。"]'),
('4baf05c4-22b3-4b70-ac44-3d0f14aaaa08','送外','龍輔','宋','宋诗','song-poetry','','[]','榜人㰕舟待，催飯送郎行。',24,'全唐诗/poet.song.253000.json','["榜人㰕舟待，催飯送郎行。", "獨諳郎食性，厨下自調羹。"]'),
('c2127cae-4670-4d05-8e5f-c9930adf7d5e','夏閨','龍輔','宋','宋诗','song-poetry','','[]','日斜未理妝，晝長人易倦。',24,'全唐诗/poet.song.253000.json','["日斜未理妝，晝長人易倦。", "迴撲硯上蠅，墨花濺團扇。"]'),
('b9a6e5f7-7d9f-4835-ac68-ba2e94f63951','蓮子寄外','龍輔','宋','宋诗','song-poetry','','[]','蓮房新摘袖中携，剖寄青青子數枚。',32,'全唐诗/poet.song.253000.json','["蓮房新摘袖中携，剖寄青青子數枚。", "若識心頭最清淨，莫嫌根脚本污泥。"]'),
('17880ce3-3209-4b72-822f-57b5c3c6d28e','蓮子詩比成自覺醜甚戲題此作以解發君一笑耳','龍輔','宋','宋诗','song-poetry','','[]','書罷題鍾字，要君知妾心。',24,'全唐诗/poet.song.253000.json','["書罷題鍾字，要君知妾心。", "雖然非白雪，却是重黄金。"]'),
('c788968b-dc27-4134-acc3-ff18849d2daf','紀夢','龍輔','宋','宋诗','song-poetry','','[]','夢中握手說離愁，夢覺歡娛忽已休。',32,'全唐诗/poet.song.253000.json','["夢中握手說離愁，夢覺歡娛忽已休。", "安得人生真似夢，華胥蝴蝶共悠悠。"]'),
('8aef5922-947b-4fd3-84b3-c2dbd38b8f67','寄外','龍輔','宋','宋诗','song-poetry','','[]','面約隨時改，離情睹物含。',24,'全唐诗/poet.song.253000.json','["面約隨時改，離情睹物含。", "君風愁少女，妾卉最宜男。"]'),
('161ed665-5172-4037-b8c7-103980d5a866','書懷','龍輔','宋','宋诗','song-poetry','','[]','藁砧不可期，蓮子空相託。',24,'全唐诗/poet.song.253000.json','["藁砧不可期，蓮子空相託。", "欲寄一封書，惟愁被姑覺。"]'),
('73e3e568-d340-4315-b35a-8269415ab555','題書齋','龍輔','宋','宋诗','song-poetry','','[]','深閨漸老大，始學謝娘詩。',48,'全唐诗/poet.song.253000.json','["深閨漸老大，始學謝娘詩。", "描筆題成句，良人事作師。", "白頭慚卓女，團扇愧班姬。", "豈敢傳千載，聊將遣一時。"]'),
('59708310-620d-4f30-a1eb-2acbc5757147','冬曉','龍輔','宋','宋诗','song-poetry','','[]','積雨带晴霧，閨中事可誇。',24,'全唐诗/poet.song.253000.json','["積雨带晴霧，閨中事可誇。", "曙窗留鏡月，寒髻集釵花。"]'),
('d5122636-1048-4b01-93e7-0022de94356d','春日  其一','龍輔','宋','宋诗','song-poetry','','[]','風吹花香薰洞房，白日照鏡光射梁。',32,'全唐诗/poet.song.253000.json','["風吹花香薰洞房，白日照鏡光射梁。", "後園草暖雙蝶晒，堂前塵落對燕翔。"]'),
('019fbd3d-99e8-4647-9235-2e8bf4310d31','春日  其二','龍輔','宋','宋诗','song-poetry','','[]','春服初裁綺，寒衣始卸絨。',24,'全唐诗/poet.song.253000.json','["春服初裁綺，寒衣始卸絨。", "花宿全慵蝶，林摇半暖風。"]'),
('c98b4b94-9906-4aa7-bd46-8bbda8ad6449','春日  其三','龍輔','宋','宋诗','song-poetry','','[]','侵階草逾碧，明窗日漸遲。',24,'全唐诗/poet.song.253000.json','["侵階草逾碧，明窗日漸遲。", "携針聽語鳥，牽斷繡床絲。"]'),
('989fe27e-6238-4852-8b08-d64d239f8a7d','偶成','龍輔','宋','宋诗','song-poetry','','[]','階下莓苔爛熳，牆邊竹色蕭疏。',28,'全唐诗/poet.song.253000.json','["階下莓苔爛熳，牆邊竹色蕭疏。", "彩鳳繡來有恨，疏鴻讀外無書。"]'),
('00d12e43-b213-4aae-87c7-915d35a4f59f','春日寫懷','龍輔','宋','宋诗','song-poetry','','[]','暖氣逼房楹，開簾多鳥聲。',24,'全唐诗/poet.song.253000.json','["暖氣逼房楹，開簾多鳥聲。", "竹春思筍嫩，地日識泥晴。"]'),
('51c77b63-5219-465b-8345-1ce238b77ea6','睡起','龍輔','宋','宋诗','song-poetry','','[]','下幃恣午睡，怪殺鳥相呼。',24,'全唐诗/poet.song.253000.json','["下幃恣午睡，怪殺鳥相呼。", "起來慵刺繡，窗下理菖蒲。"]'),
('2444feea-3839-47de-95ac-f3baf05a7c05','送外','龍輔','宋','宋诗','song-poetry','','[]','綠柳千條映遠空，郎君欲別思忡忡。',32,'全唐诗/poet.song.253000.json','["綠柳千條映遠空，郎君欲別思忡忡。", "願得化爲江上水，與郎直到赤門東。"]'),
('dae18964-0996-4600-bbed-2be28fee1cd8','寄外用前韻','龍輔','宋','宋诗','song-poetry','','[]','未得相携約尚空，小牋一見一忡忡。',32,'全唐诗/poet.song.253000.json','["未得相携約尚空，小牋一見一忡忡。", "妾意原非淥江水，無端只向畫橋東。"]'),
('054dfca2-b959-4458-955a-64c6bddda1b7','寫懷','龍輔','宋','宋诗','song-poetry','','[]','初聽鶑聲又燕聲，年華不待使人驚。',32,'全唐诗/poet.song.253000.json','["初聽鶑聲又燕聲，年華不待使人驚。", "桂花開遍門還掩，風自清時月自明。"]'),
('45da6144-df7b-4d0c-8861-4070eb404bd7','寄懷  其一','龍輔','宋','宋诗','song-poetry','','[]','莫怪書頻斷，難傳恨萬端。',48,'全唐诗/poet.song.253000.json','["莫怪書頻斷，難傳恨萬端。", "雖承結髪愛，難作比肩看。", "淚續牋恒溼，思長筆屢乾。", "臨封沾臂血，使識寸心丹。"]'),
('dadf6829-cfbc-4778-ba8d-c53d0287db24','寄懷  其二','龍輔','宋','宋诗','song-poetry','','[]','何處最難禁，思君直至今。',24,'全唐诗/poet.song.253000.json','["何處最難禁，思君直至今。", "雙魚浮水面，對鳥下庭心。"]'),
('b2d66b86-9f6d-4493-b699-03ac9ff8e3fc','恨','龍輔','宋','宋诗','song-poetry','','[]','背人解素襪，裂斷寄郎邊。',24,'全唐诗/poet.song.253000.json','["背人解素襪，裂斷寄郎邊。", "須知銷玉骨，無興步金蓮。"]'),
('af96dc5f-6f60-4e0a-ac3d-e5a453b1de5b','答外','龍輔','宋','宋诗','song-poetry','','[]','君信問平安，閨中差可歡。',24,'全唐诗/poet.song.253000.json','["君信問平安，閨中差可歡。", "竹佳連露倚，雲好下階看。"]'),
('ed671574-668e-4ac2-a53a-cdc197a00c4c','製履寄外','龍輔','宋','宋诗','song-poetry','','[]','何物寄殷勤，宮鞋綠錦文。',24,'全唐诗/poet.song.253000.json','["何物寄殷勤，宮鞋綠錦文。", "爲郎承素足，指日踏青雲。"]'),
('d0997dba-0d22-4745-a910-f254787f77e2','冬至','龍輔','宋','宋诗','song-poetry','','[]','冬至宵雖短，孤眠恨自長。',24,'全唐诗/poet.song.253000.json','["冬至宵雖短，孤眠恨自長。", "枕單寒入夢，窗破月窺床。"]'),
('52382535-3db0-453a-8986-09cb8281eed0','十一月初四日五鼓紀夢寄外','龍輔','宋','宋诗','song-poetry','','[]','昨夜有佳夢，馳書報與郎。',24,'全唐诗/poet.song.253000.json','["昨夜有佳夢，馳書報與郎。", "隔門須是近，有臭必然香。"]'),
('7fd3acc8-f068-4107-9b2b-0eda25d798d7','贈外','龍輔','宋','宋诗','song-poetry','','[]','遠別當霜雪，留郎且過冬。',24,'全唐诗/poet.song.253000.json','["遠別當霜雪，留郎且過冬。", "只愁春色裏，離恨更重重。"]'),
('7c909385-0976-4688-a291-b27524336f81','偶成','龍輔','宋','宋诗','song-poetry','','[]','情弱抽思長，腕嬌運筆拙。',24,'全唐诗/poet.song.253000.json','["情弱抽思長，腕嬌運筆拙。", "口誦恐易忘，牋書還自裂。"]'),
('4f8f56d5-d07b-4999-ad7c-db8facda2d98','蘭梅詩','龍輔','宋','宋诗','song-poetry','','[]','蘭梅逐候舒，種此欲何如。',24,'全唐诗/poet.song.253000.json','["蘭梅逐候舒，種此欲何如。", "蘭葉堪崇佩，梅花好寄書。"]'),
('c56d6e77-5508-403c-a174-64efff45aa36','答外','龍輔','宋','宋诗','song-poetry','','[]','郎書來問近何如，性癖如郎只似初。',32,'全唐诗/poet.song.253000.json','["郎書來問近何如，性癖如郎只似初。", "忍冷臨風因愛雪，抱疴點燭爲看書。"]'),
('d6460909-120f-4b31-b7be-706835002f3b','寄外讀書處','龍輔','宋','宋诗','song-poetry','','[]','主人之室隔清洲，日日華牋空自酬。',32,'全唐诗/poet.song.253000.json','["主人之室隔清洲，日日華牋空自酬。", "書似峴碑看即淚，人非萱草遇還愁。"]'),
('3ef8fad6-b02b-477c-8f25-5bca51ea2de6','山中寄外  其一','龍輔','宋','宋诗','song-poetry','','[]','泊舟古岸傍，松柏日已昫。',24,'全唐诗/poet.song.253000.json','["泊舟古岸傍，松柏日已昫。", "本非同心期，空似西陵路。"]'),
('dad46334-086e-416f-bbc7-2d4cd92c138e','山中寄外  其二','龍輔','宋','宋诗','song-poetry','','[]','湖色開明鏡，巒光列翠屏。',24,'全唐诗/poet.song.253000.json','["湖色開明鏡，巒光列翠屏。", "雙眉不忍畫，羞對遠山青。"]'),
('e7aabf2f-5b62-4fdd-998c-308e353266d6','山中寄外  其三','龍輔','宋','宋诗','song-poetry','','[]','一到空山下，回看遠俗塵。',24,'全唐诗/poet.song.253000.json','["一到空山下，回看遠俗塵。", "松枝堪作麈，無計贈情人。"]'),
('e3b49c82-7ae9-4299-b845-4516621fb427','山中寄外  其四','龍輔','宋','宋诗','song-poetry','','[]','若得共此栖，松菊長携手。',24,'全唐诗/poet.song.253000.json','["若得共此栖，松菊長携手。", "岸上數株松，何須減五柳。"]'),
('d5d6381a-8ecf-47de-a0ca-36c9549b38c7','山中寄外  其五','龍輔','宋','宋诗','song-poetry','','[]','寄郎以山字，得無無解處。',24,'全唐诗/poet.song.253000.json','["寄郎以山字，得無無解處。", "得郎一人來，便可成仙去。"]'),
('63ac3301-3238-4b56-85af-f62dca7b619c','山中寄外  其六','龍輔','宋','宋诗','song-poetry','','[]','脚下繡宮鞋，殷勤爲郎做。',24,'全唐诗/poet.song.253000.json','["脚下繡宮鞋，殷勤爲郎做。", "今日貪看山，鳳頭半已破。"]'),
('f2818eab-2df7-4018-81aa-95112049bd4c','山中寄外  其七','龍輔','宋','宋诗','song-poetry','','[]','躋攀不辭遠，微汗溼紅粉。',24,'全唐诗/poet.song.253000.json','["躋攀不辭遠，微汗溼紅粉。", "萬一有桃源，當期郎共隠。"]'),
('60e93f05-722f-40d0-ab85-0c9776cddc5e','山中寄外  其八','龍輔','宋','宋诗','song-poetry','','[]','山中白日暗，霏霏雲雨動。',24,'全唐诗/poet.song.253000.json','["山中白日暗，霏霏雲雨動。", "信此非巫山，安能入郎夢。"]'),
('d6b9fd5e-299f-4145-a421-2e76198eff33','山中寄外  其九','龍輔','宋','宋诗','song-poetry','','[]','妾在山中來，郎在溪頭住。',24,'全唐诗/poet.song.253000.json','["妾在山中來，郎在溪頭住。", "郎若泛舟尋，莫誤桃源路。"]'),
('696afd03-ab83-4a6b-8331-127d2e6c2e36','山中寄外  其一○','龍輔','宋','宋诗','song-poetry','','[]','聞郎今日來，日斜何不至。',24,'全唐诗/poet.song.253000.json','["聞郎今日來，日斜何不至。", "應知篙櫓遲，羨殺雲中翅。"]'),
('ffa11d3f-7203-4d6d-9274-bfc61585c259','山中寄外  其一一','龍輔','宋','宋诗','song-poetry','','[]','利名何足事，山中樂未央。',24,'全唐诗/poet.song.253000.json','["利名何足事，山中樂未央。", "郎如學耕耨，奴便學蠶桑。"]'),
('fc4bf222-cb79-4787-8c22-01764d73541e','山中寄外  其一二','龍輔','宋','宋诗','song-poetry','','[]','茅屋擁紅爐，聊在山中宿。',24,'全唐诗/poet.song.253000.json','["茅屋擁紅爐，聊在山中宿。", "枉却几上燈，無書供夜讀。"]'),
('1cc92f3b-ff01-46a7-b694-ff538b97ea29','山中寄外  其一三','龍輔','宋','宋诗','song-poetry','','[]','嬌兒漸聰慧，出語解人意。',24,'全唐诗/poet.song.253000.json','["嬌兒漸聰慧，出語解人意。", "促奴須早歸，恐爺書又至。"]'),
('c3c69726-2c85-4880-9c1d-443966de2cd4','山中寄外  其一四','龍輔','宋','宋诗','song-poetry','','[]','寄郎三片玉，至今無報音。',24,'全唐诗/poet.song.253000.json','["寄郎三片玉，至今無報音。", "深山多古跡，不得共郎尋。"]'),
('e864ca3c-f296-4e90-a4a4-c7cd0158dc6d','山中寄外  其一五','龍輔','宋','宋诗','song-poetry','','[]','買舟不論價，但願舟不遲。',24,'全唐诗/poet.song.253000.json','["買舟不論價，但願舟不遲。", "歸時與郎面，不致效秋時。"]'),
('aace62dc-1846-4283-8289-b239fea10de3','送外  其一','龍輔','宋','宋诗','song-poetry','','[]','與君非一身，同戶恒相憶。',24,'全唐诗/poet.song.253000.json','["與君非一身，同戶恒相憶。", "而況出門去，甯知南復北。"]'),
('1bc56256-d1db-4e85-9856-7340207c43a2','送外  其二','龍輔','宋','宋诗','song-poetry','','[]','君言遊宦向華京，不得臨歧一送行。',32,'全唐诗/poet.song.253000.json','["君言遊宦向華京，不得臨歧一送行。", "行行惟有楊花路，飛去飛來是妾情。"]'),
('dea81de2-1d4e-4248-b2bf-13bc97c84de0','又爲子夜歌','龍輔','宋','宋诗','song-poetry','','[]','明朝將解纜，叮囑不曾離。',24,'全唐诗/poet.song.253000.json','["明朝將解纜，叮囑不曾離。", "文無識頃刻，不久便當歸。"]'),
('06408a24-7125-4241-867f-1f006b36c967','鐵袈裟','李美','宋','宋诗','song-poetry','','[]','十載松關隔世塵，俯襟雲石骨毛清。',32,'全唐诗/poet.song.253000.json','["十載松關隔世塵，俯襟雲石骨毛清。", "他時脫得浮名利，好作清凉境裏人。"]'),
('6f0e4a79-33de-40f7-aead-9c744d97607d','題謝康樂石門作','王徵','宋','宋诗','song-poetry','','[]','吾聞永嘉守，□□□□心。',120,'全唐诗/poet.song.253000.json','["吾聞永嘉守，□□□□心。", "勝跡若猶在，雲澗清且深。", "綠蘿自蒙密，白日易森沉。", "□□松篠□，石門□登臨。", "碧潭映千丈，瀑布飛□□。", "秋雨□微□，暮煙生長林。", "□□□皇華，□□往來□。", "偶爾□吟箋，遺風尚□□。", "悠悠歸路長，戀戀惜餘芳。", "□動□水興，茲焉安可忘。"]'),
('827ec2f0-404b-418d-b201-428dd562aae4','題大像','王易簡','宋','宋诗','song-poetry','','[]','□□未生時，先有此石巖。',180,'全唐诗/poet.song.253000.json','["□□未生時，先有此石巖。", "一從下生已，□□□□□。", "初發混沌竅，吐盡龍宮函。", "嗟□□□□，巍坐當空嵌。", "按足大地動，□□□魔芟。", "丹青架樓閣，僅免苔蘚緘。", "上方見頂相，下方仰裙衫。", "誰如福智人，獨脫神鬼監。", "龕燈集烟燿，天花墜雲銜。", "我行豈不遥，迫此十口饞。", "叩門覓津梁，忽臯大力帆。", "善哉此方俗，不解走巫咸。", "仰佛何拳拳，盥佛何摻摻。", "靈石兆三生，神感浹至誠。", "我出唁佛語，誰能知聖凡。"]'),
('3e6e6e7c-84ae-4ce1-9a57-1930f6bad1d2','延祥寺','孫直臣','宋','宋诗','song-poetry','','[]','雷雨隨車上寶坊，僧誇山味最悠長。',64,'全唐诗/poet.song.253000.json','["雷雨隨車上寶坊，僧誇山味最悠長。", "地靈終日無塵到，天淨常時見海光。", "神雀羽毛多隠晦，卧龍頭角本軒昂。", "石樓本是通仙路，十里香燈屬梵王。"]'),
('c82311d5-6494-4141-abcd-8a9f80fb59bf','送歙硯與裴唐卿','史伯强','宋','宋诗','song-poetry','','[]','平生足跡遍九州，知子筆端回萬牛。',228,'全唐诗/poet.song.253000.json','["平生足跡遍九州，知子筆端回萬牛。", "歙硯故持贈，夜光非暗投。", "茲實舊坑子坑尾，遠勝洮州綠鴨頭。", "清淑之德隠於石，珉中玉表非其儔。", "慘淡風漪生，葱蘢雲氣浮。", "故人初贈我，千金未爲酬。", "久磨土灰實硯耻，况拙辭章爲硯羞。", "奇寶豈可窮士收，定爲神奪鬼所偷，物得其託復何求。", "所以櫝而致，賤子不敢留。", "摛藻可以麗春華，學書亦足森銀鈎。", "百氏之學資芟修，六經之文資校讎。", "雖然吾不願子以之屬文如曹劉，吾不願子以之奏賦如枚鄒。", "願子提携與之登瀛洲，獻可替否近冕旒。", "力陳治安活國謀，以寬吾君宵旰憂。"]'),
('89676987-5e52-490f-955b-2d0c190bd7e5','朱子庵','朱誥','宋','宋诗','song-poetry','','[]','落魄塵埃七十翁，平生夢想此山中。',64,'全唐诗/poet.song.253000.json','["落魄塵埃七十翁，平生夢想此山中。", "未應凡骨逢黄老，猶幸垂髫識莫公。", "泉澗泠泠皆佛法，竹符葉葉總神功。", "刀圭欲問吾仙祖，一洗塵勞萬慮空。"]'),
('bb0b44db-0511-43da-801c-b0a8e2839877','贈畫士林堯卿','游彥舉','宋','宋诗','song-poetry','','[]','古稱名畫顧丹青，遺跡遠紹難其人。',96,'全唐诗/poet.song.253000.json','["古稱名畫顧丹青，遺跡遠紹難其人。", "邇來忽臯林堯卿，繪像工夫殊絕倫。", "解后俾爾寫吾形，妙處一筆奪天真。", "始知人傑間世生，何代無才充選掄。", "待需飛詔來楓宸，凌煙特命書勳臣。", "此時此意倍精神，寧復踆踆走路塵。"]'),
('fe5dfc79-5f97-412a-9e8e-523369bc601f','壽胡運使','劉閬風','宋','宋诗','song-poetry','','[]','青原連峰鬰嵯峨，中産瑞石如金螺。',384,'全唐诗/poet.song.253000.json','["青原連峰鬰嵯峨，中産瑞石如金螺。", "清淑之氣孕秀多，蜿蟺旁礴無偏頗。", "間世人傑文星羅，六一鳴道繼雄軻。", "忠簡名節森聱牙，乃孫所學能傳家。", "天孫爲織雲錦窠，五鳳裝樓龍作梭。", "吐詞摛藻正而葩，緯國經邦真土苴。", "暫屈計臺煩撫摩，飛芻輓粟漢蕭何。", "專城治郡政不苛，分醫散藥起札瘥。", "幻出東湖十里荷，百花蔽虧萬柳遮。", "民不知勞在咄嗟，塗歌里詠自吟哦，坐致金穰玉燭和。", "登城萬寶豐百嘉，黍稷稻粱菽禾麻。", "維時秋律灰吹葭，玉宇凉生雨乍過。", "銀河夜靜風無波，祥烟瑞靄紛交加。", "只說牛女此會佳，誰知神仙降雲車。", "中驅下扶走乘戈，玉妃擁衛不撝呵。", "童女十二顔如花，乘鸞吹簫靜無譁。", "彈璈戛玉獻琵琶，琴奏雙成瑟女媧。", "仙掌金莖吸露華，西凉蒲萄勝流霞。", "桃實如蟠棗如瓜，祝公千百算增遐。", "公持玉節鎮龍沙，我領轅門吉水涯。", "一水東西騁望賒，安得共泛張騫槎。", "秋風閶闔鳴玉珂，公歸調鼎我鹽醝，持衡不致斤兩差。", "詩寄柏梁愧猗那，因詞見意倘可歌。"]'),
('77317b79-ac91-4171-8b07-5c644440970e','紫姑仙爲詩索和因用其韻贈范法官  其一','翁溪園','宋','宋诗','song-poetry','','[]','五雲樓閣閬風高，玉女輕輕月下敲。',64,'全唐诗/poet.song.253000.json','["五雲樓閣閬風高，玉女輕輕月下敲。", "軿御爲人催鳳駕，功名報我在螭坳。", "寒灰草出千言妙，爇燼誠由一念交。", "何事賦詩徵速和，一吟聊解子雲嘲。"]'),
('a30f2d47-05ec-455f-ad90-318aeffb4817','紫姑仙爲詩索和因用其韻贈范法官  其二','翁溪園','宋','宋诗','song-poetry','','[]','范君仙吏術何高，欲禱靈扃祇一敲。',64,'全唐诗/poet.song.253000.json','["范君仙吏術何高，欲禱靈扃祇一敲。", "借箸立談神斡運，畫灰成字勢盤坳。", "三錢舞卜堪爲侶，五斗師來可締交。", "神力也須人力附，寄言詩將莫輕嘲。"]'),
('8c9ddbae-2768-423c-bbcf-436bd2d43c6f','贈談命江文魁','翁溪園','宋','宋诗','song-poetry','','[]','刮眼相逢四五秋，知君藝出萬人頭。',64,'全唐诗/poet.song.253000.json','["刮眼相逢四五秋，知君藝出萬人頭。", "但看巨軸藏盈袖，不信行囊尚弊裘。", "建閣程生藏瑞墨，買田張衍寄英游。", "從來有術高天下，莫但人謀當自謀。"]'),
('bf80e999-c3b8-4531-b12c-1ae54cfef36d','贈易數胡一鑑','翁溪園','宋','宋诗','song-poetry','','[]','招牌名一鑑，數學得來真。',48,'全唐诗/poet.song.253000.json','["招牌名一鑑，數學得來真。", "以子胸中易，照他天下人。", "窮通窺見影，賢佞寫成神。", "莫但爲人監，回光監子身。"]'),
('c0cdc128-1f22-44db-bed7-aa421437f245','壽劉上舍將仕  其一','翁溪園','宋','宋诗','song-poetry','','[]','魯臺昨夜已書雲，喜報今朝紀紱麟。',64,'全唐诗/poet.song.253000.json','["魯臺昨夜已書雲，喜報今朝紀紱麟。", "五色祲呈迎瑞氣，一陽道長慶亨辰。", "定知昴宿鍾英質，須信長庚現後身。", "敢效髯秦詩格獻，蓂敷十一壽千春。"]'),
('790e1505-2cf7-427a-980f-59323d935f78','壽劉上舍將仕  其二','翁溪園','宋','宋诗','song-poetry','','[]','英聲璧水早年蜚，官樣文章價久馳。',64,'全唐诗/poet.song.253000.json','["英聲璧水早年蜚，官樣文章價久馳。", "漢殿紫荷應有種，燕山丹桂又傳枝。", "名駒行作銓闈冠，文虎因須鎖試知。", "他日汪黄推榜首，立身事業儘優爲。"]'),
('94a26a59-3029-4997-ab59-f481ea521b11','靈鑒院','陳郊','宋','宋诗','song-poetry','','[]','門外輪蹄去不休，誰人識向靜中遊。',32,'全唐诗/poet.song.253000.json','["門外輪蹄去不休，誰人識向靜中遊。", "區區名利成韁鎖，不道少年能白頭。"]'),
('6e139fa6-b150-4aa7-8436-37edfd630eb5','壽林仲喬尊人','羅子衎','宋','宋诗','song-poetry','','[]','過了元宵八日間，琴堂歌舞獻慈顔。',64,'全唐诗/poet.song.253000.json','["過了元宵八日間，琴堂歌舞獻慈顔。", "七閩山水鬚眉秀，三楚雲煙杖屨閑。", "癡絕不妨公事了，歡濃莫於酒杯慳。", "明年今日迎新霈，錦軸榮封鬢未斑。"]'),
('fe59ea01-ccbc-4273-9097-b0a801ff1ed9','閲武喜晴和厲寺正韻','于定國','宋','宋诗','song-poetry','','[]','元戎笳鼓閙新晴，風柳絲絲萬馬鳴。',64,'全唐诗/poet.song.253000.json','["元戎笳鼓閙新晴，風柳絲絲萬馬鳴。", "尺籍伍符親點檢，牙旗甲馬喜晶明。", "潢池刀劍雖安帖，紫塞煙塵欠掃清。", "聞道玉皇新有詔，禁中虛席待談兵。"]'),
('8d61077a-2b82-4ca8-9a90-ddc81bf963a2','賀謝文二子文武登科','徐子元','宋','宋诗','song-poetry','','[]','福畤何曾好譽兒，鳳毛爭奈一時奇。',64,'全唐诗/poet.song.253000.json','["福畤何曾好譽兒，鳳毛爭奈一時奇。", "青錢學士如龍友，白馬將軍似虎癡。", "齊展一雙文武手，共扶千載聖明時。", "從來謝砌無閑草，步步芳蘭亞紫芝。"]'),
('630fab18-f7d3-47ab-a365-96eda326016e','勸農和孟大監韻','朱宗强','宋','宋诗','song-poetry','','[]','祥開龍角應三農，小隊旌旗獵獵風。',64,'全唐诗/poet.song.253000.json','["祥開龍角應三農，小隊旌旗獵獵風。", "秧馬趣行田陌外，檣烏飛送櫓聲中。", "穰翁預喜甌窶滿，饁婦毋憂杼軸空。", "觀稼西成今在望，賢侯此樂與民同。"]'),
('2534de77-d641-4790-b485-f82991bc54dc','送何推官','吳復齋','宋','宋诗','song-poetry','','[]','風雨一樽酒，此懷人得知。',48,'全唐诗/poet.song.253000.json','["風雨一樽酒，此懷人得知。", "三春花落後，千里客歸時。", "浩浩人間事，悠悠身外思。", "君如能擺脫，林下早相期。"]'),
('c5f6b6c9-a0c9-44a9-aaa0-c97d1fde900d','慶游寶制  其一','吳同山','宋','宋诗','song-poetry','','[]','梅花玉立雪尤禁，歲歲吹香伴細斟。',64,'全唐诗/poet.song.253000.json','["梅花玉立雪尤禁，歲歲吹香伴細斟。", "日看篁車歸戲綵，未誇荷橐已橫金。", "水雲生閲市朝事，砥柱不移丘壑心。", "德望益尊身暫退，他年乃聽衛公箴。"]'),
('f5666284-e5ea-4781-bbc4-f16f3fa4274e','慶游寶制  其二','吳同山','宋','宋诗','song-poetry','','[]','時事枰棋著固難，奕秋袖手却旁觀。',64,'全唐诗/poet.song.253000.json','["時事枰棋著固難，奕秋袖手却旁觀。", "漢庭持論卑臯朔，洛社論年參潞韓。", "富貴無心來則受，行藏有道處之安。", "金籠放鴿徒誇詡，靜處乾坤分外寬。"]'),
('9bcee3d6-e6d3-4d16-81e6-ae23519b69cd','寄僧琴山','楊紬林','宋','宋诗','song-poetry','','[]','閩海西來山復山，白雲深處見禪關。',64,'全唐诗/poet.song.253000.json','["閩海西來山復山，白雲深處見禪關。", "幽巖風細鶑聲緩，古寺春深鶴夢閒。", "遊子從來悲草綠，老僧渾不計花殘。", "笑余猶是紅塵客，盡日攀躋行路難。"]'),
('56e86f2b-6231-495e-b86d-c737feaf66d2','九日亭','張子厚','宋','宋诗','song-poetry','','[]','九日亭成氣象高，宰君乘興幾回過。',64,'全唐诗/poet.song.253000.json','["九日亭成氣象高，宰君乘興幾回過。", "山憐峻極凌霄漢，路愛幽深入薜蘿。", "長恐泛杯籬菊少，不愁落帽海風多。", "香醪正熟芳時節，對此年年奈醉何。"]'),
('6263cd54-a4a9-44d6-a8df-afd58bc3eba6','送縣宰赴召','蕭仲才','宋','宋诗','song-poetry','','[]','出宰男邦過冉求，潦江木落四番秋。',64,'全唐诗/poet.song.253000.json','["出宰男邦過冉求，潦江木落四番秋。", "主恩父母朝天去，失哺嬰孩伏地留。", "一片丹心深國慮，數莖白髪爲民愁。", "邑人共繪生祠像，不戴貂蟬官未休。"]'),
('02e9c21d-8897-4869-8717-f735248aa825','贈行醫龍杖道人','孫伯容','宋','宋诗','song-poetry','','[]','忽報求詩有客來，詩魔正此費驅催。',64,'全唐诗/poet.song.253000.json','["忽報求詩有客來，詩魔正此費驅催。", "內丹却喜君能煉，青眼何妨我爲開。", "袖裏蛇應傳似續，手中龍漫事剸裁。", "傳玄神物經當合，道合仙陂試驗哉。"]'),
('64a1372f-0e94-4841-9d18-66a2c2ad6e06','合溪新亭','章炳炎','宋','宋诗','song-poetry','','[]','每到雙溪興自招，新亭况是隔凡囂。',64,'全唐诗/poet.song.253000.json','["每到雙溪興自招，新亭况是隔凡囂。", "水中山色都如畫，風裏湍聲却似潮。", "欹枕幾回眠盡夜，憑欄不厭立終朝。", "人生何用千鍾酒，萬古閒愁向此消。"]'),
('8514f6c3-0aab-4369-8caa-0544ecbcf27f','送徐殿院去國','程壯','宋','宋诗','song-poetry','','[]','殿中簪筆英風凜，直比朱絃清玉壺。',64,'全唐诗/poet.song.253000.json','["殿中簪筆英風凜，直比朱絃清玉壺。", "諫奏百篇多蹇諤，精忠一力撼乾樞。", "笑哦老鳳池邊句，要取驪龍頷下珠。", "扣闕舉幡心未副，芳名贏得滿江湖。"]'),
('65b5e6e1-eeb8-4a70-951c-de929f9dc30c','風井','周惠','宋','宋诗','song-poetry','','[]','寰中風穴不一處，斯井乳化能伏流。',64,'全唐诗/poet.song.253000.json','["寰中風穴不一處，斯井乳化能伏流。", "暗接高源常祕惜，不離陌路自清幽。", "土囊空豔高人賦，水品難逢處士收。", "宴坐巖頭默斟取，清凉此意與誰謀。"]'),
('eece7730-0df8-4ee1-9279-a22cc10c0896','油溪嶺','周惠','宋','宋诗','song-poetry','','[]','油溪何淼漫，油嶺復巑坃。',48,'全唐诗/poet.song.253000.json','["油溪何淼漫，油嶺復巑坃。", "白日蛇龍起，青林虎豹摶。", "乾坤誰設險，登陟壯遐觀。", "刀劍今牛犢，須知帝德寬。"]'),
('368b22d4-100f-4740-b714-a83332e40638','蕭巖','周惠','宋','宋诗','song-poetry','','[]','萬里藏雲境界寬，仙源江上起峰巒。',64,'全唐诗/poet.song.253000.json','["萬里藏雲境界寬，仙源江上起峰巒。", "鶑啼翠柳三春暖，松隠清風六月寒。", "飛雁忽驚天柱過，蟄龍猶向石潭蟠。", "宦遊爭道茲巖好，林下何曾得共歡。"]'),
('7275bbdb-c9a8-4699-b965-3c1799d1fe53','龜山禪寺贈僧柏庭','黄希武','宋','宋诗','song-poetry','','[]','出世無心與世聞，好將蹤跡遠離群。',64,'全唐诗/poet.song.253000.json','["出世無心與世聞，好將蹤跡遠離群。", "別來滄海孤舟月，歸去青山半榻雲。", "頓覺有生皆幻夢，更尋無地避塵氛。", "東林蓮社詩盟在，相送河橋已夕曛。"]'),
('e747b8f3-ef44-4c09-a336-6c09b50fa256','留題龍華僧院放懷閣','魯君錫','宋','宋诗','song-poetry','','[]','公餘閑步山陰寺，小閣臨崖面竹開。',32,'全唐诗/poet.song.253000.json','["公餘閑步山陰寺，小閣臨崖面竹開。", "我欲放懷□□□，故鄉消息未曾來。"]'),
('724ea458-4563-41f3-bc2a-4b12d83e1814','送白魚','李子西','宋','宋诗','song-poetry','','[]','秋江水落白魚肥，正是蓴鱸入興時。',64,'全唐诗/poet.song.253000.json','["秋江水落白魚肥，正是蓴鱸入興時。", "舉網得魚溪上路，揮毫走兔簡中詩。", "雅知賓幕饒供給，何待儂芹薦斂私。", "魯鬲楚魚羞不腆，此誠只有孔門知。"]'),
('21a7949d-fb85-4f87-8447-c276844382d8','題蔣山','李梅磵','宋','宋诗','song-poetry','','[]','登臨要說六朝遺，一箇乾坤幾合離。',64,'全唐诗/poet.song.253000.json','["登臨要說六朝遺，一箇乾坤幾合離。", "豪傑已隨流水去，興亡只有此山知。", "古松隔道招遊客，丹樹斜陽話舊時。", "寄語老僧珍此壁，百年後有古人詩。"]'),
('1daec9d7-f07a-469c-851a-39e1ba4b9a5b','贈談命嚴叔寓','李長沙','宋','宋诗','song-poetry','','[]','平時已秉班揚筆，暇處不妨甘石經。',64,'全唐诗/poet.song.254000.json','["平時已秉班揚筆，暇處不妨甘石經。", "吾里忻傳日邊信，君言頻中斗杓星。", "會稽夫子餘詩禮，巴蜀君平舊典型。", "歷歷周天三百度，更參璿玉到虞廷。"]'),
('859206e8-999d-41b6-8f72-24e3e4f814b8','送戴太博  其一','杜司直','宋','宋诗','song-poetry','','[]','昨者題輿政未成，鄰封騎竹已歡迎。',64,'全唐诗/poet.song.254000.json','["昨者題輿政未成，鄰封騎竹已歡迎。", "翱翔忽看天邊舉，來去從教境上爭。", "玉笥江山應改色，青原風月未忘情。", "兩邦父老休啼哭，總在甘棠蔭裏行。"]'),
('c3e0c3a5-e422-490e-aafa-a633b7099149','送戴太博  其二','杜司直','宋','宋诗','song-poetry','','[]','瓊佩霞裾雲錦裳，胸中指塞貯琳瑯。',64,'全唐诗/poet.song.254000.json','["瓊佩霞裾雲錦裳，胸中指塞貯琳瑯。", "詞章莫測波瀾闊，談笑惟圖書傳香。", "與我多應鄰臭味，於人寧有別肝腸。", "一州斗大非公處，早晚催歸白玉堂。"]'),
('acdffd23-0165-4691-92d6-b8f14f98eb8c','壽開府','嚴敦常','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','季冬兩十雞鳴初，僚吏府造如雲趨。',192,'全唐诗/poet.song.254000.json','["季冬兩十雞鳴初，僚吏府造如雲趨。", "綉軸捧星香擁爐，共慶此日生真儒。", "玉堂金印守此都，今日爲城鎮匈奴。", "坐安天下猶覆盂，祝公之壽宜何如。", "欲祝公如九臯鶴，鶴頸雖長畏繒繳。", "欲祝公如千歲龜，清江作使身亦危。", "又祝公如松與柏，樵斧焉知歲寒色。", "剛莫剛兮赤山鐵，鐵作干將有時缺。", "堅莫堅兮泰山石，溜滴波穿有時泐。", "不若祝公如太虛，包含千古無時無。", "任馳玉兔飛金烏，暑往寒來速又徐。", "髪常如漆齒常固，太虛不老君與俱。"]'),
('0a5899ea-53c6-44a4-ba35-555bf79729c8','遊濟瀆','李志全','宋','宋诗','song-poetry','','[]','水底微茫見貝宮，靈源直與海相通。',64,'全唐诗/poet.song.254000.json','["水底微茫見貝宮，靈源直與海相通。", "雪晴人立冰壺外，春暖魚遊玉鑑中。", "鶴反松林巢夜月，神歸蓬島駕天風。", "裴公亭上行吟處，佗日重來興未窮。"]'),
('0627c0c8-c88b-4031-beca-c4e226ebb27a','龍虎山','易性中','宋','宋诗','song-poetry','','[]','雲氣蓬萊近，山陰草樹香。',24,'全唐诗/poet.song.254000.json','["雲氣蓬萊近，山陰草樹香。", "御風不知遠，仙骨已清凉。"]'),
('891a091f-a814-4464-a881-72e3326792bb','遊東禪院','郭之義','宋','宋诗','song-poetry','','[]','地去關城遠，無人伴訪尋。',48,'全唐诗/poet.song.254000.json','["地去關城遠，無人伴訪尋。", "泉流溪路窄，石聳洞門深。", "紫翠烟嵐懋，清凉竹樹陰。", "重來應更□，□日解塵襟。"]'),
('78571779-b3e8-4787-aaf4-186f8fa02fc0','三蕭行賀蕭丞定夫子登科','傅西齋','宋','宋诗','song-poetry','','[]','吾鄉前輩多風誼，教子讀書全盛事。',384,'全唐诗/poet.song.254000.json','["吾鄉前輩多風誼，教子讀書全盛事。", "劉斯立在慶曆間，二子同升俱上第。", "後來嘉祐孔長源，三子聯登相後先。", "元豐四謝更同榜，一家科第光燁然。", "直到淳熙徐思叔，亦與二子連芳躅。", "又報年來蕭定夫，紹定兩科庭下玉。", "二百年間能幾家，劉家孔家無以加。", "才名學行總名世，不但官爵稱高華。", "謝家獨有民師著，徐家大無鳴詩句。", "人道蕭室父子三，前輩流風無讓處。", "蕭公要是真醇儒，家無他物惟有書。", "自家讀了教兒讀，夜半書聲喧里閭。", "造物負公還不貧，嘉定庚辰漢庭右。", "此時二子已嶄然，公曰吾心汝其懋。", "果然相繼取高科，二哥饒著與三哥。", "乃翁笑向月中問，吾家桂樹何其多。", "月娥報道蕭家桂，生滿月中香滿世。", "移過東山能幾年，今日方教翁滿意。", "祝公此意令深長，香名當使百世芳。", "前賢事業遠且大，三劉三孔尤輝光。", "世科膴仕公家有，實聲莫落謝徐後。", "要知渝上一蕭家，突過四家名宇宙。", "我曾與公同薦名，服公文行識公真。", "更與賢郎共文社，情誼凜凜如霜筠。"]'),
('6389a638-a973-431b-b7f5-f6578a142e62','送梁府教赴括蒼任','趙恬齋','宋','宋诗','song-poetry','','[]','聞得官期三月初，此行最喜奉潘輿。',64,'全唐诗/poet.song.254000.json','["聞得官期三月初，此行最喜奉潘輿。", "杏花風暖好覓句，槐影日長宜讀書。", "垂世文章星有斗，隨緣富貴水成渠。", "少須歲月朝天去，半夜金蓮歸直廬。"]'),
('12a04297-2980-4464-86f2-10c7bdb4d5fe','壽知宗','范一飛','宋','宋诗','song-poetry','','[]','天工未放二陽生，留得堯階一葉蓂。',64,'全唐诗/poet.song.254000.json','["天工未放二陽生，留得堯階一葉蓂。", "慶誕仙源貴公子，祥開南極老人星。", "日隨宮線添無盡，貌比莊椿看更青。", "歲歲華堂祝眉壽，笙歌聲裏雪梅馨。"]'),
('88f75790-5d23-4969-8934-37b51d885c17','送人赴舉','黄少師女','宋','宋诗','song-poetry','','[]','春闈報罷已三年，又向西風趁著鞭。',64,'全唐诗/poet.song.254000.json','["春闈報罷已三年，又向西風趁著鞭。", "屢鼓莫嫌非作氣，一鳴當自卜沖天。", "賈生少奮終何遇，馬援才高老益堅。", "大抵功名無早晚，平津今見起淄川。"]'),
('b22de9b6-bc82-4a54-b73b-c27df237ce46','別諸禪衆','釋洪海','宋','宋诗','song-poetry','','[]','萬瓦禪林聳翠螺，四圍山色玉新磨。',32,'全唐诗/poet.song.254000.json','["萬瓦禪林聳翠螺，四圍山色玉新磨。", "恍疑別換胸懷子，霽月光風覺轉多。"]'),
('96114121-fb50-41b1-bdcf-9e5efe981010','晚宿靈岩','雲盤山人','宋','宋诗','song-poetry','','[]','風雨旃檀閣，烟霞鐘鼓聲。',24,'全唐诗/poet.song.254000.json','["風雨旃檀閣，烟霞鐘鼓聲。", "定僧今不作，空谷尚傳燈。"]'),
('3a49b090-5951-4747-8b89-836f21461bee','羅隠題詩石','釋某','宋','宋诗','song-poetry','','[]','峭壁巉巖枕碧溪，昔賢曾過此留題。',64,'全唐诗/poet.song.254000.json','["峭壁巉巖枕碧溪，昔賢曾過此留題。", "一時章句今人憶，萬古聲名與日齊。", "山色淺深來白鶴，水光溜瀉漾金雞。", "我來弔古尋遺跡，只有漁翁傍石梯。"]'),
('63ee8e0f-b782-4a74-aece-86bd8b54a90b','紹興丁丑題烏石山','□治中','宋','宋诗','song-poetry','','[]','烏□□怪石，撐突倚山巔。',48,'全唐诗/poet.song.254000.json','["烏□□怪石，撐突倚山巔。", "□□群羊伏，昂昂萬馬聯。", "何年現蓬島，終古頌桑田。", "相揖閩王宅，東隅有九仙。"]'),
('43cc8d77-8ebc-4eed-a084-4ca8ba1eb3e0','遊東禪院','郭某','宋','宋诗','song-poetry','','[]','地去關城遠，無人□□□。',48,'全唐诗/poet.song.254000.json','["地去關城遠，無人□□□。", "泉流溪路窄，石顯洞門深。", "□□□□□，□□竹樹陰。", "□□□□□，□日解題襟。"]'),
('8513152d-164a-485e-aede-aed06060af63','南山留題和呂元錫韻','某府判','宋','宋诗','song-poetry','','[]','詞源浩渺浙江潮，倒瀉銀河落九霄。',64,'全唐诗/poet.song.254000.json','["詞源浩渺浙江潮，倒瀉銀河落九霄。", "貝闕珠宮春不老，蓬萊瀛海路非遥。", "多君訪古曾携手，愧我勞生漫折腰。", "擬欲誅茅成小隠，山雲不薄幸相招。"]'),
('4e15d005-dc53-440c-80de-e8b7facea61b','白石灘碑刻','無名氏','宋','宋诗','song-poetry','','[]','太原王氏女，金陵韓守妻。',56,'全唐诗/poet.song.254000.json','["太原王氏女，金陵韓守妻。", "戊辰年八月，葬在石城西。", "日爲弓兮月爲箭，射四時兮生改變。", "千年萬年松柏風，悲盡死亡人不見。"]'),
('8d89ee7b-7f38-4c7e-a111-1474560fcc4d','無題','無名氏','宋','宋诗','song-poetry','','[]','試將潜皖問雲遊，何似靈巖與虎丘。',32,'全唐诗/poet.song.254000.json','["試將潜皖問雲遊，何似靈巖與虎丘。", "應道淮南山水勝，清奇都在兩三州。"]'),
('659a3fd0-aa18-4243-ab4f-5e0077f0d004','題石魚','無名氏','宋','宋诗','song-poetry','','[]','諸公討未决。',189,'全唐诗/poet.song.254000.json','["諸公討未决。", "朝忌其事夕失功，詎可因循守常法。", "人心感處是天心，至誠解使金石裂。", "形勢不宜久冷落，鼓作須及人情熱。", "每憂姦雄東風塵，它日未易傾巢穴。", "人才政事所急者，此間伊呂何常乏。", "况如耿賈郭李輩，馬後牛前誰識別。", "黄芽摇寒鴥不飛，鬼洞蠻虛新過雪。", "行矣强飯莫飲酒，偷閑讀書備施設。", "一官皆可行其義，勿學庸人苟歲月。", "蹄涔之水無鯤鯨，鴛鳳寧肯爭雞楬。", "吾皇駐蹕浙江西，努力朝宗致忠烈。", "星馳電走見相。"]'),
('3be53c66-390a-4266-aa05-74eb01fc5f6e','曹孝女廟','釋元昉','宋','宋诗','song-poetry','','[]','祠古孝誠遥，悲風想暮號。',48,'全唐诗/poet.song.254000.json','["祠古孝誠遥，悲風想暮號。", "月魂迷草色，血淚濺江濤。", "斷碣惟黄絹，孤墳掩綠蒿。", "千年暗潮水，亦以姓爲曹。"]'),
('24f43b88-5663-49de-a086-32ab75c3d6b1','講教洞','高予文','宋','宋诗','song-poetry','','[]','一官羈絆混黄埃，壯抱雄懷久未開。',32,'全唐诗/poet.song.254000.json','["一官羈絆混黄埃，壯抱雄懷久未開。", "我若有山如此好，掛冠即日賦歸來。"]'),
('43ab6806-786c-4073-963d-418161eba2e9','句','謝達夫','宋','宋诗','song-poetry','','[]','兩峰環抱揖平川。',8,'全唐诗/poet.song.254000.json','["兩峰環抱揖平川。"]'),
('7b50b49d-f269-4b9a-95d5-3dff81696443','登黄樓','胡謐','宋','宋诗','song-poetry','','[]','山接青齊橫翠黛，水兼汴泗入洪流。',32,'全唐诗/poet.song.254000.json','["山接青齊橫翠黛，水兼汴泗入洪流。", "西風落日憑欄處，廊廟江湖總繫愁。"]'),
('4ab62b5e-cd7d-4a87-a859-3362269dce41','送陳吏部','林某','宋','宋诗','song-poetry','','[]','天頒一札語叮嚀，光動郎官駕使星。',64,'全唐诗/poet.song.254000.json','["天頒一札語叮嚀，光動郎官駕使星。", "頼有斯文增氣燄，可無吾道活生靈。", "馳驅漫說周原隰，登轡先須辨渭涇。", "珍重□章臨遣意，不徒鹽筴與茶經。"]'),
('af4f3bd2-8f43-4a4f-97a9-abeb6676475f','留題酒家壁','席炎','宋','宋诗','song-poetry','','[]','山雲出山無一錢，日日醉倒春風邊。',32,'全唐诗/poet.song.254000.json','["山雲出山無一錢，日日醉倒春風邊。", "采蘋橋南徐孺子，白酒初熟留神仙。"]'),
('afdd2d70-0266-4e79-8f0f-8cfd361ad6f3','新月','釋顯彬','宋','宋诗','song-poetry','','[]','微光已成魄，隠隠夕陽間。',48,'全唐诗/poet.song.254000.json','["微光已成魄，隠隠夕陽間。", "六幙無人卷，一鉤長自閑。", "輪隨明月長，香逐桂枝還。", "三五相將近，分明照竹關。"]'),
('482c2a00-047c-4b3f-8f17-752c38abb1bd','題徐氏金湖書院','梁白','宋','宋诗','song-poetry','','[]','烟霞縹緲鎖仙鄉，萬卷詩書一草堂。',64,'全唐诗/poet.song.254000.json','["烟霞縹緲鎖仙鄉，萬卷詩書一草堂。", "孝義聲華輝北闕，門閭烜赫照南方。", "千尋瀑布侵肌冷，四季閒花撲鼻香。", "正是人間無敵處，王公詩版砌虹梁。"]'),
('2e222dc4-77ce-41c7-8b64-20bcfa89a461','題徐氏金湖書院','楊徵','宋','宋诗','song-poetry','','[]','君家仙館带林塘，氣象清新志趣長。',64,'全唐诗/poet.song.254000.json','["君家仙館带林塘，氣象清新志趣長。", "千里客來如海若，一樓詩靜透文光。", "門閭旌表芝蘭貴，科第聯芳桂籍香。", "帝里詞人多景慕，願題詩句滿修篁。"]'),
('a46ec1bf-2c1d-40f9-ba3b-6f50ecf19e05','毛竹山','桑文炳','宋','宋诗','song-poetry','','[]','天地有此山，植此毛竹久。',24,'全唐诗/poet.song.254000.json','["天地有此山，植此毛竹久。", "我本山中人，清風振千古。"]'),
('be189aa2-9449-43c1-ae9c-d21062f24808','真人  其一','彭徵','宋','宋诗','song-poetry','','[]','白雲深處是仙家，清壁飛來瀑布斜。',32,'全唐诗/poet.song.254000.json','["白雲深處是仙家，清壁飛來瀑布斜。", "採藥不知歸路晚，洞門開遍碧桃花。"]'),
('8c3f0bf4-521f-456e-a6f9-cc4b5e692e85','真人  其二','彭徵','宋','宋诗','song-poetry','','[]','散髪披襟萬仞岡，天池風度碧蓮香。',32,'全唐诗/poet.song.254000.json','["散髪披襟萬仞岡，天池風度碧蓮香。", "洞雲去作人間雨，留下瑶壇月影凉。"]'),
('4abddfa7-45e4-48d3-9827-f245db43ee05','真人  其三','彭徵','宋','宋诗','song-poetry','','[]','老桂吹香入古瓢，月華如水碧天寥。',32,'全唐诗/poet.song.254000.json','["老桂吹香入古瓢，月華如水碧天寥。", "酒醒夜半誰驚覺，鶴背仙人紫玉簫。"]'),
('3e857f39-c0ca-4c11-a9d7-77b203911c31','真人  其四','彭徵','宋','宋诗','song-poetry','','[]','山中無歷任光陰，梅正開時雪意深。',32,'全唐诗/poet.song.254000.json','["山中無歷任光陰，梅正開時雪意深。", "彈罷蕊珠香滿座，天花幾個落瑶琴。"]'),
('7d1ecd89-901a-4531-9bc2-79551ded2d06','古木空烟','梁子固','宋','宋诗','song-poetry','','[]','淡烟漠漠古城頭，老樹拏雲瞰碧流。',32,'全唐诗/poet.song.254000.json','["淡烟漠漠古城頭，老樹拏雲瞰碧流。", "鴉背夕陽添晚景，就中描出一天秋。"]'),
('5f65333b-c084-4b06-9e75-04378341f31f','石通洞','朱翁','宋','宋诗','song-poetry','','[]','披棘捫蘿入洞中，拂塵剝蘚識涪翁。',64,'全唐诗/poet.song.254000.json','["披棘捫蘿入洞中，拂塵剝蘚識涪翁。", "我緣直道來施右，君爲清詩到石通。", "定後寂寥無異議，危初萋菲竟何功。", "投豺畀北言猶在，厄宋饑陳道不窮。"]'),
('affd067b-026d-438e-8763-b1e7716dee6a','游碧落洞','釋延吉','宋','宋诗','song-poetry','','[]','碧落有仙躅，迴溪限塵跡。',48,'全唐诗/poet.song.254000.json','["碧落有仙躅，迴溪限塵跡。", "虎穴建空巖，鳥道齊峭壁。", "蒼松動寒吹，孤雲觸幽石。", "物外詣所樂，高談混儒釋。"]'),
('2a7a741e-8c6d-4b2b-a3ad-96c41f4beb2a','白雲亭','徐壽朋','宋','宋诗','song-poetry','','[]','飛泉山脚水盈盈，溪會亭前就榜名。',64,'全唐诗/poet.song.254000.json','["飛泉山脚水盈盈，溪會亭前就榜名。", "駐目合流尋異派，爽心臨眺勝登瀛。", "遊人暗認仙原景，清耳微傳玉佩聲。", "依約白蓮當日事，社中賢令有淵明。"]'),
('53568c00-eb15-49a5-9572-a20809897587','勝會堂','徐壽朋','宋','宋诗','song-poetry','','[]','巧運風斤若化成，過門車馬每留行。',64,'全唐诗/poet.song.254000.json','["巧運風斤若化成，過門車馬每留行。", "吞含氣象歸平隴，鬬湊溪山到畫楹。", "春借杏桃紅照耀，曉披烟靄碧低橫。", "使麾映日安牙隊，依約當年細柳營。"]'),
('81aeb629-5d33-4b94-8dfe-10c1920dabe7','景福院','黄執中','宋','宋诗','song-poetry','','[]','娟娟竹影薄，决决溪流淺。',24,'全唐诗/poet.song.254000.json','["娟娟竹影薄，决决溪流淺。", "風生秋意回，野塘天容遠。"]'),
('b60027c2-1da6-4ee3-81e0-4348289fc269','白鶴峰','張祉','宋','宋诗','song-poetry','','[]','我登白鶴峰，下窺滄海日。',48,'全唐诗/poet.song.254000.json','["我登白鶴峰，下窺滄海日。", "色與朱橘同，形比彈丸一。", "夜半佇玩閒，無質而生質。", "所以神仙侶，色界須超出。"]'),
('dc393595-5934-4358-a2b2-7e2188647991','普通禪寺  其一','釋德惠','宋','宋诗','song-poetry','','[]','古寺何年有，巍峨入杳冥。',48,'全唐诗/poet.song.254000.json','["古寺何年有，巍峨入杳冥。", "水如僧眼碧，山作佛頭青。", "瓦礫皆能說，虛空亦解聽。", "道人心已死，窗下卷殘經。"]'),
('7a82e32c-0cf7-49e0-8437-fbd16e8ffb4e','普通禪寺  其二','釋德惠','宋','宋诗','song-poetry','','[]','問訊巖中主，形枯雪滿頭。',48,'全唐诗/poet.song.254000.json','["問訊巖中主，形枯雪滿頭。", "住山何歲月，壞衲幾春秋。", "傍石千間屋，騰空百尺樓。", "盡從心地出，聲價甲西州。"]'),
('e44e4a39-c403-4456-8da7-0c1da420f2cb','臨溪樓','敖邁','宋','宋诗','song-poetry','','[]','花溪老子昔喜花，紅雲紫霞香滿家。',160,'全唐诗/poet.song.254000.json','["花溪老子昔喜花，紅雲紫霞香滿家。", "竹溪逸士昔愛竹，翠靄蒼烟陰繞屋。", "羌茲偉人臨溪樓，唐相之裔來溪頭。", "奄有花竹著樓所，日與溪山作賓主。", "手抉銀漢地上流，仰送飛鴻俯盟鷗。", "滄浪濯纓塵化雪，清泉烹茶團碎月。", "曾似元龍意氣豪，湖海偃卧百尺高。", "又似仲宣銷憂賦，客居江左非吾土。", "不如祝翁畫欄前，梯身此樓近青天。", "湔心此溪赴滄海，樓名溪聲可千載。"]'),
('306cf4c2-05a9-40e9-bd5b-194bb0ac2350','贊驛亭壁墨龍','黄均瑞','宋','宋诗','song-poetry','','[]','一鼓春雷起九淵，風雲萬里會中天。',32,'全唐诗/poet.song.254000.json','["一鼓春雷起九淵，風雲萬里會中天。", "墨池付與無多水，去作人間大有年。"]'),
('b46fef1d-b244-42cb-82b4-18555f965c54','三溪','尹恕','宋','宋诗','song-poetry','','[]','三溪溪水別原委，長日波光蕩無已。',64,'全唐诗/poet.song.254000.json','["三溪溪水別原委，長日波光蕩無已。", "曲折有如九迴腸，合匯門前清徹底。", "只看秀色照眼明，溪上閒遊不倦情。", "何年得作逋榮客，好結芳鄰一濯纓。"]'),
('7d8cfbb1-ad0c-4e5a-abed-dfb24cc801ad','遊譚田寺','蔣金部','宋','宋诗','song-poetry','','[]','我愛譚田寺，短橋橫碧波。',24,'全唐诗/poet.song.254000.json','["我愛譚田寺，短橋橫碧波。", "數椽松竹裏，靜處不須多。"]'),
('e672e839-982c-417b-b219-8cace2417c6e','劉磐幕','許元信','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','山懸翠幙幾千丈，我疑山頂即天上。',80,'全唐诗/poet.song.254000.json','["山懸翠幙幾千丈，我疑山頂即天上。", "捫蘿躡蹬到山巔，猶如平地上青天。", "始知天高應無極，幕阜蒼蒼一卷石。", "洞庭八百古所傳，對此遥看一鏡圓。", "當此再上三千丈，那知天下有山川。"]'),
('7ed4a095-5414-4915-a152-e17f7efb92f3','幕阜山','許元信','宋','宋诗','song-poetry','','[]','幕阜山高一千八百丈，二十五洞大元天。',66,'全唐诗/poet.song.254000.json','["幕阜山高一千八百丈，二十五洞大元天。", "雪花飛滿水衝石，翠嶂撥開風卷烟。", "金鯉一雙游碧沼，石田三畝産紅蓮。", "我來絕頂無他事，爲訪仙翁葛稚川。"]'),
('9b4ffa50-811e-4a13-93bc-e6e3b21523d1','占勝亭  其一','王阜壽','宋','宋诗','song-poetry','','[]','雲橫龍角千秋岸，水發含香十里堤。',32,'全唐诗/poet.song.254000.json','["雲橫龍角千秋岸，水發含香十里堤。", "每向癡兒了公事，倚欄立到日沉西。"]'),
('6ef64b52-cc01-4f92-b35b-ff775a6e3268','占勝亭  其二','王阜壽','宋','宋诗','song-poetry','','[]','湖氣昏昏霧氣漫，泊舟亭下水生寒。',32,'全唐诗/poet.song.254000.json','["湖氣昏昏霧氣漫，泊舟亭下水生寒。", "幽人醉卧篷窗月，喝起癡龍倒挂看。"]'),
('5159143c-bb06-42df-947b-e5ccfaa1ee18','煙波亭','吳珠','宋','宋诗','song-poetry','','[]','漢水連天闊，江雲護曉寒。',24,'全唐诗/poet.song.254000.json','["漢水連天闊，江雲護曉寒。", "青青山數點，最好倚欄看。"]'),
('ef53d504-96e8-4724-ad43-25e42204dd53','秋興亭','韓揚','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','賈載嘗爲郡，名亭建此邦。',48,'全唐诗/poet.song.254000.json','["賈載嘗爲郡，名亭建此邦。", "近山連大別，遠水接長江。", "待月凭東檻，來薰起北窗。", "四時皆有興，秋興獨難降。"]'),
('b7511311-4cba-4698-b0e5-57bc15604a3d','桃花洞','方日升','宋','宋诗','song-poetry','','[]','洞口迷離春復秋，幾人幽賞賦來遊。',64,'全唐诗/poet.song.254000.json','["洞口迷離春復秋，幾人幽賞賦來遊。", "雲封亂石桃花少，月照平湖茂草稠。", "粉黛三年空不語，溪山萬古尚含愁。", "只今惟有長堤柳，猶似依依念故侯。"]'),
('7ae23edd-cd50-4c27-ae1a-cb1a1e9d0951','重遊道巖','吳棟','宋','宋诗','song-poetry','','[]','玄都重到拂題塵，屈指於今十四春。',64,'全唐诗/poet.song.254000.json','["玄都重到拂題塵，屈指於今十四春。", "白石煙消丹竈冷，蒼崖日永畫樓新。", "山中自笑黔馿技，天外誰知海鶴身。", "洞口桃花莫相笑，劉郎猶是少年人。"]'),
('8f74fdd6-6486-4687-811b-5f70efa448a2','省謁觀文之塋留題  其一','范公','宋','宋诗','song-poetry','','[]','先帝龍飛第一年，囊封夜半達甘泉。',64,'全唐诗/poet.song.254000.json','["先帝龍飛第一年，囊封夜半達甘泉。", "朝來急召明光殿，讜論能回不夜天。", "遐想神□今已遠，永懷帝德浩無邊。", "他時信史傳遺事，悟主應□數百篇。"]'),
('7ecc2a2f-6a70-4169-a02b-c30e4036fd2a','省謁觀文之塋留題  其二','范公','宋','宋诗','song-poetry','','[]','贊書褒顯下重泉，嗣聖初臨建武年。',64,'全唐诗/poet.song.254000.json','["贊書褒顯下重泉，嗣聖初臨建武年。", "河洛圖書光似日，商周盤誥遠如天。", "孤墓豈意留空谷，直意猶能禦二邊。", "彷彿音塵如在目，遺風雅頌紀新篇。"]'),
('0f8705b2-524e-4952-be3a-8d72e44e361d','咏麻姑山','許杭','宋','宋诗','song-poetry','','[]','數里岧嶢落日西，更高高處種靈芝。',64,'全唐诗/poet.song.254000.json','["數里岧嶢落日西，更高高處種靈芝。", "危峰受雪春歸晚，怪石留雲雨到遲。", "仙鹿避人眠淺徑，野禽窺果啄殘枝。", "待應俗格消磨盡，重建瑶臺舊路歧。"]'),
('9eac7863-998b-40de-887a-f86d2e317161','遊麻姑山','李潜真','宋','宋诗','song-poetry','','[]','凌晨特跨赤龍車，御氣乘風下九衢。',64,'全唐诗/poet.song.254000.json','["凌晨特跨赤龍車，御氣乘風下九衢。", "金闕殿前朝玉帝，丹霞洞口謁麻姑。", "朱絃未達鍾期耳，青鳥空傳漢殿書。", "鐵笛一聲誰會得，獨飛蹤跡到仙都。"]'),
('5c4119ad-7de7-442f-93e4-32df0a7ee918','遊麻姑','上清真人','宋','宋诗','song-poetry','','[]','攀蘿躡翠上麻姑，得到山中景物殊。',64,'全唐诗/poet.song.254000.json','["攀蘿躡翠上麻姑，得到山中景物殊。", "白鶴有情來碧落，綵鸞無意下清都。", "仙媛虛見桑田變，世事誰經海水枯。", "爲問方平開宴後，不知還約再來無。"]'),
('0af7dabe-f0d9-4568-b67a-c69d517a16c8','遊麻姑','□松卿','宋','宋诗','song-poetry','','[]','平生但玩魯公碑，今日身親到翠微。',64,'全唐诗/poet.song.254000.json','["平生但玩魯公碑，今日身親到翠微。", "一徑穹窿騰石棧，萬松森立護雲扉。", "真人得道書丹籍，福地遺蹤付羽衣。", "蹔得清幽消俗慮，不堪斜日便催歸。"]'),
('78b5c1fa-adb3-4a9b-94c3-b8509dbaf448','仙壇','蜀僧','宋','宋诗','song-poetry','','[]','萬疊峰巒聳太清，麻姑曾此會方平。',32,'全唐诗/poet.song.254000.json','["萬疊峰巒聳太清，麻姑曾此會方平。", "一從宴罷歸何處，寶殿瑶臺空月明。"]'),
('9201c01e-08f4-420a-91e2-7011582edab1','九日送人','陳顔','宋','宋诗','song-poetry','','[]','今夕遂獨坐，今晨已別離。',48,'全唐诗/poet.song.254000.json','["今夕遂獨坐，今晨已別離。", "同此良宵中，秋意各自知。", "灧灧潮與汐，來往亦何爲。", "嗟爾扁舟子，何時老藩籬。"]'),
('b362bf46-f36a-41ea-a74a-5e4cb7d83080','散懷','陳顔','宋','宋诗','song-poetry','','[]','世亂無爾我，安心伏草茅。',48,'全唐诗/poet.song.254000.json','["世亂無爾我，安心伏草茅。", "從今離蠆尾，向晚轉花稍。", "筆墨徜徉事，溪山淡泊肴。", "祇留蘭與菊，傍我作知交。"]'),
('e678d40d-ace4-4662-928f-6040e5f94a01','輓友','陳顔','宋','宋诗','song-poetry','','[]','去與來相引，修隨短共旋。',48,'全唐诗/poet.song.254000.json','["去與來相引，修隨短共旋。", "只爭生有骨，方信死無權。", "老友身前法，文章覺後圓。", "知君能悟此，哭唁一徒然。"]'),
('ecf169e9-891e-4c42-845d-bf7531b7400b','寄內','董蘿','宋','宋诗','song-poetry','','[]','別向春閨十載深，家園無夢可追尋。',64,'全唐诗/poet.song.254000.json','["別向春閨十載深，家園無夢可追尋。", "酸風冷月淒官閣，瘴雨蠻烟度鬰林。", "養老需卿扶健杖，怕寒憐我守孤衾。", "封侯未卜常滋愧，一寸程途一寸心。"]'),
('f0104491-45b3-4d2b-a5fb-39e99d9bd5ab','吳山','陳恭','宋','宋诗','song-poetry','','[]','吳山煙樹復如何，老去登臨感慨多。',64,'全唐诗/poet.song.254000.json','["吳山煙樹復如何，老去登臨感慨多。", "似說怒濤仍白馬，還看遠嶂只青螺。", "三秋草色凌荷芰，萬里閒雲下薜蘿。", "可惜江湖長浩蕩，只供短髪一高歌。"]'),
('80af9ed4-2548-429b-a759-1e2f78dbb825','感懷','陳恭','宋','宋诗','song-poetry','','[]','回首滄桑已數番，感懷無盡又何言。',64,'全唐诗/poet.song.254000.json','["回首滄桑已數番，感懷無盡又何言。", "悲看世路皆危壑，喜共家人在故園。", "筆底有心神自遠，來年多難骨猶存。", "連章句弗矜佳麗，風雅於今止一痕。"]'),
('3f52f140-2147-421a-93c5-a7a1e8d3d8f8','次韻答友','陳恭','宋','宋诗','song-poetry','','[]','竹枝歌憶楚江天，曾向潯陽久泊船。',64,'全唐诗/poet.song.254000.json','["竹枝歌憶楚江天，曾向潯陽久泊船。", "君過石鐘尋舊韻，我知鑪頂起新煙。", "故人寥落今誰在，好夢迢遥亦偶然。", "秋以爲期猶未至，冷鴻疏草暮雲邊。"]'),
('be033681-2bc0-4cbd-93fa-2d7938498da3','秋夜聞蛩和壁間韻','史慥之','宋','宋诗','song-poetry','','[]','霜氣添秋肅，蛩聲入夜清。',48,'全唐诗/poet.song.254000.json','["霜氣添秋肅，蛩聲入夜清。", "爲誰衣未織，向我語偏明。", "庭外三更月，牀頭萬里情。", "凄然如有訴，愁思動人生。"]'),
('56836e17-03ac-43e1-92f5-f915a1c2ed3b','移居甬江有感  其一','屠季','宋','宋诗','song-poetry','','[]','卜宅傍江隈，幽閑絕點埃。',48,'全唐诗/poet.song.254000.json','["卜宅傍江隈，幽閑絕點埃。", "青山排闥入，碧水繞籬回。", "孤况依歸鳥，愁懷對酒杯。", "百年堪一笑，未死已心灰。"]'),
('3ad4fa14-a3f3-4c56-8767-01cafd24a82f','移居甬江有感  其二','屠季','宋','宋诗','song-poetry','','[]','車馬長云寂，逍遥意亦嘉。',48,'全唐诗/poet.song.254000.json','["車馬長云寂，逍遥意亦嘉。", "水田殊不惡，茅屋詎堪嗟。", "故土含情遠，荒村入望賒。", "何由慰旅泊，耕殖畢生涯。"]'),
('7fbca48d-b8df-4032-a6d4-d7e55ec42576','泗上歌','薛師心','宋','宋诗','song-poetry','','[]','北風蕭騷兮吹逝波，英雄一去兮歲月多，路草青青兮遊人過。',27,'全唐诗/poet.song.254000.json','["北風蕭騷兮吹逝波，英雄一去兮歲月多，路草青青兮遊人過。"]'),
('5b16741b-7492-45a6-a3f0-edff9de79a5d','黄天蕩阻風','薛師心','宋','宋诗','song-poetry','','[]','野泊幾人愁，浮蹤果是漚。',48,'全唐诗/poet.song.254000.json','["野泊幾人愁，浮蹤果是漚。", "輕舠同一羽，高浪即三秋。", "欹枕江聲震，開篷雨腳收。", "風波身漫涉，何處有安流。"]'),
('fd0600d6-a01f-4cdd-8d56-3f14fce172c2','石頭城遇盧明府丈','薛師心','宋','宋诗','song-poetry','','[]','浮生蹤跡似浮雲，把酒論交對夕曛。',64,'全唐诗/poet.song.254000.json','["浮生蹤跡似浮雲，把酒論交對夕曛。", "十載師門稱畏友，一朝吏事誦神君。", "口中高論人間少，名下宏詞海內聞。", "此會正當春色好，莫教邂逅手輕分。"]'),
('dcefb5e8-f9a1-4e8d-bef6-5f26b154c38c','青龍巖','廖則逢','宋','宋诗','song-poetry','','[]','有泉瑩潔深谼豅，奫潫湀㶄聲如鐘。',88,'全唐诗/poet.song.254000.json','["有泉瑩潔深谼豅，奫潫湀㶄聲如鐘。", "{髟/市}{髟/市}使我毛髪豎，中有高卧虬髯翁。", "砯崖瀑布瀉明月，驚溜觸石調焦桐。", "蠲煩析酲竟造此，稽首匍拜玄冥宮。", "蜿蜒莫向此中處，天下蒼生待霖雨。"]'),
('1c6e3e6e-0780-4060-bcc0-5158fcf2fec4','紫麟峰','趙永言','宋','宋诗','song-poetry','','[]','千仞奇峰薄上清，葛洪於此尚留名。',64,'全唐诗/poet.song.254000.json','["千仞奇峰薄上清，葛洪於此尚留名。", "紫麟瑞靄春風煖，白虎丹成夜月明。", "點點蒼苔空有跡，菲菲芳草輭無聲。", "高蹤回首今何在，山水猶含萬古情。"]'),
('ea3d3328-5435-41db-9977-f86d9ff13753','合江亭','無名氏','宋','宋诗','song-poetry','','[]','□□□來□此州，□□偶到合江遊。',64,'全唐诗/poet.song.254000.json','["□□□來□此州，□□偶到合江遊。", "□□雨過□□□，□□□□□□油。", "韓愈詩奇封碧蘚，朱陵洞古枕寒流。", "肩輿歸去日將暮，啼鳥一聲山更幽。"]'),
('29f87d49-18f6-4170-b89f-6eb1408bfaf6','虞帝陵','無名氏','宋','宋诗','song-poetry','','[]','重華車駕瘞崔嵬，不似秦皇賜璽回。',64,'全唐诗/poet.song.254000.json','["重華車駕瘞崔嵬，不似秦皇賜璽回。", "西治驪山營兆域，東浮滄海訪蓬萊。", "陟方年已過期頤，老死勤民志不衰。", "何事穆王心醉飽，耄荒無復念前規。"]'),
('fc947370-d8a0-45ae-9adf-faeed270e8d7','何侯洞','無名氏','宋','宋诗','song-poetry','','[]','何氏因韓姓始傳，無由與舜共升天。',32,'全唐诗/poet.song.254000.json','["何氏因韓姓始傳，無由與舜共升天。", "洞前九井皆湮沒，唯有荆榛繞廟壖。"]'),
('3361baff-945b-4331-8143-285e1e082c4b','九疑山','無名氏','宋','宋诗','song-poetry','','[]','谿山相似路人疑，衆目詳觀固易知。',32,'全唐诗/poet.song.254000.json','["谿山相似路人疑，衆目詳觀固易知。", "厚貌深情懷險阻，離朱子羽謾揚眉。"]'),
('af7c74ee-7bdf-4f6c-9ee4-d79b9b8cdf77','碧虛洞','無名氏','宋','宋诗','song-poetry','','[]','灌溉工興古洞荒，洞門□蔽碧池傍。',64,'全唐诗/poet.song.254000.json','["灌溉工興古洞荒，洞門□蔽碧池傍。", "□□□□□□□，□□波□□□霜。", "□□□□□□□，□窗□月□寒光。", "□□□□□□□，□□□□代是□。"]'),
('6b57b947-2c6f-4d81-b80a-5bf9ab287714','遊乳洞庵','胡子澄','宋','宋诗','song-poetry','','[]','結屋青山下，幽深不計年。',48,'全唐诗/poet.song.254000.json','["結屋青山下，幽深不計年。", "泉聲秋霽雨，鐘響暮晴天。", "入洞尋僧伴，穿雲見鹿眠。", "徘徊不忍去，夜宿佛堂前。"]'),
('8c35026d-8661-4794-8f8c-bd3eb4bf9237','乳洞','胡子澄','宋','宋诗','song-poetry','','[]','古洞幽深處，縈迴路幾重。',96,'全唐诗/poet.song.254000.json','["古洞幽深處，縈迴路幾重。", "門開空寂寂，泉溜暗淙淙。", "斷壑雲連屋，奔流水激舂。", "橋橫千丈石，巖挂萬年松。", "鶴駕應重到，龜田必再逢。", "碧沙還錯落，密篠自迷濛。", "乳結銀爲樹，漿凝雪作峰。", "仙人何處去，應想子喬蹤。"]'),
('e4b17c1c-0c21-43e2-a309-e7fb313c04aa','文斾山','通真子','宋','宋诗','song-poetry','','[]','魏氏當年禮斗壇，至今遺址在人間。',64,'全唐诗/poet.song.254000.json','["魏氏當年禮斗壇，至今遺址在人間。", "蒼梧已老烟霞淡，丹竈空餘歲月閒。", "鈴鐸夜深驚睡鶴，幡幢晴影上空山。", "後人自媿縻婚宦，不得追隨款舊關。"]'),
('4f8f776e-de6a-41fc-90dc-db8d6fecee91','句','頼繼善','宋','宋诗','song-poetry','','[]','白日干戈萬馬塵，鐵心不碎竟誰身。',16,'全唐诗/poet.song.254000.json','["白日干戈萬馬塵，鐵心不碎竟誰身。"]'),
('ae69e18f-0658-418a-9981-2f072bba656f','遊資縣東巖','何景南','宋','宋诗','song-poetry','','[]','人事何時休，紛來如野馬。',120,'全唐诗/poet.song.254000.json','["人事何時休，紛來如野馬。", "相携解鑣處，去約巖之下。", "清凉二城雨，况值禳禬罷。", "白雲醉堪眠，青草春可藉。", "泉甘嗽蘇醒，樹好留閒暇。", "頻遊我嘗慣，忽至公成乍。", "徘徊共幽興，靜坐絺衣掛。", "中間五百士，閲世知幾夏。", "莓苔自成古，香火仍同社。", "巖縫更依然，莫問豐干話。"]'),
('b1228d31-0432-4031-8009-e63e71bb6180','漁樵','侯蕃','宋','宋诗','song-poetry','','[]','漁樵結伴住山谿，蓑笠生涯路不迷。',64,'全唐诗/poet.song.254000.json','["漁樵結伴住山谿，蓑笠生涯路不迷。", "洞口桃花春水滿，峰頭槲葉夕陽低。", "故人莫遣尋嚴瀨，太守何須說會稽。", "換得酒來歌得曲，大家不惜醉如泥。"]'),
('e16e722c-90b5-4937-a97c-2bb7f253657f','寄贈華陽洞隠者  其一','李楙','宋','宋诗','song-poetry','','[]','句容郭裏望三峰，綠翠芙蓉杳靄中。',32,'全唐诗/poet.song.254000.json','["句容郭裏望三峰，綠翠芙蓉杳靄中。", "安得與君騎兩鹿，碧巖深處聽松風。"]'),
('fb560927-fdd3-4d3b-94dd-a374a9a72a2c','寄贈華陽洞隠者  其二','李楙','宋','宋诗','song-poetry','','[]','天上神仙白玉扉，春雲誰繡六銖衣。',32,'全唐诗/poet.song.254000.json','["天上神仙白玉扉，春雲誰繡六銖衣。", "人間傳得新詩句，爲有高僧到紫微。"]'),
('52d7e6b8-0f48-4601-a644-e4a0d14f794b','宗壇秋夕','褚環中','宋','宋诗','song-poetry','','[]','疏綺平雲徹夜開，月明峰頂見樓臺。',32,'全唐诗/poet.song.254000.json','["疏綺平雲徹夜開，月明峰頂見樓臺。", "璚璈聲裏天燈近，知是三真謁帝回。"]'),
('33c33e1f-6f32-4b2e-bf08-f86c8c42dec7','送僧歸鳳山','釋師瑞','宋','宋诗','song-poetry','','[]','鳳凰山下鳳凰兒，文綵纔彰羽翼齊。',32,'全唐诗/poet.song.254000.json','["鳳凰山下鳳凰兒，文綵纔彰羽翼齊。", "鐵網漫天攔不得，歸心已在碧梧枝。"]'),
('4487c369-74a6-4bea-92c7-156854cb08dc','十龜潭祈雨','張春皓','宋','宋诗','song-poetry','','[]','緣蘿躡蹬共躋攀，水色山光遠近間。',64,'全唐诗/poet.song.254000.json','["緣蘿躡蹬共躋攀，水色山光遠近間。", "一勺龍蟠通海窟，半空虎嘯隔塵寰。", "石潭雲冷人稀到，溪路苔生爲倦還。", "早望雲霓施聖澤，何難菅屨步靈山。"]'),
('bc2040da-1188-48ea-b5e6-a8bb7aa7477d','永樂寺','釋龍石','宋','宋诗','song-poetry','','[]','江雲如鏡平，月當秋夜白。',24,'全唐诗/poet.song.254000.json','["江雲如鏡平，月當秋夜白。", "欸乃一聲歌，舟中南北客。"]'),
('c6d9446f-c8d3-4cdb-a537-c77ebf0ae075','舟泊港口','洪漸','宋','宋诗','song-poetry','','[]','月浸蘆花水漫天，漁翁醉後正堪眠。',32,'全唐诗/poet.song.254000.json','["月浸蘆花水漫天，漁翁醉後正堪眠。", "夜深何處孤猿咽，不管江邊有客船。"]'),
('6ff67c39-05f6-4bf1-9017-fc3a84af55e9','鳳鳴洞','史昌卿','宋','宋诗','song-poetry','','[]','何年雷斧鑿山裂，六月蒼崖細飛雪。',64,'全唐诗/poet.song.254000.json','["何年雷斧鑿山裂，六月蒼崖細飛雪。", "孤鳳一去聲不聞，海水桑田幾興滅。", "我知仙去仙尚存，時見真形生巖穴。", "青天半夜玉簫寒，喚起幽人舞明月。"]'),
('078d5a24-86f5-4e71-abee-8865bcd522e4','大觀堂','周德輝','宋','宋诗','song-poetry','','[]','披襟渺無際，一笑碧雲頭。',24,'全唐诗/poet.song.254000.json','["披襟渺無際，一笑碧雲頭。", "千里當眉睫，何須更上樓。"]'),
('b7a72fef-6c34-4070-9316-dad4876a0851','洞庭晚望七首  其一','高善濂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','擊汰凉風水面迴，偃虹堤上夕陽開。',64,'全唐诗/poet.song.254000.json','["擊汰凉風水面迴，偃虹堤上夕陽開。", "含漿老蜌浮光起，迎棹神鴉舞翅回。", "醉唱難尋漁笛樂，羈懷易動暮笳哀。", "何能雪鷺銀鷗侶，盡日無愁曲岸隈。"]'),
('b0e918d0-b753-4343-aa25-cc57a7cd28df','洞庭晚望七首  其二','高善濂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西塞烟痕向晚橫，登臨聊復上重城。',64,'全唐诗/poet.song.254000.json','["西塞烟痕向晚橫，登臨聊復上重城。", "湖邊匯澤流千派，望裏長巒翠一桁。", "歸檝江皋頻錯認，懷人天末最關情。", "散愁商隠還乘興，只恐風波愁轉生。"]'),
('f54afd9d-8640-4823-bee9-37781cbde420','岳陽樓晚眺即事疊韻四首  其一','高善濂','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','危樓縹緲倚闌斜，無數殘陽噪亂鴉。',64,'全唐诗/poet.song.254000.json','["危樓縹緲倚闌斜，無數殘陽噪亂鴉。", "過客揚帆衝雪浪，漁人舉網出銀花。", "子聲落紙閒聽奕，舌本留香爲別茶。", "巫峽瀟湘恣極覽，誰言遠望當歸家。"]'),
('e3474b6f-d774-4db4-bf3c-36bed7b9d707','岳陽樓晚眺即事疊韻四首  其二','高善濂','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','無聊憑眺日西斜，替恨成啼集暮鴉。',64,'全唐诗/poet.song.254000.json','["無聊憑眺日西斜，替恨成啼集暮鴉。", "遠樹雲中浮墨障，游魚鏡底動菱花。", "臨高每憶登樓賦，遣興還嘗覓句茶。", "到處羈愁多瑟縮，何如烟浦釣人家。"]'),
('11512665-c134-4b09-8e04-69e7b446b701','碧雲洞','蔣燮','宋','宋诗','song-poetry','','[]','漢室真人已駕鴻，空留洞府舊山中。',64,'全唐诗/poet.song.254000.json','["漢室真人已駕鴻，空留洞府舊山中。", "暮雲凝合元非鏁，俗骨腥羶自不通。", "束火杖藜深杳杳，袖椎敲石喜𩐨𩐨。", "若爲化作雙飛舄，得與郎官繼此風。"]'),
('613061c8-c0b7-4e99-b155-b51a8a84f4aa','此游淡巖同成一詩敢用拜呈','無名氏','宋','宋诗','song-poetry','','[]','行盡瀟湘山復山，掣舟來叩淡巖關。',64,'全唐诗/poet.song.254000.json','["行盡瀟湘山復山，掣舟來叩淡巖關。", "幽深雖與塵寰隔，空闊猶容俗駕攀。", "是處名山有巖竇，莫如此地最寬閑。", "真人仙去知何在，陳迹空留警世頑。"]'),
('570757ab-2492-4d79-926c-63496c630e55','象耳山','無名氏','宋','宋诗','song-poetry','','[]','籃輿來自石蒼路，喜得幽人陪杖屨。',32,'全唐诗/poet.song.254000.json','["籃輿來自石蒼路，喜得幽人陪杖屨。", "應是山靈澤旱苗，不關居士隨軒雨。"]'),
('1e1d7a75-7ea1-46e7-834b-8eb42b5e5fa6','遊象耳山','無名氏','宋','宋诗','song-poetry','','[]','水似青蘿带，山如碧玉環。',48,'全唐诗/poet.song.254000.json','["水似青蘿带，山如碧玉環。", "池蛙鳴聒聒，林鳥語關關。", "松檜磐高蓋，藤蘿引翠鬟。", "倚欄無一語，何以慰幽閒。"]'),
('b6e3dbb3-0b81-40f5-8248-5e72aa41f05b','碧沼寺','楊良臣','宋','宋诗','song-poetry','','[]','薄蹤飄梗寄禪扃，偶到山間萬慮清。',64,'全唐诗/poet.song.254000.json','["薄蹤飄梗寄禪扃，偶到山間萬慮清。", "方愧軒裳奔走役，忍聞猿鶴怨啼聲。", "世情肯顧青衫老，公道惟均白髪生。", "事業不須頻覽鏡，幻身堪比羽毛輕。"]'),
('c28895cf-7195-4de1-9661-84f5cd9e0d79','寶蓋山','趙永嘉','宋','宋诗','song-poetry','','[]','青山吐出白龍開，我是地仙趙秀才。',32,'全唐诗/poet.song.254000.json','["青山吐出白龍開，我是地仙趙秀才。", "嘉善有魚餐得去，永嘉有虎喚能來。"]'),
('628049cd-03fe-4430-a4d2-c442ee09c2ad','新婦石','林小山','宋','宋诗','song-poetry','','[]','瘦骨崚嶒立海湄，綠苔曾是嫁時衣。',32,'全唐诗/poet.song.254000.json','["瘦骨崚嶒立海湄，綠苔曾是嫁時衣。", "江郎去作三衢客，目斷天涯竟未歸。"]'),
('d42e772f-c82f-42a9-9fde-aad4258eb0ef','遊石室','趙時','宋','宋诗','song-poetry','','[]','假守聖朝多宰輔，紀題昔日盡名賢。',32,'全唐诗/poet.song.254000.json','["假守聖朝多宰輔，紀題昔日盡名賢。", "我今始會由來意，此境棲遲本列仙。"]'),
('798b4e5e-b923-414d-8cd6-9d29f352db16','題回山人畫像','宇文孝叔','宋','宋诗','song-poetry','','[]','仙蹤久矣閉禪關，忽遇高人喚得還。',64,'全唐诗/poet.song.254000.json','["仙蹤久矣閉禪關，忽遇高人喚得還。", "創就琳宮依岌嶪，移來真像带斕斑。", "路通遠浦重重水，樓倚長松面面山。", "酌我一杯如有意，坐令衰臉變朱顔。"]'),
('8acf81ff-21f2-4084-bd56-1b7c6c8052f3','榴皮題壁  其一','孫唐卿','宋','宋诗','song-poetry','','[]','碧眼仙人曾着句，玉堂學士繼其餘。',32,'全唐诗/poet.song.254000.json','["碧眼仙人曾着句，玉堂學士繼其餘。", "祇今雖說西鄰富，爭是東庵有異書。"]'),
('1135ec31-4d86-4f93-b0dd-143e7795f5b7','榴皮題壁  其二','孫唐卿','宋','宋诗','song-poetry','','[]','喚回二百年前夢，索飲西風一醉餘。',32,'全唐诗/poet.song.254000.json','["喚回二百年前夢，索飲西風一醉餘。", "壁上榴皮在何處，遊人空指沈庵書。"]'),
('ea8cab64-d6ad-4993-a50e-480151e148e1','榴皮題壁  其一','孫子光','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','黄鶴樓中吹笛罷，洞庭湖畔醉吟餘。',32,'全唐诗/poet.song.254000.json','["黄鶴樓中吹笛罷，洞庭湖畔醉吟餘。", "劍光如寶無人識，却記榴皮幾字書。"]'),
('0adf6543-8d06-42ec-9c39-9693b098b3dd','榴皮題壁  其二','孫子光','宋','宋诗','song-poetry','','[]','天地之間猶有礙，江山酌酒尚無餘。',32,'全唐诗/poet.song.254000.json','["天地之間猶有礙，江山酌酒尚無餘。", "長裘短褐經行處，惟見龍蛇壁上書。"]'),
('7c432bc2-65dc-467d-b25b-b39ab82a6b25','榴皮題壁  其一','王真人','宋','宋诗','song-poetry','','[]','東老回仙跨鶴歸，同庵卜築繼其餘。',32,'全唐诗/poet.song.254000.json','["東老回仙跨鶴歸，同庵卜築繼其餘。", "自緣不臯榴皮字，想像祇園蔓草書。"]'),
('4964b50c-8a83-4aa9-ae81-868d866a40f1','榴皮題壁  其二','王真人','宋','宋诗','song-poetry','','[]','惟知自己貧無諂，不羨他人富有餘。',32,'全唐诗/poet.song.254000.json','["惟知自己貧無諂，不羨他人富有餘。", "白酒會能延羽客，清名贏得著仙書。"]'),
('bb457b65-646d-49ab-9e97-611bdac8e8c5','榴皮題壁','丁逢季','宋','宋诗','song-poetry','','[]','水雲深處扣仙居，對酌春風夜有餘。',32,'全唐诗/poet.song.254000.json','["水雲深處扣仙居，對酌春風夜有餘。", "說遍東南耆舊話，始知勝讀十年書。"]'),
('dfd5acba-9769-485b-bd82-ad05cba258f6','榴皮題壁','葉三英','宋','宋诗','song-poetry','','[]','求仙那得仙來訪，多積陰功至有餘。',32,'全唐诗/poet.song.254000.json','["求仙那得仙來訪，多積陰功至有餘。", "欲悟東林沈東老，故留三十六玄書。"]'),
('f41dee7c-8ab0-448c-ae32-690af836f2a5','和榴皮題壁韻','馮開元','宋','宋诗','song-poetry','','[]','萬里間關辭蜀道，六年前後到西餘。',32,'全唐诗/poet.song.254000.json','["萬里間關辭蜀道，六年前後到西餘。", "雖無泰華寄來樹，且讀人間未見書。"]'),
('2633fa0f-e7a8-4298-b68f-d79554a3cc76','榴皮題壁','任鄭','宋','宋诗','song-poetry','','[]','榴皮不見烟火語，雋咏坡仙三和餘。',32,'全唐诗/poet.song.254000.json','["榴皮不見烟火語，雋咏坡仙三和餘。", "從此留芳應未歇，斕斑蘚壁可無書。"]'),
('11f2bf25-dcb3-4b6e-85f7-e3ea13393a3a','玉女峰','周載','宋','宋诗','song-poetry','','[]','誰將玉女對粧臺，曲水分明一鑑開。',32,'全唐诗/poet.song.254000.json','["誰將玉女對粧臺，曲水分明一鑑開。", "鐵石肺腸塵夢斷，任他雲雨逐人來。"]'),
('156bc557-445f-4fd8-b1a5-3c2ff80c4349','晚對亭','虞億','宋','宋诗','song-poetry','','[]','落日下青嶂，歸雲獨未安。',24,'全唐诗/poet.song.254000.json','["落日下青嶂，歸雲獨未安。", "倚杖無言久，夕陰生翠寒。"]'),
('11e17e8e-35a4-4f1e-878f-4c2dda77b31c','中秋同諸子九曲泛月','虞億','宋','宋诗','song-poetry','','[]','名山閲萬古，明月來幾時。',228,'全唐诗/poet.song.254000.json','["名山閲萬古，明月來幾時。", "顧遊屬中秋，萬里雲霧披。", "心閒境亦靜，月滿山不移。", "况茲九曲溪，正漾清漣漪。", "呼舟星村來，十客琴觴隨。", "此客俱不凡，灑落同襟期。", "居然命釣艇，造席不復疑。", "陶兀入醉鄉，伴我老不羈。", "臨流振衣袂，颯颯剛風吹。", "銀盤轉巖阿，兩川光渺瀰。", "崚嶒大王峰，嵌竇渺可窺。", "雲軿與鳳釵，來往誰可知。", "但聞山桂香，繽紛落殘巵。", "酒酣各言志，抗論不少卑。", "諸君愛軒冕，許身臯與夔。", "矯首青雲衢，塵鞅甘羈縻。", "那知涉幻境，百歲黍一炊。", "風波世上險，日月壺中遲。", "何如歸此山，相樂從希夷。"]'),
('34de8ec6-63f7-484f-b9c5-356e82611be8','接笋峰','邱攀桂','宋','宋诗','song-poetry','','[]','天下名山說武夷，高峰晴樹碧雲齊。',64,'全唐诗/poet.song.254000.json','["天下名山說武夷，高峰晴樹碧雲齊。", "望窮石鼎疑無地，行到山根却有梯。", "茅屋成村多卜隠，草書懸壁半留題。", "幾時掃斷紅塵路，一葉漁舟九曲溪。"]'),
('333f8b85-2fd1-47e3-bd8b-967142c8ac5d','紀遊','朱大卿','宋','宋诗','song-poetry','','[]','開秋氣微肅，天水湛相照。',84,'全唐诗/poet.song.254000.json','["開秋氣微肅，天水湛相照。", "扁舟愜幽尋，層峰入奇眺。", "融結幾何年，指顧集群妙。", "神仙得非幻，遺蛻在巖竅。", "行往求其蹤，恐爲識者笑。", "獨鶴去不還，山猿偶然叫。", "應有采芝人，凌空發長嘯。"]'),
('907135b2-d05c-49a6-a9af-c6a618567332','繫舟','詹羲','宋','宋诗','song-poetry','','[]','石廩巖前繫小舟，娟娟明月照清秋。',32,'全唐诗/poet.song.254000.json','["石廩巖前繫小舟，娟娟明月照清秋。", "仙人一夜吹長笛，三十六峰雲盡收。"]'),
('97fd48d7-ca0f-42ea-bd7e-98641e733ccd','一盌泉','張知退','宋','宋诗','song-poetry','','[]','泉形如盌水波圓，一勺之多可悟全。',32,'全唐诗/poet.song.254000.json','["泉形如盌水波圓，一勺之多可悟全。", "試看靈湫輕灑處，甘霖頃刻徧秦川。"]'),
('31570eac-d36b-4e95-bac6-3906eea63106','偶成','陳雲龍','宋','宋诗','song-poetry','','[]','野趣成閒散，青山即故知。',48,'全唐诗/poet.song.254000.json','["野趣成閒散，青山即故知。", "竹生踰砌笋，花引隔牆枝。", "舞蝶翻風亂，閒雲出塢遲。", "倚欄無一事，俄有客傳詩。"]'),
('d35530f6-760c-4f17-a223-331119f89f38','秋興','林東愚','宋','宋诗','song-poetry','','[]','落日江城動鼓鼙，故山千里轉逶迤。',64,'全唐诗/poet.song.254000.json','["落日江城動鼓鼙，故山千里轉逶迤。", "謝安舊宅空陳迹，尼父餘風異昔時。", "苜蓿秋高戎馬健，海門日短雁書遲。", "客窗兀對黄昏坐，雲漢悠悠起暮思。"]'),
('38a3968f-27ba-4220-ac35-a2265f4140f2','皎皎吟','朱巖伯','宋','宋诗','song-poetry','','[]','皎皎天心月，影落寒潭水。',80,'全唐诗/poet.song.254000.json','["皎皎天心月，影落寒潭水。", "雖落寒潭水，照人千萬里。", "皎皎機上絲，忽落淤泥底。", "一落淤泥底，河水不可洗。", "願君作明月，晴陰不妨缺。", "莫作淤泥絲，客子徒傷悲。", "人心皎皎莫自欺。"]'),
('53c62a61-178f-4e24-8b56-c09dc5ac1c22','書延福寺壁','朱巖伯','宋','宋诗','song-poetry','','[]','雙瀑飛來古寺西，月蘿烟草久湮迷。',64,'全唐诗/poet.song.254000.json','["雙瀑飛來古寺西，月蘿烟草久湮迷。", "自從吾輩經行後，便覺他山索價低。", "老去合爲三徑計，就中聊借一枝棲。", "石崖大有穿磨所，從與新詩著處題。"]'),
('c0edc415-2759-46d4-b791-e6a63b87e97c','紅葉','林賓暘','宋','宋诗','song-poetry','','[]','五夜霜爲染，輕明映碧流。',48,'全唐诗/poet.song.254000.json','["五夜霜爲染，輕明映碧流。", "山林驚有色，天地欲無秋。", "野渡風初起，夕陽雨未收。", "昔聞供墨客，霜屋落颼飀。"]'),
('0419b246-ac59-4b34-8a0e-e6d6ebc8d75e','病鶴','林賓暘','宋','宋诗','song-poetry','','[]','松梢秋氣怯霜衣，猶爲山人守石扉。',64,'全唐诗/poet.song.254000.json','["松梢秋氣怯霜衣，猶爲山人守石扉。", "仙國靈丹無處覓，故鄉華表幾時歸。", "心知海上雲霄□，眼見林間燕雀飛。", "却恨吹臺消息斷，草烟城郭照斜暉。"]'),
('8746ae19-7fd4-4652-8d42-50d1b98927c3','次黄日巖韻','王舫','宋','宋诗','song-poetry','','[]','孤舟閑野渡，竹外小橋通。',48,'全唐诗/poet.song.254000.json','["孤舟閑野渡，竹外小橋通。", "不涉終南逕，獨高彭澤風。", "雲閑鐘梵裏，月靜笑談中。", "千載留清節，誰云吾道窮。"]'),
('7f9a4018-50d1-4f8d-9370-ff86947edc66','次韻答陳石泉','王舫','宋','宋诗','song-poetry','','[]','炎氣漲空碧，散作藕花秋。',48,'全唐诗/poet.song.254000.json','["炎氣漲空碧，散作藕花秋。", "幽趣蘭爲佩，浮生芥作舟。", "可人從遠別，何日許重遊。", "奩玉清無底，樓居第幾州。"]'),
('3fcfad31-9f75-4311-8856-8659b5f88931','晚憩石門洞','王舫','宋','宋诗','song-poetry','','[]','艤棹石門外，天風吹夕陰。',48,'全唐诗/poet.song.254000.json','["艤棹石門外，天風吹夕陰。", "疏鐘醒客夢，危瀑洗塵襟。", "龍去洞雲薄，鶴歸松露深。", "舊碑看米字，猶带蘚痕侵。"]'),
('c0805dde-882c-4cf8-bd82-66e8bcb1caae','次愚谷雪韻','王舫','宋','宋诗','song-poetry','','[]','榾柮爐頭夜未闌，冰壺全覺漏聲乾。',64,'全唐诗/poet.song.254000.json','["榾柮爐頭夜未闌，冰壺全覺漏聲乾。", "前山草木疑長白，下界樓臺盡廣寒。", "騷客忽驚梅片落，老農先作稻花看。", "何當一奏平淮頌，坐使皇圖九鼎安。"]'),
('9c29384e-801e-4245-97a2-33a0c0271698','春日郊行次平野韻','王舫','宋','宋诗','song-poetry','','[]','楚澤凄凉笑屈原，行吟如在浣花川。',64,'全唐诗/poet.song.254000.json','["楚澤凄凉笑屈原，行吟如在浣花川。", "風迴別墅聞桐角，烟冷荒郊掛紙錢。", "麰麥正香田舍樂，茅柴初熟酒家連。", "錦囊收拾歸來晚，踏月閑敲款段鞭。"]'),
('d9b835bf-0a4d-47eb-9ee8-56bb2958d011','清虛堂','陳簡軒','宋','宋诗','song-poetry','','[]','閉門瀟灑入窗明，一洗浮生夢幻情。',64,'全唐诗/poet.song.254000.json','["閉門瀟灑入窗明，一洗浮生夢幻情。", "夜月靜移花下影，曉風輕度竹間聲。", "天空寥廓人孤坐，地聳高寒鶴不驚。", "滿眼青山雲散盡，恍疑身世在蓬瀛。"]'),
('26a2fbdc-ab2a-45fc-a5c9-e408115fece2','醉芙蓉','陳簡軒','宋','宋诗','song-poetry','','[]','璚姬秋宴集蓬壺，酒暈微微上雪酥。',64,'全唐诗/poet.song.254000.json','["璚姬秋宴集蓬壺，酒暈微微上雪酥。", "笑倚西風渾不定，因臨流水欲相扶。", "綠雲香減霜初冷，紅玉痕消日又晡。", "妝鏡明朝見真色，不知猶带宿酲無。"]'),
('1ded0208-3243-4c95-a8bf-7d4b907617f4','山房','鄭鼎夫','宋','宋诗','song-poetry','','[]','冉冉雲生石，柴扉半掩深。',48,'全唐诗/poet.song.254000.json','["冉冉雲生石，柴扉半掩深。", "餘春歸草意，積雪負葵心。", "老去忽自笑，興來時獨斟。", "閑中參物理，何處一蟬吟。"]'),
('4fb0ac53-f228-41d8-b796-90e8975a83a2','張子房','鄭鼎夫','宋','宋诗','song-poetry','','[]','功成便趁赤松遊，未必神仙事可求。',32,'全唐诗/poet.song.254000.json','["功成便趁赤松遊，未必神仙事可求。", "想得當時重借箸，爲君謀了爲身謀。"]'),
('c675cd50-3b34-4862-9d39-5eca7947863f','擬古  其一','趙處澹','宋','宋诗','song-poetry','','[]','青青河畔草，皎皎林下人。',48,'全唐诗/poet.song.254000.json','["青青河畔草，皎皎林下人。", "草有四時色，人無千載身。", "胡爲踏氛埃，樊籠長苦辛。", "君看鴻鵠飛，九萬誰能馴。"]'),
('862fedea-3839-4333-ba5b-60ae81145978','擬古  其二','趙處澹','宋','宋诗','song-poetry','','[]','西北有高樓，樓高夜何其。',48,'全唐诗/poet.song.254000.json','["西北有高樓，樓高夜何其。", "圓影湛以光，遥望斗與箕。", "何爲天一方，長恨身不飛。", "安得駕雙翼，上下長相隨。"]'),
('b6aa18b9-7b36-4333-aabe-bcf6b8c25bca','擬古  其三','趙處澹','宋','宋诗','song-poetry','','[]','涉江采芙蓉，皎皎外名利。',48,'全唐诗/poet.song.254000.json','["涉江采芙蓉，皎皎外名利。", "采之遺所思，共此無塵意。", "所思在芝田，道遠莫之致。", "悠然對芳草，綠滿江南地。"]'),
('e1910e75-f609-4c7f-a35f-afc6bf05c7ec','擬古  其四','趙處澹','宋','宋诗','song-poetry','','[]','今日宴良會，微風動波心。',48,'全唐诗/poet.song.254000.json','["今日宴良會，微風動波心。", "逸響悲秦箏，仁聲和舜琴。", "古人爲此曲，寓意良以深。", "何當共歡樂，長嘯溪之陰。"]'),
('d39c692a-d394-4dff-a521-79d91445b59e','冬至日書懷','趙處澹','宋','宋诗','song-poetry','','[]','歲月不可挽，迅如雙轉轂。',120,'全唐诗/poet.song.254000.json','["歲月不可挽，迅如雙轉轂。", "人生能幾何，苦不自知足。", "西風吹繁霜，凍雁鳴相逐。", "老幹枯無條，積葉掩深谷。", "冉冉四序遷，忽見一陽復。", "今年纔四十，玄鬢忽已禿。", "久作林下想，雅致在幽獨。", "三逕幾株松，一窗數竿竹。", "任懶鉏荒園，更種淵明菊。", "逍遥以終年，澹然忘所欲。"]'),
('427da5ba-9d3c-41f3-8b9c-4fd1d78ad2d4','追和陶淵明詠貧士','趙處澹','宋','宋诗','song-poetry','','[]','嗟予薄羅衲，孑孑將疇依。',72,'全唐诗/poet.song.254000.json','["嗟予薄羅衲，孑孑將疇依。", "晨炊井已凍，夜鑿鄰無輝。", "蒼苔鳥跡絕，卧看孤雲飛。", "老力出市米，溪寒莫忘歸。", "纖纖山雨微，何以充我饑。", "習習風吹衣，何以慰我悲。"]'),
('ffbfe9b4-3b11-4c15-a308-a5ec30b0483c','寄友','趙處澹','宋','宋诗','song-poetry','','[]','誰謂相去遠，盈盈一水間。',60,'全唐诗/poet.song.254000.json','["誰謂相去遠，盈盈一水間。", "欲渡無津梁，中情何由殫。", "秋懷多感慨，撫衿起長嘆。", "巖風墮朝露，輕雲冒遙山。", "群芳盡搖落，孰與堅歲寒。"]'),
('0fd995c1-83c1-4005-af50-8aca9e49b38b','長門怨','趙處澹','宋','宋诗','song-poetry','','[]','未央宮中花滿枝，笙歌不斷春風詞。',79,'全唐诗/poet.song.254000.json','["未央宮中花滿枝，笙歌不斷春風詞。", "玉階露冷與天近，霓裳舞罷瓊瑶巵。", "如今寂寂長門春，寒風蕭蕭愁殺人。", "花開花落如洗，轉眼身爲陌上塵。", "自笑夜來清夢斷，猶覺瑶池侍君宴。"]'),
('2826b74a-4164-442c-97a0-ec57a39de304','追擬玄真子漁歌  其一','趙處澹','宋','宋诗','song-poetry','','[]','丁山烟雨晚濛濛，柳岸蒼波著短蓬。',32,'全唐诗/poet.song.254000.json','["丁山烟雨晚濛濛，柳岸蒼波著短蓬。", "飛鳥白，斷雲紅，一曲清歌淡月中。"]'),
('2f5c8e43-d7e6-4cf9-995f-145b586489de','追擬玄真子漁歌  其二','趙處澹','宋','宋诗','song-poetry','','[]','雨晴山色靜堆藍，橋外人家分兩三。',32,'全唐诗/poet.song.254000.json','["雨晴山色靜堆藍，橋外人家分兩三。", "緣岸北，遠溪南，片片閑雲趁落帆。"]'),
('c0deefd6-31b4-4c72-90d1-fdbacc2c0265','九日會飲翠麓','趙處澹','宋','宋诗','song-poetry','','[]','山亭對佳客，秋老暮烟橫。',48,'全唐诗/poet.song.254000.json','["山亭對佳客，秋老暮烟橫。", "鳥下江如畫，潮回浪有聲。", "竹光添麓潤，詩思入門清。", "偶約非因酒，相逢話此生。"]'),
('eb24f0d3-9780-4269-9ed6-e96a2b074b57','村居','趙處澹','宋','宋诗','song-poetry','','[]','乍晴山染碧，過雨落疏花。',48,'全唐诗/poet.song.254000.json','["乍晴山染碧，過雨落疏花。", "水闊暮天逈，村居春晝嘉。", "倚欄時展畫，留客旋烹茶。", "賸得閑中趣，吟詩到日斜。"]'),
('8b1dc0cc-0881-455c-8c00-10196d57abd4','丁山眺望','趙處澹','宋','宋诗','song-poetry','','[]','絕頂蒼崖險，藤蘿手自攀。',48,'全唐诗/poet.song.254000.json','["絕頂蒼崖險，藤蘿手自攀。", "雲烟萬里逈，宇宙一身閑。", "秋氣悲才子，夕陽明遠山。", "看看九日至，黄菊翠巖間。"]'),
('ac63f989-e818-454c-8b23-d2724769f89e','山行和韻','趙處澹','宋','宋诗','song-poetry','','[]','歷窮山底路，渾不見人家。',48,'全唐诗/poet.song.254000.json','["歷窮山底路，渾不見人家。", "傍石尋丹鼎，隨雲到玉華。", "蝶幽停蕙蕊，鹿飽卧苔花。", "中有胡麻甑，香泉浸碧沙。"]'),
('d0b857b1-09a4-4bbe-bf04-195f595b030a','八月十四夜','趙處澹','宋','宋诗','song-poetry','','[]','洲渚雲飛盡，江流碧映天。',48,'全唐诗/poet.song.254000.json','["洲渚雲飛盡，江流碧映天。", "明朝秋欲半，今夜月先圓。", "玉宇濃垂露，銀河冷墜烟。", "焦桐彈一曲，孤鶴舞風前。"]'),
('88d41fa3-43d6-4eb3-9078-7c7813c70cd9','雨','趙處澹','宋','宋诗','song-poetry','','[]','溪雲依翠竹，亂石注流泉。',48,'全唐诗/poet.song.254000.json','["溪雲依翠竹，亂石注流泉。", "數日饒春雨，餘寒勝臘天。", "書從琴案讀，茶共藥爐煎。", "故舊經過少，題詩一二篇。"]'),
('224d29c0-5f1e-489b-a89e-bae0b514e1d7','偶成','趙處澹','宋','宋诗','song-poetry','','[]','風約波痕遠，雲含野色低。',48,'全唐诗/poet.song.254000.json','["風約波痕遠，雲含野色低。", "村舂向晚急，山鳥愛晴啼。", "牧笛過蘋渚，溪船泊柳堤。", "旅魂招未得，窗草更萋萋。"]'),
('f0d21b15-5a16-4133-9e40-7ee48ab4f621','春日卧病','趙處澹','宋','宋诗','song-poetry','','[]','江雨日霏霏，春寒易入衣。',48,'全唐诗/poet.song.254000.json','["江雨日霏霏，春寒易入衣。", "貧居兼卧病，愁緒對斜暉。", "有句平生拙，無營世慮稀。", "梅花欺老眼，故傍短巖飛。"]'),
('2ce1645a-0231-4722-a64d-02e568b5a07d','濯纓亭','趙處澹','宋','宋诗','song-poetry','','[]','兩派清溪合，迴波到此間。',48,'全唐诗/poet.song.254000.json','["兩派清溪合，迴波到此間。", "危峰銜古石，幽洞隔塵寰。", "雲影高低樹，嵐光遠近山。", "先賢遺迹在，盍挽舊風還。"]'),
('79f1e5ab-e42d-409a-8e86-bd246cf3d5fc','月夜','趙處澹','宋','宋诗','song-poetry','','[]','漁笛吹清夜，蘆花深處聞。',48,'全唐诗/poet.song.254000.json','["漁笛吹清夜，蘆花深處聞。", "岸窮天拍水，山靜月籠雲。", "蛩哽聲聲切，螢明個個分。", "任渠塵外事，城市日紛紜。"]'),
('2e2b2e43-f0d6-4b9e-bd42-81a6cf711213','和韻','趙處澹','宋','宋诗','song-poetry','','[]','愛看山色徧，小立渡頭風。',48,'全唐诗/poet.song.254000.json','["愛看山色徧，小立渡頭風。", "飛鷺起沙渚，何人移短蓬。", "村烟秋入夜，江月冷摇空。", "回首清香滿，方知是桂叢。"]'),
('e0503679-ebe7-409a-baec-89b42c0e7a41','偶成用溪陰韻','趙處澹','宋','宋诗','song-poetry','','[]','虛室蕭蕭百慮忘，近來趣味一何長。',64,'全唐诗/poet.song.254000.json','["虛室蕭蕭百慮忘，近來趣味一何長。", "清談自笑如東晉，好句誰能學盛唐。", "舊日故園春寂寞，三年上國夢凄凉。", "功名原在青編裏，况有青氈在玉堂。"]'),
('2b51127b-6a56-4364-8038-24ca66cdb96d','厭雨','趙處澹','宋','宋诗','song-poetry','','[]','擬欲占晴待暮鴉，不禁愁思滿蒹葭。',64,'全唐诗/poet.song.254000.json','["擬欲占晴待暮鴉，不禁愁思滿蒹葭。", "片雲飛渡風和雨，斜日低穿水浸沙。", "薏苡石邊收釣笠，芙蓉籬外響蘆笳。", "最憐冉冉秋將半，未得先乘問月槎。"]'),
('9e653043-decf-4996-b086-60519ed3c91c','題周恭叔謝池讀書處','趙處澹','宋','宋诗','song-poetry','','[]','粉蝶黄蜂二月天，初晴已覺十分妍。',64,'全唐诗/poet.song.254000.json','["粉蝶黄蜂二月天，初晴已覺十分妍。", "市橋船繫垂垂柳，花寺鐘敲淡淡烟。", "幽趣靜看青鳥啄，閑情獨羨白鷗眠。", "謝家風月今何許，總入池塘夢裏篇。"]'),
('db6841ca-3e82-4697-bb19-de634d4d3767','清明雨中','趙處澹','宋','宋诗','song-poetry','','[]','竹遶清渠長嫩蒲，數聲村角晚吹梧。',32,'全唐诗/poet.song.254000.json','["竹遶清渠長嫩蒲，數聲村角晚吹梧。", "山家最怕清明雨，打落殘花一片無。"]'),
('0f49047f-847d-49cb-8e95-426768081d41','借榻','趙處澹','宋','宋诗','song-poetry','','[]','簾捲薰風透骨香，月移花影上迴廊。',32,'全唐诗/poet.song.254000.json','["簾捲薰風透骨香，月移花影上迴廊。", "客遊不作安居計，漫借高齋一榻凉。"]'),
('be75beee-5302-4515-a5a1-8b41a2c088d0','南塘','徐獻可','宋','宋诗','song-poetry','','[]','南塘新雨過，風暖橘洲香。',48,'全唐诗/poet.song.254000.json','["南塘新雨過，風暖橘洲香。", "水長侵官路，橋低礙野航。", "竹棚人賣酒，花笠婦移秧。", "近日頻來往，春歸有底忙。"]'),
('c280d28a-062f-41c9-8487-7ef9e93ec7de','書齋','徐獻可','宋','宋诗','song-poetry','','[]','十日書齋九日扃，春晴何處不閑行。',32,'全唐诗/poet.song.254000.json','["十日書齋九日扃，春晴何處不閑行。", "瓶花落盡無人管，留得殘枝葉自生。"]'),
('b2d063cf-7dab-479e-830e-30be84813424','長門曲','林魯','宋','宋诗','song-poetry','','[]','因宿秋山懶畫眉，入宮歲早寵恩遲。',32,'全唐诗/poet.song.254000.json','["因宿秋山懶畫眉，入宮歲早寵恩遲。", "詩成莫寫溝中葉，流到人間是幾時。"]'),
('873c64b5-7e35-445d-9d29-f6490db5c3a4','夜歸','韓兼山','宋','宋诗','song-poetry','','[]','西風淅淅吹荷衣，家在蘆花深夜歸。',32,'全唐诗/poet.song.254000.json','["西風淅淅吹荷衣，家在蘆花深夜歸。", "明月滿江人不見，白鷗雙立釣魚磯。"]'),
('9f71a81a-1b83-4020-9495-f50e148b1489','漁歌','姚所韶','宋','宋诗','song-poetry','','[]','自得元無趣，悠然與世忘。',48,'全唐诗/poet.song.254000.json','["自得元無趣，悠然與世忘。", "一聲來欸乃，孤棹在滄浪。", "雲斷暮空碧，江清秋思長。", "欲將湘笛和，無調入宮商。"]'),
('cb92c8c6-1fa4-411b-9aff-072fb29433dd','弔瓊花','丘靜山','宋','宋诗','song-poetry','','[]','仙種花移上苑難，紫瓊誰復對花彈。',32,'全唐诗/poet.song.254000.json','["仙種花移上苑難，紫瓊誰復對花彈。", "玉魂不返東風老，二十四橋明月寒。"]'),
('491cc4e1-6ef3-4dec-9cfe-a76df548c33f','客鄞江','丘靜山','宋','宋诗','song-poetry','','[]','山寒無美色，風物更凄凉。',48,'全唐诗/poet.song.254000.json','["山寒無美色，風物更凄凉。", "天地忽歲窮，弟兄皆異鄉。", "酒醒衣絮薄，月死夜更長。", "聞有家書□，敲門喚隔房。"]'),
('874ec073-dd76-4865-aec1-ceeab8d661f6','諸葛廬','鄭吾民','宋','宋诗','song-poetry','','[]','瑯琊一室雲，獨許老龍卧。',48,'全唐诗/poet.song.254000.json','["瑯琊一室雲，獨許老龍卧。", "英氣宇宙春，君臣重三顧。", "歲久化爲墟，白日聚狐兔。", "惟有忠臣心，風雨不可破。"]'),
('f7cf3573-f212-4f7b-bec9-e7e1516106b2','林下讀書','高得心','宋','宋诗','song-poetry','','[]','芸葉滿牀塵夢稀，空林對雨淡相依。',64,'全唐诗/poet.song.254000.json','["芸葉滿牀塵夢稀，空林對雨淡相依。", "閒身不與時榮謝，抱膝惟評古是非。", "蕙帳風寒人未老，松門雲靜鶴初歸。", "青山紫閣原同道，肯羨宮袍耀布衣。"]'),
('92b94f15-c138-448c-88b5-b58bbbe008e9','題景星壁','無名氏','宋','宋诗','song-poetry','','[]','陌上春風破酒顔，馬頭珠絡響珊珊。',32,'全唐诗/poet.song.254000.json','["陌上春風破酒顔，馬頭珠絡響珊珊。", "歸來院落已深夜，滿地月明花影寒。"]'),
('5b84ff81-0249-47d4-b98e-996369b62165','與客登山','徐覲','宋','宋诗','song-poetry','','[]','與客登山去，山陰路未乾。',48,'全唐诗/poet.song.254000.json','["與客登山去，山陰路未乾。", "就暄分石坐，隨處带書看。", "宿雨添溪闊，春風入袖寒。", "却因樵客引，尋得一叢蘭。"]'),
('107c64d6-dfc6-4674-928e-f4d4082bb83f','秣陵秋望','徐覲','宋','宋诗','song-poetry','','[]','諸史六朝事，同爲望遠空。',48,'全唐诗/poet.song.254000.json','["諸史六朝事，同爲望遠空。", "幾年無王氣，今日但西風。", "客舍秦淮上，行宮夕照中。", "數株霜後葉，猶傍壞陵紅。"]'),
('348b7045-cb95-4c78-9150-6ff14e33db4f','送友人','徐覲','宋','宋诗','song-poetry','','[]','高帆且莫張，月色滿離觴。',48,'全唐诗/poet.song.254000.json','["高帆且莫張，月色滿離觴。", "此夕一何短，去程如許長。", "落梅吹怨笛，微雪洒行裝。", "去去深山裏，因高莫望鄉。"]'),
('aa135553-cbee-4be9-bd95-3fccfcbc9dec','唐明皇遊月宮','葛秋崖','宋','宋诗','song-poetry','','[]','秦漢求仙事已非，等閒却遇月中妃。',32,'全唐诗/poet.song.254000.json','["秦漢求仙事已非，等閒却遇月中妃。", "如何不覓長生藥，只記霓裳一曲歸。"]'),
('759aa703-3f7c-4543-881f-5a3ab4054e57','故公子家','葛秋崖','宋','宋诗','song-poetry','','[]','繡戶朱欄柳樹春，外間不識內間貧。',32,'全唐诗/poet.song.254000.json','["繡戶朱欄柳樹春，外間不識內間貧。", "白頭園子無支給，自種盆花賣與人。"]'),
('71cf8a02-4e17-456e-9ff9-57abb2b4af1e','絕句','葛秋崖','宋','宋诗','song-poetry','','[]','二十四友金谷宴，千三百里錦帆遊。',32,'全唐诗/poet.song.254000.json','["二十四友金谷宴，千三百里錦帆遊。", "人間無此春風樂，樂極人間無此愁。"]'),
('04f51f6d-4965-44b6-a39c-776765dbf3d3','石門洞','王開平','宋','宋诗','song-poetry','','[]','層崖立水湄，絕壁萬絲垂。',48,'全唐诗/poet.song.254000.json','["層崖立水湄，絕壁萬絲垂。", "長是烟雲護，不分晴雨時。", "嵐多琳宇濕，苔滑石橋危。", "得句停舟寫，春衫潤不知。"]'),
('1bf91bf7-bd92-4a79-b8bd-995a73d85321','西里翁宅','周翼之','宋','宋诗','song-poetry','','[]','詩人風致別，卜築寓烟霞。',48,'全唐诗/poet.song.254000.json','["詩人風致別，卜築寓烟霞。", "一圃分三逕，無時不有花。", "苔痕留鶴迹，松色在檐牙。", "細酌北窗下，逶迤到日斜。"]'),
('c698daf4-901d-440a-8268-756caddf3e75','春雨','周翼之','宋','宋诗','song-poetry','','[]','青陽播物時，雲氣暗天涯。',48,'全唐诗/poet.song.254000.json','["青陽播物時，雲氣暗天涯。", "點滴聽無厭，豐登喜有期。", "池幽生活水，花落長空枝。", "載酒行春屐，何憂入興遲。"]'),
('116cef26-0e0d-439a-ac1f-e18d08a44b68','京口江亭','周翼之','宋','宋诗','song-poetry','','[]','不忍憑闌久，邊愁隨望生。',48,'全唐诗/poet.song.254000.json','["不忍憑闌久，邊愁隨望生。", "如何萬馬壯，不比一江橫。", "落日明金嶼，高風撼鐵城。", "寒濤觸沙渚，天意苦難平。"]'),
('fbdc88f6-de32-4410-8f94-825d5832bf48','道傍祠','周翼之','宋','宋诗','song-poetry','','[]','荒祠古道邊，喬木翠森然。',48,'全唐诗/poet.song.254000.json','["荒祠古道邊，喬木翠森然。", "疊石爲香案，攀藤掛紙錢。", "一時靈有迹，千載祀猶傳。", "草草陳牛酒，深期大有年。"]'),
('d78cbed3-fb06-4e0d-826f-7060bc2b0fbc','初夏','周翼之','宋','宋诗','song-poetry','','[]','入夏庭中雀可羅，閒僧閒客間相過。',32,'全唐诗/poet.song.254000.json','["入夏庭中雀可羅，閒僧閒客間相過。", "鶑聲不得蛙聲接，楊柳池塘寂寞多。"]'),
('96d61242-42cd-45af-a008-1588b08a877b','桃源行','王景月','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','秦皇有地包沙漠，秦民無地堪托足。',163,'全唐诗/poet.song.254000.json','["秦皇有地包沙漠，秦民無地堪托足。", "民心咫尺不戴秦，秦令安能到空谷。", "商山紫芝青門瓜，武陵洞底栽桃花。", "草木不共人逃去，虞妃山赭良堪嗟。", "秦皇一世二世歇，秦民萬世桃花月。", "漁子相逢五百年，已聞幾度乾坤裂。", "靖節先生曾作記，祇云賢者茲避世。", "時人浪作神仙傳，空自渺茫涉奇異。", "君不見年來禮樂卯金刀，先生歸對廬山高。", "所種柴桑五株柳，勝是武陵千樹桃。"]'),
('de533a20-02c2-40a5-b464-cce8c0032ed8','采石渡','王景月','宋','宋诗','song-poetry','','[]','興亡懷此渡，貰酒易爲醺。',48,'全唐诗/poet.song.254000.json','["興亡懷此渡，貰酒易爲醺。", "數樹松青處，千年李白墳。", "曉山看夜雪，淮甸沒江雲。", "牛渚磯邊過，驚濤不可聞。"]'),
('7fef11a5-2a4e-44fc-b624-0a5c47e77ff2','遊古寺','蔡槃','宋','宋诗','song-poetry','','[]','山烟寒日暝，鴟殿與雲齊。',48,'全唐诗/poet.song.254000.json','["山烟寒日暝，鴟殿與雲齊。", "松鼠下階走，竹雞當戶啼。", "碑荒文字古，僧老語音低。", "欲往應無計，斜陽照杖藜。"]'),
('64431a1e-f048-4147-8938-c50384aebb86','竹','蔡槃','宋','宋诗','song-poetry','','[]','每愛幽窗下，烟藂與露枝。',48,'全唐诗/poet.song.254000.json','["每愛幽窗下，烟藂與露枝。", "纔聞風起處，便是雨來時。", "節直將誰比，心虛只自知。", "青青長在眼，休說化龍遲。"]'),
('51554c66-0a05-4e62-8c61-099e28d6748d','寄北磵','蔡槃','宋','宋诗','song-poetry','','[]','擬定書中字，山中欲問誰。',48,'全唐诗/poet.song.254000.json','["擬定書中字，山中欲問誰。", "一從分手後，盡是斷腸時。", "燒葉驅殘凍，挑蔬備夕饑。", "相思不但此，明月夢魂隨。"]'),
('5410563a-1498-4378-ab2c-a48e83f89a44','留別','蔡槃','宋','宋诗','song-poetry','','[]','欲去休云易，相思恐弗禁。',48,'全唐诗/poet.song.254000.json','["欲去休云易，相思恐弗禁。", "一牀秋雨夢，千里暮雲心。", "每自悲行役，知誰識老吟。", "西風聞過雁，記取問佳音。"]'),
('8535d963-3dfb-47fa-a768-edd37d41b002','山城即事','蔡槃','宋','宋诗','song-poetry','','[]','獨上山樓上，樓高望盡天。',48,'全唐诗/poet.song.254000.json','["獨上山樓上，樓高望盡天。", "更無雲一點，只有月孤圓。", "樹老飄黄葉，湖空起白烟。", "故園音信斷，愁絕不成眠。"]'),
('ed885843-8c63-4cf6-9760-555c8dbb5682','雪中懷祝聲之','蔡槃','宋','宋诗','song-poetry','','[]','逢人常自說，家遠欲歸難。',48,'全唐诗/poet.song.254000.json','["逢人常自說，家遠欲歸難。", "身暫依蓮社，心猶在杏壇。", "攤書燈下讀，磨劍月中看。", "近日無消息，相思雨雪寒。"]'),
('f473da56-326d-4d7a-b059-a5df9d1706d6','寄何尉','蔡槃','宋','宋诗','song-poetry','','[]','向晚出林麓，思君隔瀼灣。',48,'全唐诗/poet.song.254000.json','["向晚出林麓，思君隔瀼灣。", "因看雲過嶺，不覺日沉山。", "犬吠疏籬下，牛歸古道間。", "一聲何處笛，明月上松關。"]'),
('71929033-092f-4b35-8119-f19c56f91f9f','客中','蔡槃','宋','宋诗','song-poetry','','[]','舉酒吟詩易，居貧作客難。',48,'全唐诗/poet.song.254000.json','["舉酒吟詩易，居貧作客難。", "一番思世事，半日倚闌干。", "霜重竹籬薄，風高石徑寒。", "無言搔短髪，望眼到長安。"]'),
('ffde7ab5-9426-41a7-af9b-7e23f7bf5ae7','病中','蔡槃','宋','宋诗','song-poetry','','[]','遶舍東風急，柴門靜掩時。',48,'全唐诗/poet.song.254000.json','["遶舍東風急，柴門靜掩時。", "交情貧裏見，藥性病中知。", "沉寂心當定，清羸步懶移。", "呼童理書案，爲管舊時書。"]'),
('6ceed0c5-bf4a-4a88-9bdd-582d230696cb','山居','蔡槃','宋','宋诗','song-poetry','','[]','急雨開新霽，薫風獻嫩涼。',48,'全唐诗/poet.song.254000.json','["急雨開新霽，薫風獻嫩涼。", "苔花停畫壁，雲葉護書床。", "枕上清風細，詩中雅興長。", "地偏人到少，幽鳥語新篁。"]'),
('e5cb6755-6cd2-4f88-a04a-07defa7d4083','遊梅庵','蔡槃','宋','宋诗','song-poetry','','[]','一點塵難着，推窗晚翠開。',48,'全唐诗/poet.song.254000.json','["一點塵難着，推窗晚翠開。", "早知延話久，悔不带詩來。", "醫俗可無竹，耐交惟有梅。", "平生愛閑步，踏碎幾莓苔。"]'),
('65bf1639-06ad-4f23-bf3d-3e46ec2bd2ad','宿碧瑶山房','蔡槃','宋','宋诗','song-poetry','','[]','市聲不到處，作屋僅三間。',48,'全唐诗/poet.song.254000.json','["市聲不到處，作屋僅三間。", "洗硯添新水，開窗放遠山。", "濕雲侵樹黑，疏雨蝕苔斑。", "近有閒生活，吟編手自刪。"]'),
('8fc15783-3b79-43a9-9dd3-d6c0137da6a5','人間','蔡槃','宋','宋诗','song-poetry','','[]','棄盡人間事，西風掩竹門。',48,'全唐诗/poet.song.254000.json','["棄盡人間事，西風掩竹門。", "無人爭碧嶂，有鶴伴黄昏。", "掃石移雲影，澆花潤月痕。", "何須嘆牢落，知我有乾坤。"]'),
('35ddf10b-3f42-44d0-ad43-aeff4e15744e','旅中','蔡槃','宋','宋诗','song-poetry','','[]','梧葉響荒塘，秋宵不耐長。',48,'全唐诗/poet.song.254000.json','["梧葉響荒塘，秋宵不耐長。", "猿啼千嶂外，人在一燈旁。", "雁影溪橋月，鐘聲野寺霜。", "明朝又何處，烟水正茫茫。"]'),
('00c5ca81-47ed-4bea-9395-a38025b36715','越州早行','蔡槃','宋','宋诗','song-poetry','','[]','青鞋三十里，草露惹衣斑。',48,'全唐诗/poet.song.254000.json','["青鞋三十里，草露惹衣斑。", "潮落曹娥渡，雲荒夏禹山。", "秋聲黄葉裏，天影白鷗間。", "欲問錢塘□，漁家未啟關。"]'),
('704fe92f-5bfa-4c0d-b675-375baa6e157a','瓜州','蔡槃','宋','宋诗','song-poetry','','[]','烟際繫孤舟，蘆花兩岸秋。',48,'全唐诗/poet.song.254000.json','["烟際繫孤舟，蘆花兩岸秋。", "江空雙雁落，天逈一星流。", "急鼓西津渡，殘雲北固樓。", "商人茅店下，沽酒話揚州。"]'),
('01fee7b1-d4c5-4c2b-a707-c74181d323b7','金陵','蔡槃','宋','宋诗','song-poetry','','[]','六代帝王州，寒烟滿石頭。',48,'全唐诗/poet.song.254000.json','["六代帝王州，寒烟滿石頭。", "星河天北轉，江漢水東流。", "步絕金蓮雨，歌殘玉樹秋。", "白頭有漁父，猶說景陽樓。"]'),
('223980d9-6d1f-412c-a4a5-062eb6f4a856','春思','蔡槃','宋','宋诗','song-poetry','','[]','自覺無春思，春長在眼前。',48,'全唐诗/poet.song.254000.json','["自覺無春思，春長在眼前。", "天晴梅墮雪，地暖草生烟。", "獨步迷山影，空腸飽澗泉。", "鄉心徒耿耿，爲客又經年。"]'),
('a2a35009-3819-4a4a-8b02-3a3c1e2402ed','贈江湖隠者','蔡槃','宋','宋诗','song-poetry','','[]','湖上人家住最幽，簷牙倒影落滄洲。',64,'全唐诗/poet.song.254000.json','["湖上人家住最幽，簷牙倒影落滄洲。", "詩成梅塢三更月，酒醒蓬窗午夜秋。", "移石爲添燒藥竈，賣金因起讀書樓。", "經年不入城闉去，長倚闌干看白鷗。"]'),
('d45bbd39-3903-4552-a85d-0339b6b05bde','冬夕寄友','蔡槃','宋','宋诗','song-poetry','','[]','壁燈花落夜將殘，天遠那知客思單。',64,'全唐诗/poet.song.254000.json','["壁燈花落夜將殘，天遠那知客思單。", "鶴帳不成雲外夢，燕樓空鎖雨中寒。", "千年風雅教誰主，一曲淒凉只自彈。", "又恐孤山梅漸老，明朝相約過長安。"]'),
('8d220ce5-cd1e-46bd-ae73-373c368b68c3','自敘','蔡槃','宋','宋诗','song-poetry','','[]','江湖閒步幾經年，窮似襄陽孟浩然。',64,'全唐诗/poet.song.254000.json','["江湖閒步幾經年，窮似襄陽孟浩然。", "折簡爲求僧舍茗，典衣因欠酒家錢。", "真情盡向詩中見，歸夢常於枕上圓。", "世路風波深可畏，結茅何日遂歸田。"]'),
('983094f2-6753-482f-94b4-8af0e9f298d5','次幽居','蔡槃','宋','宋诗','song-poetry','','[]','却粒燒丹未有方，且逃人事住山房。',64,'全唐诗/poet.song.254000.json','["却粒燒丹未有方，且逃人事住山房。", "冷看桐葉含秋思，閒掃苔花背夕陽。", "牆壁徧題無酒句，衣裳多带搗茶香。", "雲深自是稀來往，婆餠一聲清晝長。"]'),
('276eb2b6-41e0-40ba-b3b2-ed6c85fdce9c','過橫嶺書信臣宅壁','蔡槃','宋','宋诗','song-poetry','','[]','馬嘶殘月醉醒中，行盡天涯西復東。',64,'全唐诗/poet.song.254000.json','["馬嘶殘月醉醒中，行盡天涯西復東。", "兩鬢欲霜難諱老，一心憂國不妨窮。", "只今世路渾如水，從舊交情獨有公。", "彭澤門前昔時柳，也應相傍得春風。"]'),
('95948e6c-1094-4e31-89d8-3b5deafc57c5','寄雪蓬姚監丞','蔡槃','宋','宋诗','song-poetry','','[]','憶昔青燈夜對床，斷猿聲裏早梅香。',64,'全唐诗/poet.song.254000.json','["憶昔青燈夜對床，斷猿聲裏早梅香。", "一從去棹衝寒雪，幾度凭闌到夕陽。", "秋思漸於蟬外覺，別愁偏向雁邊長。", "梧桐解得離人意，不遣西風吹葉黄。"]'),
('da03b3fb-4061-49f3-8bd5-23a736bcbeea','約友同游','蔡槃','宋','宋诗','song-poetry','','[]','買得扁舟繫海濱，梅花嶺上浪游人。',64,'全唐诗/poet.song.254000.json','["買得扁舟繫海濱，梅花嶺上浪游人。", "江山若欲留連客，詩酒何妨報答春。", "柳带梳風黄尚淺，草茵鋪雨綠將勻。", "約君携手同行樂，趁取東郊景物新。"]'),
('e1d889b2-a25c-4b89-97a0-a24432b10da7','次倪梅村見寄韻','蔡槃','宋','宋诗','song-poetry','','[]','江湖不恨知心少，只怕相逢雪上頭。',64,'全唐诗/poet.song.254000.json','["江湖不恨知心少，只怕相逢雪上頭。", "萬事悠悠雙弊屣，百年渺渺一虛舟。", "共斟荷露吟終日，坐挹松風喜近秋。", "更好停杯溪上月，不妨爲我夜深留。"]'),
('e1a876f8-a9f9-4bf7-9cfe-3d89c0f53b7b','鄭介道見訪','蔡槃','宋','宋诗','song-poetry','','[]','數株楊柳種多年，今日方維勝客船。',64,'全唐诗/poet.song.254000.json','["數株楊柳種多年，今日方維勝客船。", "掃石共看山色坐，枕書同聽雨聲眠。", "溪羹旋煮蒓絲滑，野飯新炊白玉圓。", "不管歸心忙似箭，强留吟過菊花天。"]'),
('1d5f3e2d-7522-4fa7-a22f-2461dc1bb5b9','謁范文正公祠','蔡槃','宋','宋诗','song-poetry','','[]','半龕遺像飾貂蟬，往事猶思慶曆前。',64,'全唐诗/poet.song.254000.json','["半龕遺像飾貂蟬，往事猶思慶曆前。", "未說兩朝親捧日，且言一柱獨擎天。", "山林付與書生管，香火當同信史傳。", "獨恨軍中無此老，如今西賊又侵邊。"]'),
('072c3d8b-fdfe-4957-826a-236277003549','錢塘懷古','蔡槃','宋','宋诗','song-poetry','','[]','鬰鬰東南旺氣浮，吳爭越戰幾春秋。',64,'全唐诗/poet.song.254000.json','["鬰鬰東南旺氣浮，吳爭越戰幾春秋。", "一陽柳色渾無恙，五月荷花半是愁。", "隆替且容吾輩老，英雄都付此江流。", "中原苦被淮山隔，莫向西風更倚樓。"]'),
('db852999-c41f-43e0-9fd0-2d2772bc0ca9','九日僧舍偶成','蔡槃','宋','宋诗','song-poetry','','[]','落帽年年學孟嘉，今年偶客梵王家。',32,'全唐诗/poet.song.254000.json','["落帽年年學孟嘉，今年偶客梵王家。", "石床齋散門初掩，細雨聲中落菊花。"]'),
('204972e1-a4e6-4df9-bfb0-3c9bcd23b2ac','宮主祠','蔡槃','宋','宋诗','song-poetry','','[]','玉鏡臺前懶畫眉，傷心最是月明時。',32,'全唐诗/poet.song.254000.json','["玉鏡臺前懶畫眉，傷心最是月明時。", "君恩漸絕門深掩，落盡閒花竟不知。"]'),
('502b741e-498c-41f3-a8dc-cfed4b638f59','挽內子','郭燻','宋','宋诗','song-poetry','','[]','山嵬嵬兮日西，望吾侶兮不歸。',52,'全唐诗/poet.song.254000.json','["山嵬嵬兮日西，望吾侶兮不歸。", "惆悵兮階前，物換兮人非。", "春去兮花殘，春歸兮芳菲。", "老不可以再壯，君胡爲而先馳。"]'),
('bcb79c53-4ec9-4b85-ae7d-38dcae4f4b1d','述懷  其一','陳梅莊','宋','宋诗','song-poetry','','[]','一寸柔腸萬疊縈，那堪更值此春情。',32,'全唐诗/poet.song.254000.json','["一寸柔腸萬疊縈，那堪更值此春情。", "黄鸝知我無情緒，飛過花梢禁不聲。"]'),
('5f0cceec-cabb-426d-9f6d-50c3dc81fcae','述懷  其二','陳梅莊','宋','宋诗','song-poetry','','[]','一片愁心怯杜鵑，懶妝從任鬢雲偏。',32,'全唐诗/poet.song.254000.json','["一片愁心怯杜鵑，懶妝從任鬢雲偏。", "怕郎却起陽關意，常掩琵琶第四絃。"]'),
('d5904807-6b8d-4f4e-bbb3-c3eb948ddcb1','述懷  其三','陳梅莊','宋','宋诗','song-poetry','','[]','山城忽忽欲昏黄，又了浮生半日忙。',32,'全唐诗/poet.song.254000.json','["山城忽忽欲昏黄，又了浮生半日忙。", "侍妾不須燒絳蠟，讓由明月入迴廊。"]'),
