('2ca98cd9-f0a2-45b8-845f-c7fb1c4432ab','永別','楊氏','宋','宋诗','song-poetry','','[]','春盡花隨盡，其如自是花。',24,'全唐诗/poet.song.254000.json','["春盡花隨盡，其如自是花。", "從來說花意，不過此容華。"]'),
('b0948ed3-3f87-49fc-b0f7-425cace66ae3','登高凉山謁墓','陳廷光','宋','宋诗','song-poetry','','[]','雲氣擁松楸，佳城生意幽。',48,'全唐诗/poet.song.254000.json','["雲氣擁松楸，佳城生意幽。", "掃殘黄葉路，奠徧綠新蒭。", "想像音容在，瞻衣涕泗流。", "東遷禱靈墓，端爲護行舟。"]'),
('8e475988-32ea-4110-b1ff-d4f27a08130d','小山見梅','陳廷光','宋','宋诗','song-poetry','','[]','小雪梅香已破緘，羅浮春信許先探。',64,'全唐诗/poet.song.254000.json','["小雪梅香已破緘，羅浮春信許先探。", "松林酒肆知誰醉，石壁題詩祇自慚。", "未放翠禽呼夢覺，待教黄野縱鸞驂。", "行當看我飛雲頂，並取春魁壓斗南。"]'),
('28d83145-a79c-4093-8afc-de65557ab74b','留別貴州父老','袁宏德','宋','宋诗','song-poetry','','[]','翻笑行藏不自由，郵亭杯酒又淹留。',64,'全唐诗/poet.song.254000.json','["翻笑行藏不自由，郵亭杯酒又淹留。", "罷官却喜身還健，報最空慚政未優。", "截鐙祇今難繫馬，賣刀自昔已牽牛。", "蠻烟嶺樹斜陽路，兩地離懷一樣秋。"]'),
('2e0b2169-5092-4032-baed-d58a99826f8e','狀元峰','鍾宿','宋','宋诗','song-poetry','','[]','馬蹄一日遍長安，螢火雞窗千載寒。',32,'全唐诗/poet.song.254000.json','["馬蹄一日遍長安，螢火雞窗千載寒。", "從此錦衣歸故里，文峰高並彩雲端。"]'),
('ef232b42-c0a5-420e-b551-7d922986a600','蛻龍洞','鍾宿','宋','宋诗','song-poetry','','[]','蒼巖磊落任龍蟠，綿亙千年露未乾。',32,'全唐诗/poet.song.254000.json','["蒼巖磊落任龍蟠，綿亙千年露未乾。", "一自爲霖破壁去，至今風雨逼山寒。"]'),
('80289003-4724-4d22-b2cc-d405cad3e615','登竺雲山','釋白幻','宋','宋诗','song-poetry','','[]','獨上千峰與萬峰，晴嵐淡寫海江容。',32,'全唐诗/poet.song.254000.json','["獨上千峰與萬峰，晴嵐淡寫海江容。", "偶從動問山居事，笑拍巖前一樹松。"]'),
('a4a4a801-b13f-4f5c-abd5-0acce3566766','寒雲千疊山','楊養晦','宋','宋诗','song-poetry','','[]','松竹陰森護上方，老仙蓬髪一簪霜。',32,'全唐诗/poet.song.254000.json','["松竹陰森護上方，老仙蓬髪一簪霜。", "閑來欹枕松風裏，歸夢不知山水長。"]'),
('92aac95b-19e8-434e-a3c5-55029396082d','宣妙樓','方鴻飛','宋','宋诗','song-poetry','','[]','雲觀烟樓是梵家，竹圍如洗逼寒沙。',64,'全唐诗/poet.song.254000.json','["雲觀烟樓是梵家，竹圍如洗逼寒沙。", "因風綠浪摇晴麥，遇雨紅香落澗花。", "人鎖晝房聽鳥語，僧歸晚塢放蜂衙。", "不須老遠來沽酒，只覓天酥爲點茶。"]'),
('c4645cf0-844a-4d0f-a797-c39928cd2d71','守居園池雜題 待月臺','文同','宋','宋诗','song-poetry','','[]','城端築層臺，木杪轉深路。',24,'全唐诗/poet.song.26000.json','["城端築層臺，木杪轉深路。", "常此候明月，上到天心去。"]'),
('1bd91dde-cdb9-417d-8c03-8b32c3bfc0cd','守居園池雜題 二樂榭','文同','宋','宋诗','song-poetry','','[]','㬊山孰云靜，漢水亦非動。',24,'全唐诗/poet.song.26000.json','["㬊山孰云靜，漢水亦非動。", "二見因妄生，仁智何常用。"]'),
