('06f69437-733d-4893-a36d-372516fab406','守居園池雜題 南園','文同','宋','宋诗','song-poetry','','[]','農桑乘曉日，凌亂如碧油。',24,'全唐诗/poet.song.26000.json','["農桑乘曉日，凌亂如碧油。", "紫椹熟未熟，但聞黄栗留。"]'),
('bb2e9b6d-8dd6-4c08-a328-9f6cfd5dda06','守居園池雜題 北園','文同','宋','宋诗','song-poetry','','[]','春風有多少，盡入使君家。',24,'全唐诗/poet.song.26000.json','["春風有多少，盡入使君家。", "當與郡人樂，滿園桃李花。"]'),
('900873e9-a7a4-4e5d-a1d9-a3fb08a7048b','守居園池雜題 寒蘆港','文同','宋','宋诗','song-poetry','','[]','落月照冰湖，曉氣何太爽。',24,'全唐诗/poet.song.26000.json','["落月照冰湖，曉氣何太爽。", "兩岸雪烟昏，鳬鷗出深港。"]'),
('9bc386ba-8df7-4245-a77d-ea4174abab4b','守居園池雜題 野人廬','文同','宋','宋诗','song-poetry','','[]','蕭條野人廬，籬巷雜蓬葦。',24,'全唐诗/poet.song.26000.json','["蕭條野人廬，籬巷雜蓬葦。", "每一過衡門，歸心爲之起。"]'),
('f415f42b-82fe-4a1f-80a6-d72e6216608b','守居園池雜題 披錦亭','文同','宋','宋诗','song-poetry','','[]','繁紅層若雲，密綠疊如浪。',24,'全唐诗/poet.song.26000.json','["繁紅層若雲，密綠疊如浪。", "青帝下尋春，滿園開步障。"]'),
('04e26254-7396-42b8-87bc-87b04a0e5bba','守居園池雜題 此君庵','文同','宋','宋诗','song-poetry','','[]','叢筠裹圜檐，凈影碧如水。',24,'全唐诗/poet.song.26000.json','["叢筠裹圜檐，凈影碧如水。", "誰識愛君心，過橋先到此。"]'),
('7045db34-a8b4-495a-81d4-42c72a7af9f4','湖上衆禽盡以俗呼爲題 淘河','文同','宋','宋诗','song-poetry','','[]','群魚見新晴，萬鬣戲清泚。',24,'全唐诗/poet.song.26000.json','["群魚見新晴，萬鬣戲清泚。", "忽爾下淘河，驚回入水底。"]'),
('39af4b3d-b32c-4d6e-b46b-86cf78784a97','湖上衆禽盡以俗呼爲題 連點七','文同','宋','宋诗','song-poetry','','[]','翩翩彼珍禽，金羽耀寒日。',24,'全唐诗/poet.song.26000.json','["翩翩彼珍禽，金羽耀寒日。", "飛落灘上冰，對人連點七。"]'),
('58af8fe5-3bf3-4b45-8fdf-dccc30aaaad6','湖上衆禽盡以俗呼爲題 拖白練','文同','宋','宋诗','song-poetry','','[]','盤石坐深林，不欲人求見。',24,'全唐诗/poet.song.26000.json','["盤石坐深林，不欲人求見。", "隔岸誰品弦，數聲拖白練。"]'),
('14dfbc54-1e6a-495b-8fc7-8feee4ce53b4','湖上衆禽盡以俗呼爲題 泥滑滑','文同','宋','宋诗','song-poetry','','[]','春日正晴明，滿園花盛發。',24,'全唐诗/poet.song.26000.json','["春日正晴明，滿園花盛發。", "勸爾竹木鷄，莫啼泥滑滑。"]'),
('5aab8682-e8bb-46d4-91be-98c745cc30c8','湖上衆禽盡以俗呼爲題 提葫蘆','文同','宋','宋诗','song-poetry','','[]','花開已堪摘，酒熟正好沽。',24,'全唐诗/poet.song.26000.json','["花開已堪摘，酒熟正好沽。", "山禽會人意，勸我提葫蘆。"]'),
('30fe955e-60f4-4831-a0d9-10469c92e250','詠蓮','文同','宋','宋诗','song-poetry','','[]','全紅開似鏡，半綠卷如杯。',24,'全唐诗/poet.song.26000.json','["全紅開似鏡，半綠卷如杯。", "誰爲回風力，清香滿面來。"]'),
('101bb4f6-86b6-4af4-a474-b9294bc2cab3','題友人書齋新壁','文同','宋','宋诗','song-poetry','','[]','彩槴縱橫設，雕厨次第開。',24,'全唐诗/poet.song.26000.json','["彩槴縱橫設，雕厨次第開。", "須防何法盛，直入此中來。"]'),
('71aa5b2a-9723-420a-b989-4d496c1f4d68','張凈琬','文同','宋','宋诗','song-poetry','','[]','驃騎極豪侈，後房多艷姬。',24,'全唐诗/poet.song.26000.json','["驃騎極豪侈，後房多艷姬。", "可憐張凈琬，不識半酣時。"]'),
('3b817b19-5d97-49d7-aa99-9e8491bae4b5','待雪','文同','宋','宋诗','song-poetry','','[]','向晚欲雪天氣陰，木葉亂飛雜歸禽。',32,'全唐诗/poet.song.26000.json','["向晚欲雪天氣陰，木葉亂飛雜歸禽。", "城頭徙倚待飄灑，東北萬里皆雲林。"]'),
('7a7df89f-8864-4f10-a10e-7e4f7eb64ef3','送提刑司勳','文同','宋','宋诗','song-poetry','','[]','同昔分符守興元，公始仗節來武信。',352,'全唐诗/poet.song.26000.json','["同昔分符守興元，公始仗節來武信。", "因而出入在門下，未有三日不親近。", "臺移希疏獄讞少，凜凜清風滿牆仞。", "乘閑每許陪後乘，好寺名園遍遊盡。", "惟携茶具賞幽絕，新胯珍團曾不吝。", "或因議事閱書畫，止用小肴并淺醖。", "清歡雅興自無厭，妓樂喧煩誰願進。", "開張胸懷脫羈檢，顔色何嘗形喜慍。", "使威斂霽官况樂，瞥過二年如一瞬。", "後同先滿去涪上，數月復來爲屬郡。", "再將厚蔭蒙舊物，掩蔽不才寬責問。", "同常自念性偏僻，凡取交游最精慎。", "雖然衆中事汎愛，仁者與親餘不認。", "生平所得無幾人，既已得之心自信。", "公家兄弟何磊落，一一光華如美瑾。", "顧同質狀似頑石，輒簉其間襲溫潤。", "令昆强季沒已久，公獨康莊馳駔駿。", "朝廷要人辦繁劇，昨下詔書催入覲。", "連城衆口惜公去，不問鯢鮐與髫齔。", "烟開漢沔曉光薄，雪下褒斜寒力峻。", "嗟同不得送行旆，回視腰間綰雙印。", "灙城西北有危樓，徒望高鴻寄長韵。"]'),
('0cc2abda-f637-46f9-8c96-d5087b40af54','翡翠','文同','宋','宋诗','song-poetry','','[]','清晨有珍禽，翩翩下魚梁。',228,'全唐诗/poet.song.26000.json','["清晨有珍禽，翩翩下魚梁。", "其形不盈握，毛羽鮮且光。", "天人裁碧霞，爲爾縫衣裳。", "晶熒炫我目，非世之青黄。", "愛之坐良久，常恐瞥爾翔。", "忽然投清漪，得食如針鋩。", "如是者三四，厭飫已一肮。", "既飽且自嬉，翻身度回塘。", "飛鳴逐佳匹，相和音琅琅。", "是時鳬與雁，狼藉島嶼旁。", "滿腹釀腥穢，紛紛曬晴陽。", "鶖鶬最粗惡，嘴大脚脛長。", "入水捕蛇鱓，淤泥亦銜將。", "想其見爾時，一啄亦爾傷。", "其心肯謂爾，被體凝華章。", "勸爾慎所止，好醜難同鄉。", "清溪多纖鮮，亦足充爾腸。", "江海深且闊，所獲未可量。", "爾當事澡刷，帝囿參鸞凰。"]'),
('956ed3c0-8641-43a6-9461-05a33a611566','依韵和圖南五首 平阿馬上','文同','宋','宋诗','song-poetry','','[]','江山相引轉平皋，滿馬詩情擁敝袍。',64,'全唐诗/poet.song.26000.json','["江山相引轉平皋，滿馬詩情擁敝袍。", "鳴鶴不知誰使怨，飛鳶何謂爾能高。", "岩頭亂木森如戟，澗下繁雲涌似濤。", "才到郵亭便沈思，向來佳景待吾曹。"]'),
('5b4266c9-6e7a-4358-b673-1f6ac9f6224d','依韵和圖南五首 過朝天嶺','文同','宋','宋诗','song-poetry','','[]','雙壁相參萬木深，馬前猿鳥亦難尋。',64,'全唐诗/poet.song.26000.json','["雙壁相參萬木深，馬前猿鳥亦難尋。", "雲容杳杳斷鴻意，風色蕭蕭行客心。", "山若畫屏隨峽勢，水如衣带轉巖陰。", "生平來往成何事，且倚鈎欄擁鼻吟。"]'),
('4ba11a24-576f-40fb-a05b-1443fc3ddce6','依韵和圖南五首 晚泊金牛','文同','宋','宋诗','song-poetry','','[]','一襟初覺晚霜清，短鞚垂頭任馬行。',64,'全唐诗/poet.song.26000.json','["一襟初覺晚霜清，短鞚垂頭任馬行。", "斜日斂回疏木影，急風收斷落泉聲。", "望窮好景番番別，題遍新詩闋闋精。", "終是教人伏潘令，許多才調賦西征。"]'),
('3e02ebde-3c16-4d00-8f80-20cc9f783bef','依韵和圖南五首 金牛相別呈誠之','文同','宋','宋诗','song-poetry','','[]','出門相與望橫參，露浥幧頭冷逼簪。',64,'全唐诗/poet.song.26000.json','["出門相與望橫參，露浥幧頭冷逼簪。", "驛在金堆隨澗遠，路經銅冶入烟深。", "過橋住馬應回首，上嶺聞猿想動心。", "勝事莫過文酒樂，此時銷得各沉吟。"]'),
('b39c10c0-ff18-45a6-b454-09a721857a5b','依韵和圖南五首 大桃途次見菊','文同','宋','宋诗','song-poetry','','[]','英英寒菊犯清霜，來伴山中草木黄。',64,'全唐诗/poet.song.26000.json','["英英寒菊犯清霜，來伴山中草木黄。", "不趁盛時隨衆卉，自甘深處作孤芳。", "其他爛漫非真色，惟此氤氳是正香。", "却念白衣誰送酒，滿籬高興憶吾鄉。"]'),
('2f357449-8963-47c3-975e-b1ca01470ccd','弄珠亭下柳','文同','宋','宋诗','song-poetry','','[]','江柳早春前，濛濛弄紫烟。',48,'全唐诗/poet.song.26000.json','["江柳早春前，濛濛弄紫烟。", "未容長作带，已見亂飛綿。", "遠外分晴島，深中泊暮舡。", "惟應漢水色，奈爾一年年。"]'),
('6d58a1fc-1948-4c4c-8a84-0e6c76dc62d2','弄珠亭春日閑望','文同','宋','宋诗','song-poetry','','[]','弄珠亭上客，來想弄珠人。',48,'全唐诗/poet.song.26000.json','["弄珠亭上客，來想弄珠人。", "野草迷晴岸，垂楊暗晚津。", "天涯羈旅地，村落寂寥春。", "何處皤然叟，扁舟下釣綸。"]'),
('922521f3-3609-4892-8674-f15efa56bbc3','寄子駿運使','文同','宋','宋诗','song-poetry','','[]','西鄉巴嶺下，嶮道入孱顔。',48,'全唐诗/poet.song.26000.json','["西鄉巴嶺下，嶮道入孱顔。", "使騎到荒驛，野禽啼亂山。", "問民青靄裏，訪古白雲間。", "幾日南城路，新詩滿軸還。"]'),
('a07b03cf-6ca1-4df9-b198-5ec5cb03b79a','寄景孺提刑','文同','宋','宋诗','song-poetry','','[]','江由岩嶮地，萬木與雲齊。',48,'全唐诗/poet.song.26000.json','["江由岩嶮地，萬木與雲齊。", "弭節山中宿，思歸夜半啼。", "麝香霑野草，虎迹滑春泥。", "到此須憑酒，何人手可携。"]'),
('96db3596-1952-4d19-ac7a-34185339c624','公館','文同','宋','宋诗','song-poetry','','[]','公館晝沈沈，烟雲晚作陰。',48,'全唐诗/poet.song.26000.json','["公館晝沈沈，烟雲晚作陰。", "琴軒冰沼凈，書閣火爐深。", "默坐自有得，閑行誰可尋。", "還應上高閣，看雪一千岑。"]'),
('af539c65-aef6-451e-981c-442d0b9ebd2d','衰晚','文同','宋','宋诗','song-poetry','','[]','衰晚得洋川，勞生只自憐。',48,'全唐诗/poet.song.26000.json','["衰晚得洋川，勞生只自憐。", "文移供盡日，心力付流年。", "咄咄空書字，便便聲晝眠。", "其如昏嫁在，了即賦歸田。"]'),
('ddad7050-c2e5-49a9-b41d-b353b5885db7','欲雪','文同','宋','宋诗','song-poetry','','[]','山城蔽層陰，晚照空外滅。',48,'全唐诗/poet.song.26000.json','["山城蔽層陰，晚照空外滅。", "天低雲氣暖，此意欲作雪。", "歸鴉烟慘澹，斷雁風蕭屑。", "樽酒聊自持，同誰感時節。"]'),
('56152ddc-d778-4c9b-9004-a4ee92d2a5b6','晴山','文同','宋','宋诗','song-poetry','','[]','東北橫群峰，新過夜來雨。',48,'全唐诗/poet.song.26000.json','["東北橫群峰，新過夜來雨。", "扶空立屏障，浩翠小萬古。", "豈無短齒屐，携手誰我侶。", "欲往殊未能，□□□□□。"]'),
('63d218c9-8fc5-4312-8a36-26e3bc3de421','臨漢亭','文同','宋','宋诗','song-poetry','','[]','危亭俯絕岸，漢水望天表。',48,'全唐诗/poet.song.26000.json','["危亭俯絕岸，漢水望天表。", "遥源瀉金穴，高浪灌朱鳥。", "紆餘轉荆楚，萬里合浩渺。", "誰知嶓冢下，悸然如带小。"]'),
('fb85fb79-a023-42dc-9c9b-39127836e820','雪中三章寄景孺提刑','文同','宋','宋诗','song-poetry','','[]','城頭高榭陟嶙峋，坐看江郊灑玉塵。',32,'全唐诗/poet.song.26000.json','["城頭高榭陟嶙峋，坐看江郊灑玉塵。", "恨不同來對清絕，擬將佳景待何人。"]'),
('0d3b7447-0f58-4cef-8a2a-aa0b0468b9de','雪中三章寄景孺提刑 晚雪湖上','文同','宋','宋诗','song-poetry','','[]','朔風吹雪滿橫湖，衆鳥歸栖日欲晡。',32,'全唐诗/poet.song.26000.json','["朔風吹雪滿橫湖，衆鳥歸栖日欲晡。", "獨坐水軒人不到，滿林如挂暝禽圖。"]'),
('12b4279a-00c4-42ef-acf1-2dc87b4f1562','雪中三章寄景孺提刑 齋宮','文同','宋','宋诗','song-poetry','','[]','玉龍噴霧碧霏霏，鈿枕珠衾照百枝。',32,'全唐诗/poet.song.26000.json','["玉龍噴霧碧霏霏，鈿枕珠衾照百枝。", "自與侍書人一處，此中全不管岷之。"]'),
('d01eb3ed-50fa-44f7-87f4-34dcabbc24ef','咏柳  其一','文同','宋','宋诗','song-poetry','','[]','風外挂簾誇軟甚，雨中盤砌奈長何。',32,'全唐诗/poet.song.26000.json','["風外挂簾誇軟甚，雨中盤砌奈長何。", "一般草木緣何事，聽唱驪駒爾最多。"]'),
('219385c7-f132-4152-a0a6-af5ab20d1f3a','咏柳  其二','文同','宋','宋诗','song-poetry','','[]','綠蛾緣條立春後，金蛹抱花寒食前。',32,'全唐诗/poet.song.26000.json','["綠蛾緣條立春後，金蛹抱花寒食前。", "行人折罷自欲去，更罥長梢留客鞭。"]'),
('926c5902-fd08-4a9b-b649-9fe2dba87b81','郡齋水閣閑書 湖上','文同','宋','宋诗','song-poetry','','[]','湖上雙禽泛泛，橋邊細柳垂垂。',28,'全唐诗/poet.song.26000.json','["湖上雙禽泛泛，橋邊細柳垂垂。", "日午亭中無事，使君來此吟詩。"]'),
('72cba72b-1a3c-42f7-b4a5-6d3a1862137e','郡齋水閣閑書 獨坐','文同','宋','宋诗','song-poetry','','[]','不報門前賓客，已收案上文書。',28,'全唐诗/poet.song.26000.json','["不報門前賓客，已收案上文書。", "獨坐水邊林下，宛如故里閑居。"]'),
('53c375e6-479a-4daf-a7fa-ee2249a9e033','郡齋水閣閑書 湖橋','文同','宋','宋诗','song-poetry','','[]','湖橋北頰花塢，水閣西頭竹村。',28,'全唐诗/poet.song.26000.json','["湖橋北頰花塢，水閣西頭竹村。", "霏霏薄霧紅暖，漠漠輕烟翠昏。"]'),
('30af10d8-0aa8-44e5-9486-d819e9546a03','郡齋水閣閑書 推琴','文同','宋','宋诗','song-poetry','','[]','點點新萍帖水，濛濛亂絮縈風。',28,'全唐诗/poet.song.26000.json','["點點新萍帖水，濛濛亂絮縈風。", "盡日推琴默坐，有人池上亭中。"]'),
('31058c52-5456-4226-bcbf-7de7e90079e1','郡齋水閣閑書 靜觀','文同','宋','宋诗','song-poetry','','[]','十許紋魚弄水，一雙花鴨眠沙。',28,'全唐诗/poet.song.26000.json','["十許紋魚弄水，一雙花鴨眠沙。", "靜觀只恐驚去，無語憑欄日斜。"]'),
('74953d44-261e-4d91-b7d0-2c279fdcfb5e','郡齋水閣閑書 亭館','文同','宋','宋诗','song-poetry','','[]','亭館翛翛度日，園林寂寂經春。',28,'全唐诗/poet.song.26000.json','["亭館翛翛度日，園林寂寂經春。", "且遮新笋誇客，莫掃殘花悶人。"]'),
('d710a1f0-349d-4209-b3ed-579d3a8bebe0','郡齋水閣閑書 流水','文同','宋','宋诗','song-poetry','','[]','四首秦僧絕論，一篇楚客離騷。',28,'全唐诗/poet.song.26000.json','["四首秦僧絕論，一篇楚客離騷。", "讀罷却彈流水，先生此興尤高。"]'),
('c2ca88b5-c809-48f8-9e56-c40c569ef4df','郡齋水閣閑書 報國','文同','宋','宋诗','song-poetry','','[]','報國無忘竭節，居官勿用論功。',28,'全唐诗/poet.song.26000.json','["報國無忘竭節，居官勿用論功。", "莫問咥咥趨樂，不煩咄咄書空。"]'),
('117c24e4-63df-484b-9ccc-b8843190c52b','郡齋水閣閑書 聞道','文同','宋','宋诗','song-poetry','','[]','聞道幸非曲士，讀書甘作陳人。',28,'全唐诗/poet.song.26000.json','["聞道幸非曲士，讀書甘作陳人。", "爲文自怪逆俗，好畫誰知入神。"]'),
('872b336f-9068-4c03-a289-a1bee52eb55e','郡齋水閣閑書 相如','文同','宋','宋诗','song-poetry','','[]','相如何必稱病，靖節奚須去官。',28,'全唐诗/poet.song.26000.json','["相如何必稱病，靖節奚須去官。", "就下其誰不許，如愚是處皆安。"]'),
('ade66548-a53a-46d6-b3d1-d9e9af2c8d6b','郡齋水閣閑書 彭澤','文同','宋','宋诗','song-poetry','','[]','彭澤先生未去，武陵太守常貧。',28,'全唐诗/poet.song.26000.json','["彭澤先生未去，武陵太守常貧。", "上官幸且容己，下鬼休來笑人。"]'),
('86a383b0-1e60-4d3e-9edc-6d60f4f28dd1','郡齋水閣閑書 憑几','文同','宋','宋诗','song-poetry','','[]','列傳日逢佳士，群書時得微言。',28,'全唐诗/poet.song.26000.json','["列傳日逢佳士，群書時得微言。", "自對古人憑几，不煩俗客登門。"]'),
('a3300b9d-703b-4f38-8f02-41765709b6f1','郡齋水閣閑書 衰後','文同','宋','宋诗','song-poetry','','[]','衰後常親藥餌，憂來頗憶林泉。',28,'全唐诗/poet.song.26000.json','["衰後常親藥餌，憂來頗憶林泉。", "身坐謝莊小閣，心游沈約東田。"]'),
('9cb78af1-3d96-4307-9553-b459ef8d1d24','郡齋水閣閑書 自悟','文同','宋','宋诗','song-poetry','','[]','自悟空王理勝，因知辯士辭窮。',28,'全唐诗/poet.song.26000.json','["自悟空王理勝，因知辯士辭窮。", "但了一忘六解，休論四異三同。"]'),
('fb60abc1-320c-4992-b4f6-86fb7b428a5a','郡齋水閣閑書 鷺鷥','文同','宋','宋诗','song-poetry','','[]','避雨竹間點點，迎風柳下翻翻。',28,'全唐诗/poet.song.26000.json','["避雨竹間點點，迎風柳下翻翻。", "靜依寒蓼如畫，獨立晴沙可憐。"]'),
('636248b2-469e-4049-bb12-400ebf3909a1','郡齋水閣閑書 蓮子','文同','宋','宋诗','song-poetry','','[]','綠實填房未滿，黄茸繞殻方開。',28,'全唐诗/poet.song.26000.json','["綠實填房未滿，黄茸繞殻方開。", "爲問因誰勸酒，一時齊側金杯。"]'),
('19db1110-41b9-4c52-8a25-8d3310ba4ad8','郡齋水閣閑書 采蓮','文同','宋','宋诗','song-poetry','','[]','岸幘客來橋上，濺裙人在湖中。',28,'全唐诗/poet.song.26000.json','["岸幘客來橋上，濺裙人在湖中。", "桂楫蘭橈甚處，蓮花荷葉無窮。"]'),
('c4bb7e69-3127-49ad-8b36-2ffc482588e2','郡齋水閣閑書 翡翠','文同','宋','宋诗','song-poetry','','[]','見諸長喙須避，得少纖鱗便飛。',28,'全唐诗/poet.song.26000.json','["見諸長喙須避，得少纖鱗便飛。", "爲報休來近岸，有人愛汝毛衣。"]'),
('f9da4ba7-325b-43ea-b486-bfee3a6a5dcc','郡齋水閣閑書 朱槿','文同','宋','宋诗','song-poetry','','[]','含露方矜杳裊，摇風旋見離披。',28,'全唐诗/poet.song.26000.json','["含露方矜杳裊，摇風旋見離披。", "湖上先生笑汝，朝開暮落何爲。"]'),
('54247005-8343-4978-bdb1-0d430be89041','郡齋水閣閑書 青鸛','文同','宋','宋诗','song-poetry','','[]','常惡靜時鳬鶩，不驚飽處蝦魚。',28,'全唐诗/poet.song.26000.json','["常惡靜時鳬鶩，不驚飽處蝦魚。", "與吾閑正相似，問爾樂復何如。"]'),
('33b28dda-edbf-4d15-89a8-de172de8f749','郡齋水閣閑書 車軒','文同','宋','宋诗','song-poetry','','[]','平湖靜處朱閣，垂柳深中畫橋。',28,'全唐诗/poet.song.26000.json','["平湖靜處朱閣，垂柳深中畫橋。", "隠几香烟露濕，投竿衣带風飄。"]'),
('7382336d-3f0e-4a46-8533-50453a29bfb3','郡齋水閣閑書 偶書','文同','宋','宋诗','song-poetry','','[]','犢去食苗莫問，烏來攫肉休知。',28,'全唐诗/poet.song.26000.json','["犢去食苗莫問，烏來攫肉休知。", "物須以信相感，事忌於心有爲。"]'),
('336b8e0a-97ad-461b-9d24-e863b858c550','郡齋水閣閑書 北岸','文同','宋','宋诗','song-poetry','','[]','曲榭紅蕖影上，圓庵綠篠陰中。',28,'全唐诗/poet.song.26000.json','["曲榭紅蕖影上，圓庵綠篠陰中。", "門外何人會畫，故來寫作屏風。"]'),
('f2d4325a-f67e-47eb-a9bb-3a44b28c090c','郡齋水閣閑書 自詠','文同','宋','宋诗','song-poetry','','[]','看畫亭中默坐，吟詩岸上微行。',28,'全唐诗/poet.song.26000.json','["看畫亭中默坐，吟詩岸上微行。", "人謂偷閑太守，自呼竊祿先生。"]'),
('7f4ba6d5-8a68-4d8e-b2cf-1a8f7fab0025','郡齋水閣閑書 再贈鷺鷥','文同','宋','宋诗','song-poetry','','[]','頸若瓊鈎淺曲，股如碧管深翹。',28,'全唐诗/poet.song.26000.json','["頸若瓊鈎淺曲，股如碧管深翹。", "湖上水禽無數，其誰似汝風標。"]'),
('d45bc5c9-0ca9-4ab1-bbcb-eed3595ec38f','郡齋水閣閑書 閑書','文同','宋','宋诗','song-poetry','','[]','逐出堪羞子溥，歸來可重淵明。',28,'全唐诗/poet.song.26000.json','["逐出堪羞子溥，歸來可重淵明。", "試問七松處士，何如五柳先生。"]'),
('5648aa4c-3d22-42ed-ab20-e63c743db0a4','往年寄子平','文同','宋','宋诗','song-poetry','','[]','往年記得歸在京，日日訪子來西城。',160,'全唐诗/poet.song.26000.json','["往年記得歸在京，日日訪子來西城。", "雖然對坐兩寂寞，亦有大笑時相轟。", "顧子心力苦未老，猶弄故態如狂生。", "書窗畫壁恣掀倒，脫帽褫带隨縱橫。", "喧呶歌詩嘂文字，蕩突不管鄰人驚。", "更呼老卒立臺下，使抱短簫吹月明。", "清歡居此僅數月，夜夜放去常三更。", "別來七年在鄉里，已忝三度移雙旌。", "今茲惛惛意思倦，加以跕跕疾病嬰。", "每思此樂一絕後，更不逢人如夜行。"]'),
('49523297-dc17-45dd-b1a8-ef5c2e0fbdf8','贈日新禪師','文同','宋','宋诗','song-poetry','','[]','嶕嶢祝融峰，䆗窱懶瓚巖。',168,'全唐诗/poet.song.26000.json','["嶕嶢祝融峰，䆗窱懶瓚巖。", "師也西南人，嘗居彼巉巉。", "十年不下山，烟雲爛衣衫。", "借問爾何爲，法味見愈饞。", "妄萌將軋然，即以慧刃芟。", "既久闢門戶，不須更封緘。", "龍神護水瓶，鬼物扶經函。", "疊足坐蒼石，放身依古杉。", "一日望劍門，歸心瞥如帆。", "過我畫戟前，清晨投短銜。", "欣然揖師坐，未語已不凡。", "再勘自不破，誰敢分酸鹹。", "大朴本無痕，巧者强削劖。", "師如捉龜拂，定不空喃喃。"]'),
('29872147-e4e3-43fe-b561-1f8970d1c848','送竇僉判同年','文同','宋','宋诗','song-poetry','','[]','冰霜滿清漢，此地送君歸。',72,'全唐诗/poet.song.26000.json','["冰霜滿清漢，此地送君歸。", "天涯作遠別，懷抱殊依依。", "短亭臨灙水，楊柳長條稀。", "道傍有寒梅，幽香撲人衣。", "折以持贈君，愛之含春暉。", "酒罷不可留，晚鴻隨馬飛。"]'),
('515d2e60-da55-4200-ab92-d19e48d7a0fc','拙詩六韵奉寄興州分判誠之蒲兄','文同','宋','宋诗','song-poetry','','[]','武興山水郡，左右有佳處。',72,'全唐诗/poet.song.26000.json','["武興山水郡，左右有佳處。", "仙巖蟬兩殻，佛字玉一柱。", "神坑孕金礫，靈竇洩瓊乳。", "乳柱石窟寺，不辨文字古。", "主人好事者，乃我詩酒侶。", "安得陪後乘，放蕩此歷睹。"]'),
('98d23357-b7a0-4834-a5aa-89e6b679df4a','依韵和蒲誠之春日即事','文同','宋','宋诗','song-poetry','','[]','輕烟漠漠雨斜斜，無事常教放兩衙。',64,'全唐诗/poet.song.26000.json','["輕烟漠漠雨斜斜，無事常教放兩衙。", "問客江邊求好石，倩人山裏覓奇花。", "新蔬宛宛生晴圃，淺溜涓涓出暖沙。", "入夏杯盤須准備，繞畦親灌邵平瓜。"]'),
('d1fa55a4-3c44-40af-a353-3bc52da38233','和提刑子功喜雨','文同','宋','宋诗','song-poetry','','[]','時雨已可喜，况當春發生。',240,'全唐诗/poet.song.26000.json','["時雨已可喜，况當春發生。", "入地如流膏，浸灌萬物萌。", "真宰每自惜，纔灑復却晴。", "常時稍霑濕，庶彙亦已榮。", "昨宵忽盛下，欄宇翻瓶罌。", "高原與庳陸，旦可一尺盈。", "尋觀太陽起，紅光吐崢嶸。", "萬里洗氛濁，四顧蒼烟平。", "群農悉就野，上下羅晨耕。", "父老荷鋤鍤，林間笑相迎。", "盡言此美澤，天意恤下甿。", "麻麥固已定，預見禾黍成。", "且幸賦輸辦，敢望求他贏。", "次第還與官，口腹甘別營。", "願常獲豐稔，自覺所取輕。", "言罷乃散去，溝壠紛縱橫。", "使者有職事，其喜誰與并。", "高齋聽淙淙，不寐達五更。", "豈不省文移，頼此一夕傾。", "天明作浩歌，滿紙編和聲。"]'),
('4fb19f5a-3321-4b44-becf-db36bda646fc','謝夏文州寄金綫狨','文同','宋','宋诗','song-poetry','','[]','天地生奇獸，朝廷寵近臣。',48,'全唐诗/poet.song.26000.json','["天地生奇獸，朝廷寵近臣。", "覆鞍須用此，投網爲何人。", "梨栗恩雖厚，雲山夢想頻。", "煩君遠相惠，時爲一沾巾。"]'),
('d5dbf70b-bbc8-487b-bc62-d740880389b5','依韵和子駿雪山圖','文同','宋','宋诗','song-poetry','','[]','一白溪山六幅中，其間雪意與雲容。',32,'全唐诗/poet.song.26000.json','["一白溪山六幅中，其間雪意與雲容。", "君應記得飛仙下，飈馭亭前此數峰。"]'),
('dae11a99-fe1e-47b4-b32a-2dc4184bf755','此樂','文同','宋','宋诗','song-poetry','','[]','吏散收簿書，公館如山居。',123,'全唐诗/poet.song.26000.json','["吏散收簿書，公館如山居。", "歸來換野服，携策將焉如。", "園亭極瀟灑，陰森修竹下。", "拂石坐終日，徙倚不知夜。", "山月照我明，林風吹我清。", "口誦太古文，往來池上行。", "露下覺微凜，南窗歸就枕。", "心閑神自安，達旦得酣寢。", "亂曰：懶守爾何爲，日日常若斯。", "爲言我自爾，此樂非汝知。"]'),
('4a6faa70-ce32-4262-aaaa-38e2e4de45bc','百舌鳥','文同','宋','宋诗','song-poetry','','[]','衆禽乘春喉吻生，滿林無限啼新晴。',129,'全唐诗/poet.song.26000.json','["衆禽乘春喉吻生，滿林無限啼新晴。", "南園花木正繁盛，小小大大皆來鳴。", "藏枝映葉復誰使，不肯停住常嚶嚶。", "就中百舌最無謂，滿口學盡群鳥聲。", "自無一語出於己，徒爾嘲异常誇從橫。", "朝朝泊我高柳上，叫破一窗殘月明。", "幽人穩睡正酣美，無計可奈遭爾驚。", "少年挾彈彼誰者，安得爲我來五更。"]'),
('7aa67fc2-eb45-404c-aa66-3b7c1bcb8602','莫掃花','文同','宋','宋诗','song-poetry','','[]','莫掃花，從教花滿地。',93,'全唐诗/poet.song.26000.json','["莫掃花，從教花滿地。", "縱然堆積亦何害，留之且重東君意。", "君不見昨朝枝上正芳菲，今日庭前已憔悴。", "中間得好能幾時，用此請君窮物理。", "一榮一謝兩皆空，若了非真本自同。", "但對落英開酒盞，每年如此任春風。"]'),
('467e07f3-4621-4807-8f6a-aaa8a69f51f8','一字至十字成章二首 詠竹','文同','宋','宋诗','song-poetry','','[]','竹，竹。',130,'全唐诗/poet.song.26000.json','["竹，竹。", "森寒，潔綠。", "湘江濱，渭水曲。", "帷幔翠錦，戈矛蒼玉。", "心虛異衆草，節勁逾凡木。", "化龍杖入仙陂，呼鳳律鳴神谷。", "月娥巾帔靜苒苒，風神笙竽清蔌蔌。", "林間飲酒碎影摇樽，石上圍棋輕陰覆局。", "屈大夫逐去徒悅椒蘭，陶先生歸來但尋松菊。", "若論檀欒之操無敵於君，欲圖瀟灑之姿莫賢於僕。"]'),
('1c8f03bd-cf6a-4028-8b11-c30bc2a22bff','一字至十字成章二首 詠石','文同','宋','宋诗','song-poetry','','[]','石，石。',130,'全唐诗/poet.song.26000.json','["石，石。", "陰黑，陽白。", "岸肧胎，山骨骼。", "天地鎔鑄，鬼神刻畫。", "鯤鯢張怒眼，虎兕交鬥額。", "敲如溫玉聲清，洗似精鋼色碧。", "花邊矹爾盡奇品，林下礴然無俗格。", "冰霜慘冽堅操不移，塵土昏冥孤標自隔。", "嶢矹獨立見到侍中家，磊落群居在牛丞相宅。", "昔時大士常命汝曰聽徒，今日衰翁且對君爲佳客。"]'),
('657da7bd-5ae4-4f55-bcef-6b69512e84d1','深渡','文同','宋','宋诗','song-poetry','','[]','前日寒食在綿州，牡丹盛開海棠落。',80,'全唐诗/poet.song.26000.json','["前日寒食在綿州，牡丹盛開海棠落。", "今已逾旬過深渡，山桃一枝橫曉閣。", "此花平川最爲早，何乃於此才破萼。", "化工豈爾用功偏，蓋爾所生居絕壑。", "一年春事但自了，勿較後先嗟寂寞。"]'),
('4f00428b-e09d-4ee5-bda9-828aeee6f0cd','嘉川','文同','宋','宋诗','song-poetry','','[]','嘉川之西過新棧，幾里朱欄繞青壁。',64,'全唐诗/poet.song.26000.json','["嘉川之西過新棧，幾里朱欄繞青壁。", "我行落月尚在水，水影照人襟袖白。", "繁英雜綴修蔓上，綠錦纈带垂百尺。", "清香滿馬去未休，頼爾春風慰行客。"]'),
('84f1bef3-70b7-4473-902b-7e90c30c6d04','青烏','文同','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','青烏客館之東軒，前對長江隔層嶂。',64,'全唐诗/poet.song.26000.json','["青烏客館之東軒，前對長江隔層嶂。", "欹危一徑入林外，竹柵茅檐儼相向。", "愛其生事亦自足，牛羊縱橫鷄犬放。", "安得與爾號比鄰，爲作野歌供吹唱。"]'),
('a8ee7bea-0e2e-43df-af24-c42f13888992','木瓜園','文同','宋','宋诗','song-poetry','','[]','驅馬下高崗，吟鞭只自揚。',48,'全唐诗/poet.song.26000.json','["驅馬下高崗，吟鞭只自揚。", "溪山過新霽，草木發清香。", "浩蕩來江闊，縈紆去棧長。", "春風去欲盡，樽酒嘆何嘗。"]'),
('6550e073-4c5d-48e4-a3e3-009b7058e8df','長舉','文同','宋','宋诗','song-poetry','','[]','山色滿西閣，到江知幾層。',48,'全唐诗/poet.song.26000.json','["山色滿西閣，到江知幾層。", "峰巒李成似，澗谷范寬能。", "闊外晴烟落，深中晚靄凝。", "無由畫奇絕，已下更重登。"]'),
('90598f17-eaf5-4874-bfb2-e98414ffaae7','水磑','文同','宋','宋诗','song-poetry','','[]','激水爲磑嘉陵民，構高穴深良苦辛。',64,'全唐诗/poet.song.26000.json','["激水爲磑嘉陵民，構高穴深良苦辛。", "十里之間凡共此，麥入麵出無虛人。", "彼甿居險所産薄，世世食此江之濱。", "朝廷遣使興水利，嗟爾平輪與側輪。"]'),
('1c89951d-e9a3-4390-a0f3-e81f7dd2c5dd','長舉驛樓','文同','宋','宋诗','song-poetry','','[]','爽氣浮空紫翠濃，隔江無限有奇峰。',32,'全唐诗/poet.song.26000.json','["爽氣浮空紫翠濃，隔江無限有奇峰。", "君如要識營丘畫，請看東頭第五重。"]'),
('e76e08e5-a663-4d02-a5f3-98a21dfed180','正月八日峽中新花','文同','宋','宋诗','song-poetry','','[]','深碧長條淺紫芽，曉叢無數傲霜華。',32,'全唐诗/poet.song.26000.json','["深碧長條淺紫芽，曉叢無數傲霜華。", "只應耻在江梅後，未著葉時先放花。"]'),
('c9195169-6845-499d-90af-334ca12885fa','贈淘金叟','文同','宋','宋诗','song-poetry','','[]','濯石淋沙不自勞，抉光挑屑甚幺麽。',32,'全唐诗/poet.song.26000.json','["濯石淋沙不自勞，抉光挑屑甚幺麽。", "世間有客能胠篋，比爾元來得校多。"]'),
('b579dc3c-9207-4503-9364-08bd6f995676','過青泥','文同','宋','宋诗','song-poetry','','[]','鐵山正月雪交加，欲探東風未有涯。',32,'全唐诗/poet.song.26000.json','["鐵山正月雪交加，欲探東風未有涯。", "纔過青泥春便好，水邊林下見梅花。"]'),
('3fe21ad8-0d80-4aec-b9fe-1b6937333acc','過大散寄子駿','文同','宋','宋诗','song-poetry','','[]','纔過嘉陵心自喜，歸來一夜寫君書。',32,'全唐诗/poet.song.26000.json','["纔過嘉陵心自喜，歸來一夜寫君書。", "明朝便送曾冰底，定有西行雙鯉魚。"]'),
('bb27f557-c9e0-4cf4-a891-b3839663a76b','飛仙石溪','文同','宋','宋诗','song-poetry','','[]','愛此潺湲任濺衣，獨尋幽石坐多時。',32,'全唐诗/poet.song.26000.json','["愛此潺湲任濺衣，獨尋幽石坐多時。", "日斜徒御應相笑，底事教公上馬遲。"]'),
('7be6662f-db62-4d3e-814b-ddbbd063afa9','籌筆諸峰','文同','宋','宋诗','song-poetry','','[]','君看籌筆驛江邊，翠壁蒼崖起晝烟。',32,'全唐诗/poet.song.26000.json','["君看籌筆驛江邊，翠壁蒼崖起晝烟。", "正是峽中佳絕處，土人休用作畬田。"]'),
('59bf4f52-7a25-4012-a41e-848b7f249b6e','柳池贈丁絪','文同','宋','宋诗','song-poetry','','[]','場屋聲名四十年，五車書誤一囊錢。',32,'全唐诗/poet.song.26000.json','["場屋聲名四十年，五車書誤一囊錢。", "老來山驛爲監吏，相對春風但惘然。"]'),
('b2d07064-ea4f-4adf-9dbc-d13579076010','偶題','文同','宋','宋诗','song-poetry','','[]','鬢雲雙墮給明珠，窄窄羅裙短短襦。',32,'全唐诗/poet.song.26000.json','["鬢雲雙墮給明珠，窄窄羅裙短短襦。", "閑把花枝起新樣，滿調金粉畫文輸。"]'),
('9582694a-9f53-47c9-ba2e-c6619bf12c35','天漢橋','文同','宋','宋诗','song-poetry','','[]','風吹兩岸菰蒲乾，日灑一汀鳬鶩寒。',32,'全唐诗/poet.song.26000.json','["風吹兩岸菰蒲乾，日灑一汀鳬鶩寒。", "夜深霜月照湖水，須上此橋憑畫欄。"]'),
('5d30a5a7-50a8-4f20-876a-ce4a55ac2953','望雲樓','文同','宋','宋诗','song-poetry','','[]','南山北嶺遠如層，朝雲暮雨濃若烝。',32,'全唐诗/poet.song.26000.json','["南山北嶺遠如層，朝雲暮雨濃若烝。", "樓高百尺見萬里，更有底事須來登。"]'),
('7fefc462-8467-4ef6-8534-86f47d6f7fa2','灙泉亭','文同','宋','宋诗','song-poetry','','[]','竹列蒼戟枝榦稠，亭開翠幄窗戶幽。',32,'全唐诗/poet.song.26000.json','["竹列蒼戟枝榦稠，亭開翠幄窗戶幽。", "下分灙水入渠口，正坐小榻臨清流。"]'),
('f4181254-60f1-4767-9eae-9959fba4ba93','此君庵','文同','宋','宋诗','song-poetry','','[]','斑斑墮籜開新筠，粉光璀璨香氛氳。',32,'全唐诗/poet.song.26000.json','["斑斑墮籜開新筠，粉光璀璨香氛氳。", "我常愛君此默坐，勝見無限尋常人。"]'),
('ede5a4ff-8087-429d-b0fc-98dcf045e0fa','二樂榭','文同','宋','宋诗','song-poetry','','[]','㬊山北來聳峨峨，漢水東下流滔滔。',32,'全唐诗/poet.song.26000.json','["㬊山北來聳峨峨，漢水東下流滔滔。", "開軒直可望百里，最愛此榭凌雲高。"]'),
('5ca21bc8-6167-46f3-bb88-b383d0629e51','漫郎亭','文同','宋','宋诗','song-poetry','','[]','鑿城爲洞深且長，沿壕開徑閑復荒。',32,'全唐诗/poet.song.26000.json','["鑿城爲洞深且長，沿壕開徑閑復荒。", "有亭如許入蒙密，誰比次山稱漫郎。"]'),
('d648093a-b3e4-4eec-acf9-4da4708470f3','涵虛亭','文同','宋','宋诗','song-poetry','','[]','雲外衆峰檐際橫，竹間飛泉窗下鳴。',32,'全唐诗/poet.song.26000.json','["雲外衆峰檐際橫，竹間飛泉窗下鳴。", "欲往二樂即歇此，胸懷已自如冰清。"]'),
('eedf5f84-32a7-4ee8-ba66-46c89254e915','菡萏亭','文同','宋','宋诗','song-poetry','','[]','日高過竹湖水光，風長入座荷花香。',32,'全唐诗/poet.song.26000.json','["日高過竹湖水光，風長入座荷花香。", "交紅映綠滿渠下，各有意態隨低昂。"]'),
('bb0e1716-e191-47c9-8c29-ffe742bdd77b','篔簹谷','文同','宋','宋诗','song-poetry','','[]','池通一谷波溶溶，竹合兩岸烟濛濛。',32,'全唐诗/poet.song.26000.json','["池通一谷波溶溶，竹合兩岸烟濛濛。", "尋幽直去景漸野，宛爾不似在塵中。"]'),
('50f62a84-7b26-4999-86e8-daaed6cbe205','王氏北溪','文同','宋','宋诗','song-poetry','','[]','石龜州北群峰起，一去距城無十里。',64,'全唐诗/poet.song.26000.json','["石龜州北群峰起，一去距城無十里。", "烟嵐秀氣護巖扃，松菊清香泛溪水。", "輕裘肥馬正榮耀，春韮秋菘任凋毀。", "待將底物勒移文，谷口濃雲白如紙。"]'),
('33effc33-91c5-4c39-bce6-4d28a1eace2f','雋老水墨','文同','宋','宋诗','song-poetry','','[]','之人勃海後，所尚亦瀟灑。',48,'全唐诗/poet.song.26000.json','["之人勃海後，所尚亦瀟灑。", "不承春秋學，乃好水墨畫。", "鵝溪吾鄉里，有絹滑如砑。", "君凡幾多筆，爲我禿數把。"]'),
('f00d4658-3ec7-4845-ba6b-4ab0ea86b41b','李堅甫凈居雜題一十三首 靜居','文同','宋','宋诗','song-poetry','','[]','何事當清世，歸來詠考槃。',24,'全唐诗/poet.song.26000.json','["何事當清世，歸來詠考槃。", "近聞新住處，不似在長安。"]'),
('64b19587-f9e5-4564-9717-30d220783cd5','李堅甫凈居雜題一十三首 靜叟','文同','宋','宋诗','song-poetry','','[]','米鹽辭劇務，宮觀得清資。',24,'全唐诗/poet.song.26000.json','["米鹽辭劇務，宮觀得清資。", "自取閑官樂，爭教俗客知。"]'),
('81011381-5dea-49f0-abfc-1a5260c8ecde','李堅甫凈居雜題一十三首 琴室','文同','宋','宋诗','song-poetry','','[]','將何寫幽意，有此古桐聲。',24,'全唐诗/poet.song.26000.json','["將何寫幽意，有此古桐聲。", "爲問好彈處，誰來聽蟹行。"]'),
('53b5ceb0-735e-4ac9-90c9-659776a521ea','李堅甫凈居雜題一十三首 棋室','文同','宋','宋诗','song-poetry','','[]','身閑無可奈，惟此度晨昏。',24,'全唐诗/poet.song.26000.json','["身閑無可奈，惟此度晨昏。", "與客正爭局，聞誰休叩門。"]'),
('b6072171-ff6a-4733-9d3b-c2b7ce52d68e','李堅甫凈居雜題一十三首 書齋','文同','宋','宋诗','song-poetry','','[]','縑緗羅几格，無限有奇書。',24,'全唐诗/poet.song.26000.json','["縑緗羅几格，無限有奇書。", "想在中間坐，渾如獺祭魚。"]'),
('17d80bb1-c518-4c06-aedc-d66a555e378e','李堅甫凈居雜題一十三首 畫齋','文同','宋','宋诗','song-poetry','','[]','試品齋中畫，曾無第二流。',24,'全唐诗/poet.song.26000.json','["試品齋中畫，曾無第二流。", "頑礓與亂篠，應挂在當頭。"]'),
('60cb8fc3-637b-49bf-8bc9-5000afec3ddc','李堅甫凈居雜題一十三首 春軒','文同','宋','宋诗','song-poetry','','[]','日光明駘蕩，天氣暖氤氳。',24,'全唐诗/poet.song.26000.json','["日光明駘蕩，天氣暖氤氳。", "草木遍庭檻，清香朝暮聞。"]'),
('4548aec6-85ec-4818-ad3e-4c769cb71f02','李堅甫凈居雜題一十三首 秋軒','文同','宋','宋诗','song-poetry','','[]','清飈動蕭瑟，翠樾減婆娑。',24,'全唐诗/poet.song.26000.json','["清飈動蕭瑟，翠樾減婆娑。", "却愛夜來月，滿窗寒影多。"]'),
('5ae1b737-cdc9-4874-a44b-e9aeb696b7ec','李堅甫凈居雜題一十三首 竹軒','文同','宋','宋诗','song-poetry','','[]','鐵石枝梢勁，冰霜節目圓。',24,'全唐诗/poet.song.26000.json','["鐵石枝梢勁，冰霜節目圓。", "凈摇風苒苒，閑映月娟娟。"]'),
('c8d79a36-ae7e-480e-8d55-cb6a8806be5d','李堅甫凈居雜題一十三首 檜軒','文同','宋','宋诗','song-poetry','','[]','翠羽攢何密，青丸綴實繁。',24,'全唐诗/poet.song.26000.json','["翠羽攢何密，青丸綴實繁。", "誰知人與木，俱是太清孫。"]'),
('8d9a4e11-b79e-40ee-91ad-628a57e38d05','李堅甫凈居雜題一十三首 水亭','文同','宋','宋诗','song-poetry','','[]','寒溜日涓涓，縈紆小檻前。',24,'全唐诗/poet.song.26000.json','["寒溜日涓涓，縈紆小檻前。", "不知明月下，誰與弄潺湲。"]'),
('803d9a83-469d-4e20-a516-0a8fa5f03313','李堅甫凈居雜題一十三首 退庵','文同','宋','宋诗','song-poetry','','[]','未老先求退，題庵乃自呼。',24,'全唐诗/poet.song.26000.json','["未老先求退，題庵乃自呼。", "有才須進用，能保此名無。"]'),
('09e71308-be60-40e4-88a8-8d0da5abba60','李堅甫凈居雜題一十三首 北堂','文同','宋','宋诗','song-poetry','','[]','凈居都葺了，餘地蓋斯堂。',24,'全唐诗/poet.song.26000.json','["凈居都葺了，餘地蓋斯堂。", "不用栽萱草，無憂可得忘。"]'),
('657abb51-d38b-4431-9656-52287bfab3eb','晉銘','文同','宋','宋诗','song-poetry','','[]','長安鬻碑者，遺我古鼎銘。',120,'全唐诗/poet.song.26000.json','["長安鬻碑者，遺我古鼎銘。", "不知其所來，有眼實未經。", "凡百十九字，詭怪摹物形。", "縱橫下點畫，不類子與丁。", "試考諸傳說，其源已冥冥。", "宣王石鼓文，氣韵殊飄零。", "始皇嶧山碑，骨骼何竛竮。", "我恐鬼哭時，正爲此物靈。", "安得不死神，提去詢大庭。", "爲我譯其辭，讀之駭群聽。"]'),
('1ec7cd56-d5dc-4abf-ba7b-537107d97c44','秦詔','文同','宋','宋诗','song-poetry','','[]','山流濯幽阬，銅篆發古耀。',168,'全唐诗/poet.song.26000.json','["山流濯幽阬，銅篆發古耀。", "我行奉天縣，叟以百錢糶。", "讀之乃二世，元年所刻詔。", "謂法度量者，盡始皇帝造。", "辭止曰皇帝，久遠若爲道。", "乃命斯去疾，具述紀其右。", "文章既精簡，字畫亦佳妙。", "亥爾何等人，敢作萬世調。", "其爲者非是，所累纔一廟。", "區區頌微末，回首皆可弔。", "郡兵厭寶玉，得此只揮掉。", "漂流落荒壤，千載厄潛奧。", "乃知天宇內，事有不可料。", "此物今何爲，惟助觀者笑。"]'),
('cc7647fa-0966-4347-ab5a-62f794a0a790','問陳彥升覓古瓦硯','文同','宋','宋诗','song-poetry','','[]','魏主用死力，構彼銅雀臺。',192,'全唐诗/poet.song.26000.json','["魏主用死力，構彼銅雀臺。", "當時臺上瓦，百澄爲一坯。", "燒成比堅玉，翠甲橫崔嵬。", "西陵既歸後，此地日以摧。", "後歷典午朝，群雄力相豗。", "茲臺既已傾，此瓦只自堆。", "歲久岸谷變，埋沒深蒿萊。", "初誰得耕人，刳之研松煤。", "其理密且潤，端歙真可咍。", "彥升所有者，一一皆珍材。", "自言欲購時，經歲無一枚。", "琴紋與錫花，此乃如瓊瑰。", "前日秘閣下，重匣手自開。", "示我者佳絕，恰用一樸裁。", "形模甚古野，用可資怪魁。", "歸來作詩乞，願致無遲回。"]'),
('4d425c5e-269b-4de9-bdb1-1b5d161c3341','謝楊侍讀惠端溪紫石硯','文同','宋','宋诗','song-poetry','','[]','學文二十年，語氣殊未成。',240,'全唐诗/poet.song.26000.json','["學文二十年，語氣殊未成。", "所以文房中，四譜無一精。", "豈不願收貯，恐竊好事名。", "自愧中槁然，敢假外物榮。", "前日下秘閣，謁公來西城。", "公常顧遇厚，待以爲墨卿。", "延之吐佳論，出口無雜聲。", "語次座上物，硯有紫石英。", "云在嶺使得，渠常美其評。", "因取手自封，見授囑所擎。", "倉皇捧以拜，其喜懷抱盈。", "歸來示家人，衆目歡且驚。", "言並我所有，瓦礫而瑶瓊。", "貴價市珍煤，風前試寒泓。", "磨知密理潤，點覺浮光清。", "洗濯鑒面瑩，彈扣牙音鏗。", "遂剪十襲巾，加以重篋盛。", "客來有欲觀，稍俗不敢呈。", "願傳之子孫，更重金滿籝。", "作詩敘嘉貺，慚比毫毛輕。"]'),
('ee3b4b34-d2fc-4a75-87c9-0fa3588119fa','西岡僦居','文同','宋','宋诗','song-poetry','','[]','出官在秦蜀，始末凡十年。',288,'全唐诗/poet.song.26000.json','["出官在秦蜀，始末凡十年。", "所治得公宇，靡不完且堅。", "中堂與挾廊，角翼相鈎聯。", "領屬僅十口，出處皆安便。", "冬夏惡風日，侵薄曾無緣。", "今年歸中都，職事叨磨鉛。", "未免僦屋住，敢謂須華鮮。", "西岡頗幽僻，愛此遠市廛。", "問得王氏居，十楹月四千。", "床榻案几外，空處無一椽。", "匽溷及井竈，坼壁皆相連。", "經庳須俯首，過隘常側肩。", "所謂十口者，日繞蝸殻旋。", "前時大暑中，幾不禁袢延。", "鬰若鼎釜炊，局如狴犴攣。", "走蝎過亂蟻，飛蚊劇群蟬。", "今日幸過之，復畏明日然。", "喜見白露節，相賀肌肉全。", "如何下淫雨，曉夕常綿綿。", "瓦破榱棟漏，柱陷牆垣穿。", "惟供改席坐，豈暇安枕眠。", "中庭止數步，深已可載船。", "盡室徒跣行，一起復一顛。", "京師費耗地，居止實重遷。"]'),
('65ab09d4-6619-4613-976a-2890e121e89e','閿鄉值風','文同','宋','宋诗','song-poetry','','[]','烈風吹華陰，古槐若長呼。',120,'全唐诗/poet.song.26000.json','["烈風吹華陰，古槐若長呼。", "高沙起黄磧，四望如一鋪。", "上馬低便面，據鞍兀長途。", "日晚過潼關，行客亦已疏。", "守吏索姓名，沸亂如蟲蛆。", "兩目不可開，說之使自書。", "夜至閿鄉縣，僮僕相欷歔。", "困定即洗濯，泥土捫短鬚。", "草草具盤飧，零落飯與蔬。", "恨無姜少府，爲膾黄河魚。"]'),
('af4dd611-941e-4d60-89a1-624d4fccd781','積雨','文同','宋','宋诗','song-poetry','','[]','京師值積雨，浮淖皆滿城。',144,'全唐诗/poet.song.26000.json','["京師值積雨，浮淖皆滿城。", "况當淘决時，左右羅深阬。", "有客南河居，旦夕堤上行。", "病僕挾羸馬，十步八九傾。", "職事有出入，長抱落膽驚。", "都人素豪恣，小官常見輕。", "排闢要穩道，斂避不敢爭。", "試欲效呵止，圜目根姓名。", "往往被濺污，直落舌與睛。", "歸來事洗濯，袍袴紛縱橫。", "仰首問天公，春澤當早晴。", "幸有好日月，何惜施光明。"]'),
('d0ba8702-af13-448f-b7ff-d6e744dd21da','大熱過散關因寄里中友人','文同','宋','宋诗','song-poetry','','[]','六月日正午，大暑若沸鑊。',204,'全唐诗/poet.song.26000.json','["六月日正午，大暑若沸鑊。", "時行古關道，十步九立脚。", "煙雲炙盡散，樹木曬欲落。", "喉鼻喘不接，齒舌津屢涸。", "擔血僮破領，鞍汗馬濡膊。", "幽坑困猿狖，密莽渴鳥雀。", "至此因自謂，胡爲就名縛。", "所利緣底物，奔走冒炎惡。", "塵心日夜迫，欲住不能略。", "因念吾故園，左右悉林薄。", "昔我未第時，此有文酒樂。", "長松借高蔭，飛瀑與清濯。", "層崖對僧詠，大石引客酌。", "畏景雖赫然，無由此流爍。", "于今只夢想，欲往途路邈。", "所效殊未立，期歸尚誰約。", "徒爾發短歌，西首謝巖壑。"]'),
('8c676fa0-10af-4caa-b536-c346f7bf201d','問景遜借梅聖俞詩卷','文同','宋','宋诗','song-poetry','','[]','前日讀子詩，快我煩病軀。',96,'全唐诗/poet.song.26000.json','["前日讀子詩，快我煩病軀。", "若坐大暑中，瓊杯飲琳腴。", "辭嚴意清絕，敢謂人所無。", "子乃不自高，尚爾尊聖俞。", "爲我誦佳句，實亦郊島徒。", "遂云有家藏，兩軸如椽粗。", "我方嗜此學，常恨失所趨。", "願子少假之，使之識夷途。"]'),
('cd68e6f1-cef3-4dcd-b8f9-0cbd76dd3414','秋居覽景因感所事','文同','宋','宋诗','song-poetry','','[]','閒居閉窮巷，拙者誠所宜。',204,'全唐诗/poet.song.26000.json','["閒居閉窮巷，拙者誠所宜。", "掩書坐前楹，默與天理期。", "是時新雨收，物物含秋姿。", "疏檐正殘日，曲几方凉颸。", "群雀下空階，逐逐顧且隨。", "微蟲出幽隙，繞繞行復飛。", "疏篁挺堅勁，不並草木衰。", "叢蘭吐芬芳，豈畏霜露知。", "觀此動與植，一一全天資。", "因念物稟生，有性各異持。", "夫人爲靈者，仁義實所尸。", "胡爲智巧役，所有日夜隳。", "不能保其元，妄事紛擾爲。", "汲汲以就死，所耗無纖釐。", "還本既不完，何用冠且衣。", "余因激所遇，攬筆成此詩。", "庶哉學者心，讀已而悟茲。"]'),
('8e09c536-2e95-4bf6-bbce-b2ab17fc5cd1','彥思示望南山詩因答','文同','宋','宋诗','song-poetry','','[]','余於岐雍間，屢走官道上。',240,'全唐诗/poet.song.26000.json','["余於岐雍間，屢走官道上。", "終南百里近，不得迂馬訪。", "徒常飫雙眼，引首旦夕望。", "群巒突天起，氣勢頗豪王。", "余名愛山者，所見亦無量。", "嵩華最魁傑，詩之豈曾讓。", "至此覺才弱，不敢輒名狀。", "世謂秦土强，捨是孰爲壯。", "彥思奇偉士，雅志同所尚。", "近自山中來，滿幅以詩貺。", "凡是山勝絕，鈎罥付心匠。", "驅聯以大語，句度實奔放。", "豁若展圖畫，壓紙千萬嶂。", "讀之未云徹，早自肝膽喪。", "試欲效其說，無迹可依傍。", "坐見山所有，已若一携杖。", "何當俯清渭，解带濯塵坱。", "掉手入巖谷，琴樽樂幽曠。", "浩漭八極大，冥心恣飄颺。", "此意殊未諧，臨風一悽愴。"]'),
('78412ed9-b801-4695-89cd-e38d4f86c5d9','嘲中條','文同','宋','宋诗','song-poetry','','[]','荆山赴太華，百萬如走駝。',96,'全唐诗/poet.song.26000.json','["荆山赴太華，百萬如走駝。", "嘴尾不相殊，前後翻海波。", "既至擁而蹲，仰首爭列羅。", "太華勢愈尊，引手欲下摩。", "中條從北來，亦願依巍峨。", "豈知隊伍弱，只類馬與驘。", "奔騰氣力盡，群伏飲大河。", "飲已只南望，岌然將奈何。"]'),
('653ba469-658b-4e84-845b-2bc2d1883626','寄題威勝軍守居高明榭','文同','宋','宋诗','song-poetry','','[]','石侯守銅鞮，暑居念煩愀。',96,'全唐诗/poet.song.26000.json','["石侯守銅鞮，暑居念煩愀。", "營基切城角，列礎出樹杪。", "窗橫四野外，轉目可俱了。", "長風落霄極，萬里吹縹緲。", "主人白羽扇，日日上清曉。", "琴樽嘯佳侶，以樂軍事少。", "晴煙抹闤闠，暮角送禽鳥。", "語客莫遽歸，前林月將皎。"]'),
('5707f958-7b22-4516-91c2-22122bbc0f4f','仙禽送景遜赴階州監稅','文同','宋','宋诗','song-poetry','','[]','肅肅彼靈羽，英英下瑶臺。',96,'全唐诗/poet.song.26000.json','["肅肅彼靈羽，英英下瑶臺。", "揚翹俗采暗，振響仙籟回。", "凡鳥只斂避，衆人亦驚猜。", "羅以萬目網，離以雙翼摧。", "十載困塵土，一身伏蒿萊。", "晦色不敢耀，藏音豈能哀。", "饑腸金屑實，渴吻瓊漿開。", "俯首事澡刷，一飛遊九垓。"]'),
('f045d5aa-d64b-4c4d-8373-921ab2c24d2b','送呂希彥司門通判河陽','文同','宋','宋诗','song-poetry','','[]','行父須生公相家，修潔不類在紈綺。',96,'全唐诗/poet.song.26000.json','["行父須生公相家，修潔不類在紈綺。", "豈惟浩蕩愛古學，實亦縱橫曉時事。", "孟州之民爾何幸，一旦得此賢半刺。", "定知未幾政清簡，日日案頭詩滿紙。", "河陽花開酒休䛏，太行雲飛樓好倚。", "若因行縣至盤谷，爲訪其間隠君子。"]'),
('c61f3b8f-11c9-4c0c-935f-a26b1b07c7e2','送周介之學士通判定州  其一','文同','宋','宋诗','song-poetry','','[]','紫垣之東藩，群宇合四翼。',96,'全唐诗/poet.song.26000.json','["紫垣之東藩，群宇合四翼。", "天家積圖史，編簡何萬億。", "介之才藝選，此地典文墨。", "縱橫四部內，騁驟千古力。", "久爲光祿校，頗倦承明直。", "嘗言石渠樹，五見弄春色。", "前自啟君相，得請均外職。", "翩然駕別乘，去矣大河北。"]'),
('aab3d587-6ba1-49ff-bb20-209a8b3ea329','送周介之學士通判定州  其二','文同','宋','宋诗','song-poetry','','[]','河北扼虜要，定武承其咽。',96,'全唐诗/poet.song.26000.json','["河北扼虜要，定武承其咽。", "分道宿勁兵，望之爲中權。", "朝廷倚注地，擇用須材賢。", "黠獫讋所聞，射獵不敢邊。", "茲焉勢愈重，豈謂甲馬然。", "將軍廟堂老，御史蓬瀛仙。", "合謀運潛略，勝氣壓古燕。", "惟當陪緩带，壺觴鈴閣前。"]'),
('a17fd6b9-11ce-49da-a90c-e22b7e102b00','送柳才僉判蔡州','文同','宋','宋诗','song-poetry','','[]','翩翩河東孫，豪邁有祖德。',96,'全唐诗/poet.song.26000.json','["翩翩河東孫，豪邁有祖德。", "二十補楚掾，能用口破賊。", "歸來入京寺，不借推挽力。", "驕夸固其宜，了不見顔色。", "題輿蓋本乘，入幕乃屈職。", "淮西號劇府，君也茲斂翼。", "朝廷選材吏，聞下前日敕。", "奉詔者云誰，此章君可塞。"]'),
('3f6edba5-9bfb-43db-a666-f63246c2ac47','送張宗益工部知相州','文同','宋','宋诗','song-poetry','','[]','學術深沉久未施，晚登臺省世方知。',64,'全唐诗/poet.song.26000.json','["學術深沉久未施，晚登臺省世方知。", "詩章好奏周文廟，字法宜磨魏武碑。", "禁掖便當提大筆，名藩猶自擁高麾。", "應憐共試金坡者，答颯渾如鄭鮮之。"]'),
('4951410b-b4a9-45bf-a370-f83e48987a65','送王恪司門知絳州','文同','宋','宋诗','song-poetry','','[]','絳守園池天下誇，紹述有記詞聱牙。',64,'全唐诗/poet.song.26000.json','["絳守園池天下誇，紹述有記詞聱牙。", "蒼官青士左右樹，神君仙人高下花。", "遠水依然尚鈎带，舊門想已無靴檛。", "自憐俗狀不能到，此去羨君專宴衙。"]'),
('8cf201c6-bc6c-4af2-927a-906ceb85eac9','送蒲霖中舍致仕歸閬中','文同','宋','宋诗','song-poetry','','[]','急趨長拜倦勞勞，自笑風埃滿綠袍。',64,'全唐诗/poet.song.26000.json','["急趨長拜倦勞勞，自笑風埃滿綠袍。", "官味十年如水薄，歸心一日共雲高。", "毫釐已悟蝸爭角，文彩須知鳳得毛。", "且喜還家收拾在，錦屏山下舊東皋。"]'),
('4127ee11-a431-412d-bffa-c10e69394154','送劉立之著作歸長安因赴安定知縣','文同','宋','宋诗','song-poetry','','[]','西郊晴霧曉霏霏，回首京塵一拂衣。',64,'全唐诗/poet.song.26000.json','["西郊晴霧曉霏霏，回首京塵一拂衣。", "上國莫嗟爲客久，高堂初喜改官歸。", "洛城氣候花纔動，灞水風光絮恰飛。", "恨不同遊曲江岸，與將歌酒䛏春暉。"]'),
('914e2538-e67f-4c8d-889b-11fd08a3de30','送張正夫監簿歸漢州','文同','宋','宋诗','song-poetry','','[]','知己非不遇，其如才命違。',48,'全唐诗/poet.song.26000.json','["知己非不遇，其如才命違。", "宦名疑在夢，親祿只徒歸。", "道路盤危棧，家山指落暉。", "好將綿竹頌，重拂入關衣。"]'),
('df5dc386-7c6b-403e-bd40-6e50df3ef8b8','新霜','文同','宋','宋诗','song-poetry','','[]','新霜著庭樹，葉下如猛剉。',84,'全唐诗/poet.song.26000.json','["新霜著庭樹，葉下如猛剉。", "蕭然物容改，有若懼凌挫。", "砌下丹橘落，牆邊紫榴破。", "精光竹勁健，沮喪柳怯懦。", "覽景惜向暮，感時驚忽過。", "勝事實可樂，閑愁本堪唾。", "何當共佳客，對此酌香糯。"]'),
('89f888d2-4dae-4d12-aa59-d49b0004f102','答馬子山節推見寄','文同','宋','宋诗','song-poetry','','[]','曾陪參畫從櫜鞬，文雅當時最盛傳。',64,'全唐诗/poet.song.26000.json','["曾陪參畫從櫜鞬，文雅當時最盛傳。", "玉挂好風橫飲簟，翠漪明月漾吟船。", "石渠金馬余何者，綠水紅蓮子尚然。", "好養江邊鴻漸翼，詔書非久下菑川。"]'),
('33e0f87c-c6cf-4769-af1f-d5a1806d449b','紅樹','文同','宋','宋诗','song-poetry','','[]','萬葉驚風盡卷收，獨餘紅樹擬禁秋。',64,'全唐诗/poet.song.26000.json','["萬葉驚風盡卷收，獨餘紅樹擬禁秋。", "已疑斷燒生前嶺，更共殘霞入遠樓。", "楓岸最深霜未落，柿園渾變雨初休。", "勸君莫上青山道，粧點行人分外愁。"]'),
('0193b648-6b60-4812-89a7-db6375a06b70','彥思惠榅桲因謝','文同','宋','宋诗','song-poetry','','[]','秦中物專美，榅桲爲嘉果。',96,'全唐诗/poet.song.26000.json','["秦中物專美，榅桲爲嘉果。", "南枝種府署，高樹立婀娜。", "秋來放新實，照日垂萬顆。", "中滋甘醴釀，外飾素茸裹。", "彥思摘晨露，滿合持贈我。", "復侑以佳句，再拜極所荷。", "珍之不敢盡，玩已即深鎖。", "茲焉遂名産，沙苑忽幺麽。"]'),
('127732c2-dc22-4963-a54a-43f1d2fb7f26','彥思有北樓見寄之作依韵和答','文同','宋','宋诗','song-poetry','','[]','峨峨守居城上樓，最宜登覽群物秋。',64,'全唐诗/poet.song.26000.json','["峨峨守居城上樓，最宜登覽群物秋。", "層檐高搴礙翠嶺，采檻直出橫清流。", "煙中島嶼遠歷歷，風外巖壑寒颼颼。", "主人好事客意樂，日夕幸此忘幽憂。"]'),
('ff9a6af8-6c54-45c2-b38e-46c0cd91dec2','閑居秋日書事','文同','宋','宋诗','song-poetry','','[]','秋雨晚蕭蕭，端居閑寂寥。',48,'全唐诗/poet.song.26000.json','["秋雨晚蕭蕭，端居閑寂寥。", "雀饑爭朽穗，蟬病落寒條。", "雲過茶煙沒，風歸硯水摇。", "惟當䛏圖史，閑日底能消。"]'),
('1239d62d-8935-4b4b-be80-467c9a980aa4','寄題湖州沈秀才天隠樓','文同','宋','宋诗','song-poetry','','[]','自念久不偶，歸老東南州。',48,'全唐诗/poet.song.26000.json','["自念久不偶，歸老東南州。", "地名水精宮，家有天隠樓。", "收捲勢利心，欲與汗漫遊。", "出處固以義，無爲子光羞。"]'),
('96b61977-2f09-4a1f-ad85-47173a83186b','酬仲幾秦州道上見寄','文同','宋','宋诗','song-poetry','','[]','送子入秦處，紛紛黄葉間。',48,'全唐诗/poet.song.26000.json','["送子入秦處，紛紛黄葉間。", "孤舟渡野水，疋馬轉遥山。", "明月每夜望，清風何日還。", "新詩慰牢落，爲一破愁顔。"]'),
('1366bd04-327c-453a-85e9-dded8c69eb0e','入谷馬上  其一','文同','宋','宋诗','song-poetry','','[]','宛轉入深谷，一林還一丘。',48,'全唐诗/poet.song.26000.json','["宛轉入深谷，一林還一丘。", "摇鞭弄新霽，把筆韵高秋。", "翠巘雲長合，寒潭煙自浮。", "因成憶猿鶴，聊此爲遲留。"]'),
('2e5dd79e-a750-4aab-90d5-a901e6fdbc29','入谷馬上  其二','文同','宋','宋诗','song-poetry','','[]','亂竹圍清密，垂蘿蔭屈盤。',48,'全唐诗/poet.song.26000.json','["亂竹圍清密，垂蘿蔭屈盤。", "晴林風色淡，晚水日光寒。", "樹石因誰好，煙雲只自漫。", "群峰若相待，滿眼碧巑岏。"]'),
('c407ef03-192e-425e-a71f-2c71b6c3f505','入谷馬上  其三','文同','宋','宋诗','song-poetry','','[]','北谷氣象佳，有景乃天設。',48,'全唐诗/poet.song.26000.json','["北谷氣象佳，有景乃天設。", "峰巒互虧蔽，湍瀨相綰結。", "珍條拂垂袂，芳草留去轍。", "自顧塵滿纓，安能住深絕。"]'),
('778ebc5b-1dc0-4a4f-8fac-7874dc943e35','入谷馬上  其四','文同','宋','宋诗','song-poetry','','[]','群山護秦隴，轉去轉幽深。',48,'全唐诗/poet.song.26000.json','["群山護秦隴，轉去轉幽深。", "嵐氣重壓眼，秋光清徹心。", "憑鞍吟絕壁，解带坐高林。", "愛此巖泉好，臨流浣俗襟。"]'),
('693764e0-bfa2-40e6-8ddb-d1a588434a85','將至隴城縣','文同','宋','宋诗','song-poetry','','[]','數日山林間，嵬眼復傾耳。',60,'全唐诗/poet.song.26000.json','["數日山林間，嵬眼復傾耳。", "煩襟一以換，飄若方外士。", "今朝出谷口，已覺俗慮起。", "可惜身上衣，斑班遂塵滓。", "回首林下游，何年赤松子。"]'),
('c6e583e8-e3a7-4cee-88da-f58bd64eba60','宿雲屏山寺','文同','宋','宋诗','song-poetry','','[]','翠嶺聳雲端，巉巉走復蟠。',48,'全唐诗/poet.song.26000.json','["翠嶺聳雲端，巉巉走復蟠。", "客從塵外入，僧向畫中看。", "月上千巖碧，風生萬木寒。", "平明惜歸去，猶待一憑欄。"]'),
('53d920ab-27c7-4cef-94d0-ac8d2d0b01e4','寒食','文同','宋','宋诗','song-poetry','','[]','蜀客寓秦城，寒威怯夜生。',48,'全唐诗/poet.song.26000.json','["蜀客寓秦城，寒威怯夜生。", "火床功甚小，酒榼力何輕。", "月外天無色，霜中地有聲。", "王章龍具薄，數徹郡樓更。"]'),
('f5604cb8-e75a-4bd4-8289-df18c0d9a320','寄彥思時在長安言遊終南','文同','宋','宋诗','song-poetry','','[]','日日望車馬，君當何日還。',48,'全唐诗/poet.song.26000.json','["日日望車馬，君當何日還。", "談諧思衮衮，篇什愛關關。", "大道風埃惡，長河冰雪頑。", "相招早來此，擬欲問南山。"]'),
('192e9ff6-525d-4da1-bc57-d0e356b9d01b','寄景遜','文同','宋','宋诗','song-poetry','','[]','別後西城上，來須到日曛。',48,'全唐诗/poet.song.26000.json','["別後西城上，來須到日曛。", "目迎秦塞雁，心過隴山雲。", "寡合無如我，高懷少似君。", "相思只相望，徒爾託云云。"]'),
('563e004b-724a-44ca-8565-3a9c8bc03462','聽天台處士彈琴','文同','宋','宋诗','song-poetry','','[]','處士得琴要，誰師師自然。',48,'全唐诗/poet.song.26000.json','["處士得琴要，誰師師自然。", "爲言秋思好，因聽夜聲圓。", "耳出淫哇外，心摇寂寞前。", "廣陵君且止，不欲慢商絃。"]'),
('1704ecae-9d19-4f52-8202-336b760244c9','鳴玉亭籌筆之南','文同','宋','宋诗','song-poetry','','[]','層崖高百尺，亭即層崖下。',48,'全唐诗/poet.song.26000.json','["層崖高百尺，亭即層崖下。", "飛泉若環珮，萬縷當檐瀉。", "坐可脫赤熱，聽宜徹清夜。", "亭前樹膚剝，爲繫行人馬。"]'),
('13575560-7a6c-49a5-b9db-ec0ae70430bb','思歸鳥左右掩作','文同','宋','宋诗','song-poetry','','[]','峽中足啼鳥，醆鄒不可會。',48,'全唐诗/poet.song.26000.json','["峽中足啼鳥，醆鄒不可會。", "其道思歸者，雄鳴即雌對。", "前壑雲漸起，後山月已背。", "行人畏聞汝，一聲一心碎。"]'),
('5a4627e5-171a-45e9-af10-2d201e880fa6','夜發散關','文同','宋','宋诗','song-poetry','','[]','風吹古關口，萬木響如裂。',48,'全唐诗/poet.song.26000.json','["風吹古關口，萬木響如裂。", "凄凉異鄉客，騎馬關下月。", "板道霜鑿鑿，石梁溪咽咽。", "怪來曉寒重，御愛山頭雪。"]'),
('3fbfebad-446d-4f98-bf1c-36d6a130cc85','宿山寺','文同','宋','宋诗','song-poetry','','[]','高峰浮雲際，古寺高峰上。',48,'全唐诗/poet.song.26000.json','["高峰浮雲際，古寺高峰上。", "秋來已瀟灑，雨後益清曠。", "坐隨明月轉，吟伴寒蛩響。", "待曉出松關，幽襟謝嘉貺。"]'),
('34f7b5c6-726b-4bfa-9c72-e9ab8b131cee','中秋月  其一','文同','宋','宋诗','song-poetry','','[]','隔林灧灧生寒浪，倚漢岧岧數亂峰。',32,'全唐诗/poet.song.26000.json','["隔林灧灧生寒浪，倚漢岧岧數亂峰。", "記得舊山曾此夕，碧巖千尺坐高松。"]'),
('c9ac0bd4-7a14-4398-aff1-f2b8fda91bf2','中秋月  其二','文同','宋','宋诗','song-poetry','','[]','望外物容澄似水，坐中秋力凜如刀。',32,'全唐诗/poet.song.26000.json','["望外物容澄似水，坐中秋力凜如刀。", "此身直願乘雙翼，飛上三峰第一高。"]'),
('3d505a68-c33f-4c01-8060-92195603c0cb','二里溪濯足','文同','宋','宋诗','song-poetry','','[]','暑氣沉晚樹，晴光滿遥川。',48,'全唐诗/poet.song.26000.json','["暑氣沉晚樹，晴光滿遥川。", "下馬古道側，濯足清溪邊。", "勝事樂水石，幽懷託雲煙。", "還來振衣起，回首徒悒然。"]'),
('d20e9c35-754f-41bd-99a5-2299f4216733','稠桑見荆山','文同','宋','宋诗','song-poetry','','[]','萬嶺鬰叢叢，盤雲氣勢雄。',48,'全唐诗/poet.song.26000.json','["萬嶺鬰叢叢，盤雲氣勢雄。", "縱橫誰畫筆，屈折自屏風。", "倒樹出斷外，亂雲生掩中。", "無由更停馬，此意恨如蓬。"]'),
('e9561901-44fa-459b-8b06-39c509b8a255','白鶴寺北軒圍棋','文同','宋','宋诗','song-poetry','','[]','祇園隠城角，開軒極幽邃。',48,'全唐诗/poet.song.26000.json','["祇園隠城角，開軒極幽邃。", "日影轉不到，居常抱秋氣。", "余茲度炎燠，一局忘萬事。", "擾擾門外人，誰知此中意。"]'),
('5ee0ba52-2cb9-4d20-8a8e-fa030e6b1363','太常致齋閑書寺壁','文同','宋','宋诗','song-poetry','','[]','晚日微明弄雨餘，竹陰桐影共蕭疏。',32,'全唐诗/poet.song.26000.json','["晚日微明弄雨餘，竹陰桐影共蕭疏。", "旋移小榻中庭坐，讀盡扶桑太帝書。"]'),
('1223bfcf-a5cb-43fe-88fc-905e3124c72f','景遜以詩招棋因答','文同','宋','宋诗','song-poetry','','[]','待闕官期遠，僑居客思多。',24,'全唐诗/poet.song.26000.json','["待闕官期遠，僑居客思多。", "許時閑日月，願與局中磨。"]'),
('c180bb08-e3d6-42bb-9492-60ed104d78ce','初入二里','文同','宋','宋诗','song-poetry','','[]','樹色交山色，蟬聲雜水聲。',24,'全唐诗/poet.song.26000.json','["樹色交山色，蟬聲雜水聲。", "客懷殊不倦，信馬此間行。"]'),
('7d497b6a-daa6-4ee6-835c-e75adf890499','又送劉著作','文同','宋','宋诗','song-poetry','','[]','北地戎馬後，凋殘今幾年。',48,'全唐诗/poet.song.26000.json','["北地戎馬後，凋殘今幾年。", "邊民此天幸，縣令若君賢。", "况自儲蓄久，定知摩撫全。", "好須圖善政，能爲作詩傳。"]'),
('0857b7d9-6224-4e10-a0d4-f12c130eea77','送張樸翁歸盩厔  其一','文同','宋','宋诗','song-poetry','','[]','一覺落天夢，遂吟招隠詩。',48,'全唐诗/poet.song.26000.json','["一覺落天夢，遂吟招隠詩。", "携家異鄉去，變服散人爲。", "郿塢雲開後，圭峰月上時。", "清秋此高興，琴酒問同誰。"]'),
('ff893d43-28f3-4c52-a3a9-d2c1fc4aea07','送張樸翁歸盩厔  其二','文同','宋','宋诗','song-poetry','','[]','山曲水曲處，其間皆美田。',48,'全唐诗/poet.song.26000.json','["山曲水曲處，其間皆美田。", "夫君別桑梓，此地卜林泉。", "壯歲可立事，明時方尚賢。", "何當再就詔，便忍說終焉。"]'),
('09b42906-022a-478a-bc82-805171151f4b','宋復古度支晚川晴雪','文同','宋','宋诗','song-poetry','','[]','霽色變雲林，寒光混烟水。',24,'全唐诗/poet.song.26000.json','["霽色變雲林，寒光混烟水。", "遥山定何處，渺漭纔可指。"]'),
('597cad09-1c62-4112-8e49-c34e01e32c3a','早秋山水硯屏','文同','宋','宋诗','song-poetry','','[]','晚靄隔遠岫，秋容入平林。',24,'全唐诗/poet.song.26000.json','["晚靄隔遠岫，秋容入平林。", "方素僅盈尺，岩谷能許深。"]'),
('1d748c91-8ec7-4a9b-b754-9d3773676028','寇君玉郎中大蟹','文同','宋','宋诗','song-poetry','','[]','蟹性最難圖，生意在螯跪。',24,'全唐诗/poet.song.26000.json','["蟹性最難圖，生意在螯跪。", "伊人得之妙，郭索不能已。"]'),
('0cdc2c41-9a25-43f8-8adf-6e26b187e2fb','小蟹','文同','宋','宋诗','song-poetry','','[]','骨甲與支節，解絡尤精研。',24,'全唐诗/poet.song.26000.json','["骨甲與支節，解絡尤精研。", "手足雖爾多，能使如一錢。"]'),
('effe2585-a480-4a78-b968-d7300ade8bcb','黄筌鵲雛','文同','宋','宋诗','song-poetry','','[]','短羽已褵褷，弱脛方屴岌。',24,'全唐诗/poet.song.26000.json','["短羽已褵褷，弱脛方屴岌。", "母也向何處，開口猶仰食。"]'),
('ce368fdf-fa51-41d3-b6e9-0702a7f3faf5','滕昌祐芙蓉','文同','宋','宋诗','song-poetry','','[]','雙幹發寒葩，一枿立紋羽。',24,'全唐诗/poet.song.26000.json','["雙幹發寒葩，一枿立紋羽。", "欲品精妙人，君當二三數。"]'),
('16ae3a3b-0674-43e1-a114-85ab3a54ad75','毛老鬥牛','文同','宋','宋诗','song-poetry','','[]','牛牛爾何爭，於此輒鬥怒。',48,'全唐诗/poet.song.26000.json','["牛牛爾何爭，於此輒鬥怒。", "長鞭鬧兒童，大炬走翁嫗。", "蒼㺏八九子，駭立各四顧。", "何時解角歸，茅舍江村暮。"]'),
('1fb7b453-8be6-4254-80b1-b85b64a8d72d','鄧隠老木寒牛','文同','宋','宋诗','song-poetry','','[]','蒼崖稜層草芊綿，巨木半死生枯烟。',32,'全唐诗/poet.song.26000.json','["蒼崖稜層草芊綿，巨木半死生枯烟。", "羸牛日晚已噍草，稚子天寒猶打錢。"]'),
('ab8c5858-578f-46cd-9a9f-e15c5628f021','許道寧寒林','文同','宋','宋诗','song-poetry','','[]','許生雖學李營丘，墨路縱橫多自出。',32,'全唐诗/poet.song.26000.json','["許生雖學李營丘，墨路縱橫多自出。", "交柯揮霍裴旻劍，亂蔓淋漓張曉筆。"]'),
('f8bbf430-845e-4d11-b84d-bd949c539153','易元吉抱櫟狨','文同','宋','宋诗','song-poetry','','[]','老櫟抱擁腫，金狨立鬅鬙。',24,'全唐诗/poet.song.26000.json','["老櫟抱擁腫，金狨立鬅鬙。", "當年隴山道，似此見危層。"]'),
('7c5a7b29-d241-45bd-b28a-ddd625349ba6','引子獐','文同','宋','宋诗','song-poetry','','[]','蒼獐引黄麑，雙耳誰驚立。',24,'全唐诗/poet.song.26000.json','["蒼獐引黄麑，雙耳誰驚立。", "高原想新霽，町疃見行迹。"]'),
('7f15bc57-6809-4add-8365-255542f7a1cd','崔白敗荷折葦寒鷺','文同','宋','宋诗','song-poetry','','[]','疏葦雨中老，亂荷霜外凋。',24,'全唐诗/poet.song.26000.json','["疏葦雨中老，亂荷霜外凋。", "多情惟白鳥，常此伴蕭條。"]'),
('fc5cdb0e-e28c-407f-86c1-401bbcf93e11','孫太古辟支迦佛','文同','宋','宋诗','song-poetry','','[]','調御出火起正念，薩埵捧香生信心。',32,'全唐诗/poet.song.26000.json','["調御出火起正念，薩埵捧香生信心。", "二士之意在筆外，彼太古者何情深。"]'),
('4fb1154b-6e65-4a37-a94d-8b462e78b564','許中正捕龍雷','文同','宋','宋诗','song-poetry','','[]','彼龍胡爲被天謫，不肯爲天行雨澤。',104,'全唐诗/poet.song.26000.json','["彼龍胡爲被天謫，不肯爲天行雨澤。", "天敕雷公恣搜索，龍藏何所忽爾獲。", "提之滿空若曳帛，雹風電火相卷射。", "雷張兩翅但拍拍，首尾挽之足雙磔。", "龍力與雷固不敵，雷轉威怒龍褫魄，須臾定見肝胃拆。", "萬力千氣凡幾畫，斯人斯品入神格。"]'),
('33c1c736-7b17-46e0-b63d-c27a58f7cc5d','范寬雪中孤峰','文同','宋','宋诗','song-poetry','','[]','大雪灑天表，孤峰入雲端。',24,'全唐诗/poet.song.26000.json','["大雪灑天表，孤峰入雲端。", "何人向漁艇，擁褐對巑岏。"]'),
('39927a08-00ce-45c5-9a45-cae3293c3c38','晚秋烟波','文同','宋','宋诗','song-poetry','','[]','直於一丈素，寫盡千里景。',44,'全唐诗/poet.song.26000.json','["直於一丈素，寫盡千里景。", "雲山杳杳已成秋，烟水漻漻方入暝。", "君應無心得此畫，我豈有言能爾詠。"]'),
('3d24fff8-ea9d-43d2-9451-97de4363ef22','春山','文同','宋','宋诗','song-poetry','','[]','岡原草木秀，溪谷雲霞媚。',24,'全唐诗/poet.song.26000.json','["岡原草木秀，溪谷雲霞媚。", "君筆誰所傳，獨解吐和氣。"]'),
('431aa871-7cea-41a1-adb4-b583457389af','秋山','文同','宋','宋诗','song-poetry','','[]','孤峰露蒼骨，疏木聳堅幹。',24,'全唐诗/poet.song.26000.json','["孤峰露蒼骨，疏木聳堅幹。", "高堂挂虛壁，爽氣來不斷。"]'),
('58213c20-d439-4f4a-bb82-acc44ea4b72a','梁信羯鼓小圖','文同','宋','宋诗','song-poetry','','[]','高梧間垂楊，玉宇極清邃。',96,'全唐诗/poet.song.26000.json','["高梧間垂楊，玉宇極清邃。", "三郎當殿坐，左右擁佳麗。", "氍毹近香案，蹲獸吐碧穗。", "寶几承畫控，繽紛交綵袂。", "花奴卷雙袖，俯立前奏技。", "君王顧之笑，軒廡動和氣。", "誰謂一尺素，寫遍天上意。", "聽者定何如，觀之猶解穢。"]'),
('8be7d989-cc16-4a58-862b-b237f7b6f153','蒲生鍾馗','文同','宋','宋诗','song-poetry','','[]','寒風酸號月慘苦，梟飛狐鳴滿墟墓。',288,'全唐诗/poet.song.26000.json','["寒風酸號月慘苦，梟飛狐鳴滿墟墓。", "叢棘亂礓翳野霧，古社禿剝倒枯樹。", "下有三鬼相嘯聚，初行誰家作疰忤。", "痛熱腫癢快嘔吐，塞噎咽喉脹臍肚。", "呼巫召覡使呪詛，翁驚嫗忙設賽具。", "茅盤草舡置五路，飯盂炙串狼籍布。", "相共收歛各執去，方此危坐歠且哺。", "忽爾相視生畏怖，有神傑然駕巨牯。", "前訶後擁役二豎，此神噉鬼充旦暮。", "其腹尚餒色躁怒，鬼遥見之悉失措。", "竄匿不暇相告諭，酒傾肉落雜穢污。", "魄魂飛蕩身偃仆，一入木底只四據。", "一尚把盞愕以顧，一自隠蔽捩眥覷。", "神用氣攝縛束固，前死入吻無十步。", "計之嚼嚙或味飫，蒲生胡爲適爾遇。", "畫之滿卷無一誤，筆墨醜怪實可懼。", "持以贈余子何故，摇手不取一錢賂。", "他日乞詩者尤屢，試爲言之寫其故。"]'),
('1a34cd99-fbfa-4d5f-baca-8bc6f984bb6d','折楊柳','文同','宋','宋诗','song-poetry','','[]','垂楊百尺臨池水，風定烟濃盤不起。',32,'全唐诗/poet.song.26000.json','["垂楊百尺臨池水，風定烟濃盤不起。", "欲折長條寄遠行，想到君邊已憔悴。"]'),
('8770631a-1f26-4b5c-b9ed-87f534cd1537','仁宗皇帝挽詩十首  其一','文同','宋','宋诗','song-poetry','','[]','緒業承三聖，規模盛一王。',48,'全唐诗/poet.song.26000.json','["緒業承三聖，規模盛一王。", "朝廷周禮樂，庠序漢文章。", "殊俗皆歸往，蒸民盡樂康。", "帝功如此大，宜享壽無疆。"]'),
('2e2d5964-0716-4c6f-8cc4-120e19b0a6a1','仁宗皇帝挽詩十首  其二','文同','宋','宋诗','song-poetry','','[]','徇速承王後，聰明復辟初。',48,'全唐诗/poet.song.26000.json','["徇速承王後，聰明復辟初。", "恩波同海浸，刑網比天疏。", "屢有搜賢詔，曾無諫獵書。", "惟餘封禪事，應恨缺蒲車。"]'),
('51939462-953d-4fb6-8e95-2544623cd63d','仁宗皇帝挽詩十首  其三','文同','宋','宋诗','song-poetry','','[]','求治親垂詔，觀文自著圖。',48,'全唐诗/poet.song.26000.json','["求治親垂詔，觀文自著圖。", "何曾憑喜怒，未省蔽讒諛。", "塵世留徽號，烟霄返舊都。", "悠悠增筴驗，難問鬼臾區。"]'),
('e5a0d885-75b6-4090-acd9-aa83b62dd8aa','仁宗皇帝挽詩十首  其四','文同','宋','宋诗','song-poetry','','[]','寶輅嬉遊少，珠宮藝學優。',48,'全唐诗/poet.song.26000.json','["寶輅嬉遊少，珠宮藝學優。", "仙毫媚風帛，睿藻煥星鈎。", "天極推神曆，兵防演秘謀。", "飈流今已矣，長共糓林秋。"]'),
('32a315c2-682f-4fdf-b44f-029e908ee13b','仁宗皇帝挽詩十首  其五','文同','宋','宋诗','song-poetry','','[]','政殿咨丞弼，經筵引俊髦。',48,'全唐诗/poet.song.26000.json','["政殿咨丞弼，經筵引俊髦。", "未嘗耽逸樂，終是過焦勞。", "歸路三山遠，遺臺萬古高。", "小臣無分去，定擁墮髯號。"]'),
('629f70f3-958d-40a5-9ba7-95367bd01614','仁宗皇帝挽詩十首  其六','文同','宋','宋诗','song-poetry','','[]','神鼎猶烘藥，夷槃已實冰。',48,'全唐诗/poet.song.26000.json','["神鼎猶烘藥，夷槃已實冰。", "留恩均器服，下詔約山陵。", "影殿虛綈几，皇堂掩漆燈。", "蕭蕭柏城下，空有暮雲凝。"]'),
('eed149c4-90d6-4604-908f-285a98cabcb3','仁宗皇帝挽詩十首  其七','文同','宋','宋诗','song-poetry','','[]','浮世期云盡，清都位欲傳。',48,'全唐诗/poet.song.26000.json','["浮世期云盡，清都位欲傳。", "秉珪徒請命，脫躧遂登仙。", "遺澤流天下，重光照柩前。", "幾時來甲觀，更待一千年。"]'),
('4e85ff1a-af60-4a39-b6f5-53d41bb61de8','仁宗皇帝挽詩十首  其八','文同','宋','宋诗','song-poetry','','[]','被衮纔憑几，躋階忽受同。',48,'全唐诗/poet.song.26000.json','["被衮纔憑几，躋階忽受同。", "哀文鋪帝業，謚冊講仁功。", "竭蹷趨群后，號咷動兩宮。", "銘旌來鞏洛，萬里卷悲風。"]'),
('5c79c98e-e233-4e2d-a76d-ee270d72b92a','仁宗皇帝挽詩十首  其九','文同','宋','宋诗','song-poetry','','[]','幡翣離三殿，簫笳接兩都。',48,'全唐诗/poet.song.26000.json','["幡翣離三殿，簫笳接兩都。", "堯殂如考妣，禹葬省人徒。", "豈並遊韶石，應同去鼎湖。", "愁聞下竹使，海外走哀符。"]'),
('5bd9fd4c-06ad-413f-bfe6-562ebb410de4','仁宗皇帝挽詩十首  其一○','文同','宋','宋诗','song-poetry','','[]','史祝周壇日，人憂杞國時。',48,'全唐诗/poet.song.26000.json','["史祝周壇日，人憂杞國時。", "飲池無善效，頮水有遺辭。", "仙仗朝三后，蕃儀集四夷。", "從今河與洛，長瀉鳳臺悲。"]'),
('d862c299-ac03-4f72-bed8-217912bbcd0c','正肅吳公挽詩  其一','文同','宋','宋诗','song-poetry','','[]','虎節歸兵日，麟符命使年。',48,'全唐诗/poet.song.26000.json','["虎節歸兵日，麟符命使年。", "帝將還二府，人已哭三川。", "清議誰違者，高風自凜然。", "佳城空萬古，一壙掩寒烟。"]'),
('04952778-7454-4276-8a58-23cd30d16878','正肅吳公挽詩  其二','文同','宋','宋诗','song-poetry','','[]','晁董文章重，夔龍德業尊。',48,'全唐诗/poet.song.26000.json','["晁董文章重，夔龍德業尊。", "簡編成故事，穹壤與長存。", "風旐飄寒陌，霜笳咽晚原。", "誰人碑有道，應不愧斯言。"]'),
('055961c1-0bf1-4655-93c8-15044295159b','張中允先生挽詩三首  其一','文同','宋','宋诗','song-poetry','','[]','善頌堂中客，華嚴會裏人。',48,'全唐诗/poet.song.26000.json','["善頌堂中客，華嚴會裏人。", "生爲天所祐，沒與佛相親。", "祖送逾千兩，哀號動四鄰。", "宜祠瑞筠社，永配蜀江神。"]'),
('7b25cda1-a0a7-4205-821b-7d8a4ec6f572','張中允先生挽詩三首  其二','文同','宋','宋诗','song-poetry','','[]','鄉校咨橅範，閨門慕典刑。',48,'全唐诗/poet.song.26000.json','["鄉校咨橅範，閨門慕典刑。", "愛看高士傳，欲注凈名經。", "素節標家牒，芬情勒冢銘。", "近誰瞻碧落，應見少微星。"]'),
('aedf0992-4661-42d7-a077-42d654a22fbc','張中允先生挽詩三首  其三','文同','宋','宋诗','song-poetry','','[]','文行俱高妙，聲名五十秋。',48,'全唐诗/poet.song.26000.json','["文行俱高妙，聲名五十秋。", "君恩來草澤，子舍上瀛洲。", "有相身須盡，無誰淚不流。", "庭前雲蓋石，長伴影堂愁。"]'),
('3c0b8c97-0547-418b-a1de-a1baae0de189','張思孺秘校挽詩二首  其一','文同','宋','宋诗','song-poetry','','[]','昔在天彭郡，僑居過一冬。',48,'全唐诗/poet.song.26000.json','["昔在天彭郡，僑居過一冬。", "感君常見訪，無日不相從。", "遠寺携棋局，高亭把酒鍾。", "誰知三載後，孤冢列新松。"]'),
('24fab9af-1255-4326-8afc-2e01d3ee6574','張思孺秘校挽詩二首  其二','文同','宋','宋诗','song-poetry','','[]','人前常奉詫，張也好堂堂。',48,'全唐诗/poet.song.26000.json','["人前常奉詫，張也好堂堂。", "處衆謙和甚，居官志力强。", "當時君壯健，在座我蒼浪。", "今日翻相哭，無言問彼蒼。"]'),
('6df8aa75-b8e8-4b33-afad-61a68321d3d8','呂惠穆挽詩四首  其一','文同','宋','宋诗','song-poetry','','[]','文靖登庸久，朝廷政教隆。',48,'全唐诗/poet.song.26000.json','["文靖登庸久，朝廷政教隆。", "相門無或議，子舍有如公。", "恩澤非徼幸，官榮悉治功。", "至今清論在，常滿縉紳中。"]'),
('6110270c-4116-417b-8408-3cfb9fca09a4','呂惠穆挽詩四首  其二','文同','宋','宋诗','song-poetry','','[]','帝御皇圖後，公居右府時。',48,'全唐诗/poet.song.26000.json','["帝御皇圖後，公居右府時。", "開陳諸議論，感發止嗟咨。", "自此傾宸眷，方將正宰司。", "胡爲便淪謝，天意固難知。"]'),
('390a7097-83f7-405f-b5be-064e0c2a2f30','呂惠穆挽詩四首  其三','文同','宋','宋诗','song-poetry','','[]','憶在南邛日，家君此忽亡。',48,'全唐诗/poet.song.26000.json','["憶在南邛日，家君此忽亡。", "公時帥本道，力爲濟歸喪。", "賤息將何報，深恩不可忘。", "如今每念及，惟有淚浪浪。"]'),
('94842721-03cd-4bff-9439-4116dd105dd2','呂惠穆挽詩四首  其四','文同','宋','宋诗','song-poetry','','[]','自出公門下，常蒙禮意勤。',48,'全唐诗/poet.song.26000.json','["自出公門下，常蒙禮意勤。", "相看如子姓，交政爲郎君。", "每望中書入，俄驚遠訃聞。", "何時高冢上，永日哭寒雲。"]'),
('675b56d4-7679-47f2-b585-1802e3bce575','張林宗司勳挽詩三首  其一','文同','宋','宋诗','song-poetry','','[]','巫峽乘軺去，涪江擁節還。',48,'全唐诗/poet.song.26000.json','["巫峽乘軺去，涪江擁節還。", "方來赴京兆，又出領潼關。", "髀肉川涂瘦，顛毛案牘斑。", "音容今遂已，清血爲公潸。"]'),
('f05bf999-1498-46f1-9e4f-ff86d96cbf70','張林宗司勳挽詩三首  其二','文同','宋','宋诗','song-poetry','','[]','候騎排弓箙，牙門換戟衣。',48,'全唐诗/poet.song.26000.json','["候騎排弓箙，牙門換戟衣。", "使麾方報入，神柩已云歸。", "關吏驚來往，鄉人嘆是非。", "生平幽石在，誰爲刻珠璣。"]'),
('877f0c83-a1f8-438a-b599-febfbef735b2','張林宗司勳挽詩三首  其三','文同','宋','宋诗','song-poetry','','[]','素節鄉評重，清芬世閱傳。',48,'全唐诗/poet.song.26000.json','["素節鄉評重，清芬世閱傳。", "謝家兒姪盛，穆宅弟兄賢。", "展矣茲良士，嗟乎不永年。", "西風寄哀調，願爲唱新阡。"]'),
('8e9f92a6-3079-4c43-ba92-a614ff3a7268','張道宗比部挽詩三首  其一','文同','宋','宋诗','song-poetry','','[]','學富詞章妙，才高志力强。',48,'全唐诗/poet.song.26000.json','["學富詞章妙，才高志力强。", "帝方知可用，官欲漸難量。", "始得西原使，纔終右省郎。", "念公今止此，無語問蒼蒼。"]'),
('e905a8ff-40e8-49dc-92e2-99d232938fd9','張道宗比部挽詩三首  其二','文同','宋','宋诗','song-poetry','','[]','見說關西訃，危腸已似刀。',48,'全唐诗/poet.song.26000.json','["見說關西訃，危腸已似刀。", "撫膺成一慟，復魄遂三號。", "舊館州名桂，新居里曰蒿。", "九泉休負恨，蘭玉滿兒曹。"]'),
('2ab2fabe-6bae-4e9d-ba6d-f6b92c6e77d1','張道宗比部挽詩三首  其三','文同','宋','宋诗','song-poetry','','[]','憶在南岐日，于今十二年。',48,'全唐诗/poet.song.26000.json','["憶在南岐日，于今十二年。", "宦途聊邂逅，賓館重留連。", "正喜謀黄峒，俄驚葬圃田。", "無由執行紼，徒爾淚如泉。"]'),
('46bce532-b2a7-4130-9240-782355187bce','石左藏挽詩二首  其一','文同','宋','宋诗','song-poetry','','[]','世澤傳清範，戎韜演秘謀。',48,'全唐诗/poet.song.26000.json','["世澤傳清範，戎韜演秘謀。", "雄藩未賜節，大壑忽移舟。", "謝氏胡床在，羊公羽扇收。", "光華歸令子，何恨掩泉丘。"]'),
('275c000b-84a6-4be3-9244-22fae435f1ab','石左藏挽詩二首  其二','文同','宋','宋诗','song-poetry','','[]','昔年陪宴上崏臺，一聽新歌一舉杯。',32,'全唐诗/poet.song.26000.json','["昔年陪宴上崏臺，一聽新歌一舉杯。", "此會如今嗟已矣，擬將何調寄餘哀。"]'),
('c266cc96-c8d1-474c-ab80-f8d192bf37fc','邛州賞豐亭','文同','宋','宋诗','song-poetry','','[]','人之創亭意，大率繇己便。',180,'全唐诗/poet.song.26000.json','["人之創亭意，大率繇己便。", "夫何我公者，所作異他見。", "臨邛郡東北，井井畫群甸。", "其民喜施力，無歲不登衍。", "公因到城上，有此多稼羨。", "而云彼嘉穀，誠我民所擅。", "如其每用此，豈不鄉土戀。", "伊我牧其衆，胡爾懼流轉。", "遂茲謀棟宇，顯顯向一面。", "題爲賞豐字，義不止營繕。", "常時命僚侶，于時歌管薦。", "高談詫上瑞，衮衮莫之倦。", "擎酒揖大野，指顧一欣忭。", "田夫各相語，我輩誰曰賤。", "太守亦爲我，今日又張讌。"]'),
('1bdc4fe7-587c-4d57-8b40-4cf45446c9e5','邛州倅','文同','宋','宋诗','song-poetry','','[]','將欲言治人，必先由正身。',288,'全唐诗/poet.song.26000.json','["將欲言治人，必先由正身。", "身正人自治，此化行如神。", "總總群聖書，論說尤諄諄。", "後賢守爲法，不敢忘逡巡。", "有欲著其迹，更假他物伸。", "或取几杖明，或用盤盂陳。", "或則銘於座，或則書於紳。", "此皆貪道者，欲己日夕親。", "涵泳既滋久，盛德光璘璘。", "魯侯相門子，佩義而服仁。", "來乘別駕輿，齒髪何青春。", "開口議政事，條件皆有倫。", "春露與秋霜，畏愛其吏民。", "尚懼有片缺，不使其質純。", "乃於廳事側，開軒承甲寅。", "題曰三省堂，大構高榜新。", "地古物象野，水竹清衣巾。", "公暇每居此，寂嘿如隠淪。", "冥心以自觀，外揣復內循。", "一有所不逮，補綻無纖塵。", "既已自作詩，文理相彬彬。", "宛轉示明戒，欲使風俗淳。", "愚重侯所存，再拜無辭頻。", "待己固如此，賢哉君子鄰。"]'),
('b42b06a9-8843-485f-9cba-8c93c535aa5f','題何靖山人隠居二首  其一','文同','宋','宋诗','song-poetry','','[]','錦屏山下何夫子，鐵带麻衣真古人。',64,'全唐诗/poet.song.26000.json','["錦屏山下何夫子，鐵带麻衣真古人。", "苦學詩來偷鬢老，樂爲儒後却家貧。", "酒中酌月江村夜，琴上彈風鶴寺春。", "君已歸尋舊閑味，肯騎肥馬入紅塵。"]'),
('1a50d737-6f48-4d86-b949-2cbe7de8c9d4','題何靖山人隠居二首  其二','文同','宋','宋诗','song-poetry','','[]','因循失計下青山，却恨谿雲占斷閑。',64,'全唐诗/poet.song.26000.json','["因循失計下青山，却恨谿雲占斷閑。", "黄卷聖賢忻對語，青雲岐路祗低顔。", "月牆槐影侵階暗，雨檻秋花滿目斑。", "自愛蕭條真吏隠，心清不累有無間。"]'),
('24869232-6659-4232-be37-5a389e9b25a2','題兜率寺','文同','宋','宋诗','song-poetry','','[]','簿領迷人喜暫閑，聊尋古寺陟孤巒。',64,'全唐诗/poet.song.26000.json','["簿領迷人喜暫閑，聊尋古寺陟孤巒。", "柏藏一徑中間窄，雲斂千峰四面寬。", "遠目已將飛鳥過，寸心更乞老僧安。", "若爲借得禪房宿，卧看龕燈一點殘。"]'),
('8490b740-893e-4e02-8160-2912b6efdf40','題鳳凰山後巖','文同','宋','宋诗','song-poetry','','[]','此景又奇絕，半空生曲欄。',48,'全唐诗/poet.song.26000.json','["此景又奇絕，半空生曲欄。", "蜀塵隨眼斷，蕃雪滿襟寒。", "澗下雨聲急，巖頭雲色乾。", "歸鞍休報晚，吾待且盤桓。"]'),
('776293e1-623c-41a8-9d59-7583d9bd8383','子瞻戲子由依韵奉和','文同','宋','宋诗','song-poetry','','[]','子由在陳窮於丘，正若淺港橫巨舟。',240,'全唐诗/poet.song.26000.json','["子由在陳窮於丘，正若淺港橫巨舟。", "每朝升堂講書罷，緊合兩眼深埋頭。", "才名至高位至下，此事自屬他人羞。", "猶勝俁俁彼賢者，手把翟籥隨群優。", "岌如老鶴立海上，退避不與鶖鶬遊。", "文章豈肯用一律，獨取無間有神術。", "所蓄未嘗資己身，搰搰恰如蜂聚蜜。", "有時七日不火食，支體雖羸心不屈。", "陵陽謬守卑且勞，馬前空愧持旌旄。", "平生讀書若奊詬，老大下筆侵離騷。", "貧且賤焉真可耻，欲撻群邪無尺箠。", "安得來親絳帳旁，日與諸生供唯唯。", "須知道義故可樂，莫問功名能得幾。", "君子道遠不計程，死而後已方成名。", "千鈞一羽不須校，女子小人知重輕。"]'),
('8cf92330-9fe7-4538-b901-d24638871f4e','依韵和子瞻遊孤山','文同','宋','宋诗','song-poetry','','[]','跨明越，壓蘇湖，錢塘風物天下無。',160,'全唐诗/poet.song.26000.json','["跨明越，壓蘇湖，錢塘風物天下無。", "玉峰孱顔石穿漏，雪海浩蕩潮喧呼。", "舊嘗持之詫吾孥，會挈爾去相與娛。", "宦遊若不來此都，腰間綵組徒云紆。", "子瞻鳳咮新結廬，日哦其間興不孤。", "平生美志自償足，休問滿眼生萑蒲。", "有物可比中鄙夫，蜉蝣朝生死於晡。", "公攘顯奪入胠篋，驕穉無乃非良圖。", "子瞻之樂固有餘，辨說是非從魯蘧。", "我今有索君勿逋，歸日好景爲我摹。"]'),
('241e9952-50e8-4eb3-a5ea-e133a684ca34','再和','文同','宋','宋诗','song-poetry','','[]','問子瞻，何江湖，乃心魏闕君豈無。',160,'全唐诗/poet.song.26000.json','["問子瞻，何江湖，乃心魏闕君豈無。", "胡爲放浪檢束外，日與隠者相招呼。", "籃輿往往從以孥，靈運石壁無此娛。", "窮深極險興未已，豈復更憚梯登紆。", "過客休誇衡與廬，天下此景君勿孤。", "欲將文字寫物象，當截無限春江蒲。", "登高能賦屬大夫，遊覽未厭嗟已晡。", "安得世上有絕筆，盡取君詩妝在圖。", "此身之外何贏餘，成然而寐其覺蘧。", "請看湖上人名逋，此子形相誰解摹。"]'),
('d7634415-a65a-4e6a-a983-2261388f0acc','和陳基載大雨','文同','宋','宋诗','song-poetry','','[]','黕黕雲如涌，淙淙雨若傾。',48,'全唐诗/poet.song.26000.json','["黕黕雲如涌，淙淙雨若傾。", "驟翻銀漢濁，勻灑玉繩明。", "雷怒無停勢，風豪有遏聲。", "危樓已初伏，猶謂裌衣輕。"]'),
('f3d3b338-174e-4d69-a954-f413ef6a291f','和張推官荔枝','文同','宋','宋诗','song-poetry','','[]','長嗟珍果滯遐方，好種華林奉帝王。',64,'全唐诗/poet.song.26000.json','["長嗟珍果滯遐方，好種華林奉帝王。", "夏簟滿風羅秀色，曉梯乘露摘新香。", "潑霞乍染愁將變，烹玉纔凝忍更嘗。", "正在臨邛病痟甚，忽蒙佳惠敢相忘。"]'),
('609be6e1-7e1f-4868-a8b7-8988498f1a8c','贈李仲祥道士','文同','宋','宋诗','song-poetry','','[]','不見先生已數年，相思惟是誦嘉篇。',64,'全唐诗/poet.song.26000.json','["不見先生已數年，相思惟是誦嘉篇。", "因來守郡空山裏，又喜通名畫戟前。", "抵掌劇談猶矍鑠，堆胸豪氣尚蜿延。", "近聞買得鵝池住，且向人間作地仙。"]'),
('d2925ed6-e0cb-45b9-bbe5-f02a961a533f','賀陳基載重陽日','文同','宋','宋诗','song-poetry','','[]','文酒尋常不厭求，坐中須得賈長頭。',64,'全唐诗/poet.song.26000.json','["文酒尋常不厭求，坐中須得賈長頭。", "幸逢九日稱佳節，宜對三嵎賞素秋。", "歲月但看隨葉落，利名當信與雲浮。", "憑君且學龍山飲，一醉能令萬事休。"]'),
('844b46d8-66b9-4bc5-a595-3f32ce59e8b1','寄張郎中','文同','宋','宋诗','song-poetry','','[]','常媿無才動有權，十年鄉里但留連。',64,'全唐诗/poet.song.26000.json','["常媿無才動有權，十年鄉里但留連。", "養成答颯人應笑，學得支離自謂賢。", "三館舊遊層漢上，一麾今守亂峰前。", "幸逢別駕如張軌，免對蘇章說二天。"]'),
('338a439a-b167-466a-bcc9-c2a7f492e543','遊閑居院','文同','宋','宋诗','song-poetry','','[]','乘暇訪閑居，臨行欲所須。',24,'全唐诗/poet.song.26000.json','["乘暇訪閑居，臨行欲所須。", "急沽龍口酒，忙打佛前魚。"]'),
('8d347abf-f329-483e-95ae-ac3929fe3442','大元觀題壁','文同','宋','宋诗','song-poetry','','[]','三十窮男子，其如膽氣成。',48,'全唐诗/poet.song.26000.json','["三十窮男子，其如膽氣成。", "鴻毛在鄉里，驥足本乾坤。", "周孔爲逢揖，軻雄自吐吞。", "平生所懷抱，應共帝王論。"]'),
('0d9a480e-0fa8-44e0-a319-ded0b7f2fb1f','游石門詩','文同','宋','宋诗','song-poetry','','[]','凌城走馬過花村，先玩玉盆到石門。',32,'全唐诗/poet.song.26000.json','["凌城走馬過花村，先玩玉盆到石門。", "細想張良燒斷處，巖前佇立欲銷魂。"]'),
('b93ee00d-4971-4d0e-8f2e-e8b637ca8116','句  其一','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','北客若來休問事，西湖雖好莫吟詩。',16,'全唐诗/poet.song.26000.json','["北客若來休問事，西湖雖好莫吟詩。"]'),
('ccd9b535-51a8-4882-bb00-e13c05625ccd','句  其二','文同','宋','宋诗','song-poetry','','[]','擬將一段鵝溪絹，掃取寒梢萬丈長。',16,'全唐诗/poet.song.26000.json','["擬將一段鵝溪絹，掃取寒梢萬丈長。"]'),
('6f879d82-b906-4a09-b782-d5b5b0700223','句  其三','文同','宋','宋诗','song-poetry','','[]','興來雷出土，萬籜起崖谷。',12,'全唐诗/poet.song.26000.json','["興來雷出土，萬籜起崖谷。"]'),
('e86eac7d-c0c6-4663-8dde-cf91810d4c34','句  其四','文同','宋','宋诗','song-poetry','','[]','來觀古柏丹淵客。',8,'全唐诗/poet.song.26000.json','["來觀古柏丹淵客。"]'),
('8591be0f-6232-4c6a-85b6-73bb9052561e','遊連山涌泉觀次文與可韵','楊闢之','宋','宋诗','song-poetry','','[]','雙旗曉出遠遊山，遍覽幽奇日日閒。',32,'全唐诗/poet.song.26000.json','["雙旗曉出遠遊山，遍覽幽奇日日閒。", "幕下淵雲陪後乘，馬蹄歸去月華間。"]'),
('cf489e16-38ea-4f70-acd7-73589e8ebdc8','遊連山涌泉觀次文與可韵','任道','宋','宋诗','song-poetry','','[]','繚繞澄江面面山，使君來與吏民閒。',32,'全唐诗/poet.song.26000.json','["繚繞澄江面面山，使君來與吏民閒。", "可堪歸騎臨晴陌，散盡遊人夕照間。"]'),
('399b4f17-8415-4ddf-bcab-5fb0f380e09d','遊連山涌泉觀次文與可韵','麻臺文','宋','宋诗','song-poetry','','[]','得得朱輪到此山，遲留共愛此幽閒。',32,'全唐诗/poet.song.26000.json','["得得朱輪到此山，遲留共愛此幽閒。", "人生勝事惟行樂，休問黄粱一爨間。"]'),
('3351fa9a-cfc3-4815-915f-64fbc36c3e62','句','趙成伯','宋','宋诗','song-poetry','','[]','只有當年燕子樓。',8,'全唐诗/poet.song.26000.json','["只有當年燕子樓。"]'),
('2357fcce-9e15-4b9e-b154-4b1beccd73d6','賦新繁周表權如詔亭','任伋','宋','宋诗','song-poetry','','[]','盡道君家教育深，義方高作靄儒林。',64,'全唐诗/poet.song.26000.json','["盡道君家教育深，義方高作靄儒林。", "綵衣已是真郎貴，紫詔方旌昔日心。", "鯉每趨庭惟獨立，鶴常和子自鳴陰。", "此之能事人方信，勝積籝中十萬金。"]'),
('23143f74-c180-4edc-9f5d-91e6f8dea563','遊安樂山','任伋','宋','宋诗','song-poetry','','[]','安樂溪上峰，萬木森翠羽。',60,'全唐诗/poet.song.26000.json','["安樂溪上峰，萬木森翠羽。", "孤撐切天心，橫拓壓坤股。", "氣勢西吞夷，光芒南定楚。", "雲泉出石竇，淋漓灑玉宇。", "烟蘿纏林梢，摇拽垂翠組。"]'),
('60ff0de3-9e81-401d-b77c-536dd1966761','句','任伋','宋','宋诗','song-poetry','','[]','榆錢莫買城南春，柳絲莫繫城中人。',21,'全唐诗/poet.song.26000.json','["榆錢莫買城南春，柳絲莫繫城中人。", "何修別墅。"]'),
('0e8e421e-129c-4550-8a07-0b5f2b22c334','送程給事知越州','虞大熙','宋','宋诗','song-poetry','','[]','標置才謀孰尚公，拜恩新領浙江東。',64,'全唐诗/poet.song.26000.json','["標置才謀孰尚公，拜恩新領浙江東。", "黄扉玉殿官儀貴，皂蓋朱幡使節雄。", "耕織富饒青嶂裏，樓臺縹緲翠雲中。", "到時湖上看秋月，安得清樽侍下風。"]'),
('1423d80a-612f-4e69-aef9-bca807c9639c','題共樂堂','錢暄','宋','宋诗','song-poetry','','[]','疏就湖山秀氣濃，花林茂列景爭雄。',64,'全唐诗/poet.song.26000.json','["疏就湖山秀氣濃，花林茂列景爭雄。", "管弦交奏客歡合，臺榭競登人喜同。", "環嶂鷺行飛早晚，平波魚陣躍西東。", "荒蕪芟去成佳致，換得汀洲月與風。"]'),
('d89f8228-bd0a-40dc-b058-c6884cc4e281','遊日山','錢暄','宋','宋诗','song-poetry','','[]','清晨渡水陟秋山，日上高原葉葉丹。',64,'全唐诗/poet.song.26000.json','["清晨渡水陟秋山，日上高原葉葉丹。", "已傍松筠尋磴道，更瞻臺殿倚層巒。", "梁間雲氣蒸衣潤，窗外嵐光照席寒。", "顧我塵勞嗟少暇，暫驅熊軾一盤桓。"]'),
('b7cf6ca3-85d8-41e1-9342-a6ae77a4c59f','恭和','呂公著','宋','宋诗','song-poetry','','[]','雪消春動氣清微，夾道都人望帝暉。',64,'全唐诗/poet.song.26000.json','["雪消春動氣清微，夾道都人望帝暉。", "法部已調絲竹管，御袍初進赭紅衣。", "康衢彌節嚴三衛，真館焚香降六飛。", "宴罷瑶池回蹕晚，五雲通夜擁端闈。"]'),
('7afc375c-8081-43c3-b82b-6868c9a9b861','分題得癭木壺','呂公著','宋','宋诗','song-poetry','','[]','天地産衆材，任材謂之智。',228,'全唐诗/poet.song.26000.json','["天地産衆材，任材謂之智。", "棟桷與楹杙，小大無有棄。", "方者以矩度，圓者中規制。", "嗟爾木之癭，何異肉有贅。", "生成擁腫姿，賦象難取類。", "檃括所不施，鉤繩爲爾廢。", "大匠睨而往，惻然乃有意。", "孰非造化功，而終朽不器。", "刳剔虛其中，朱漆爲之僞。", "斟漿挹酒醴，施用惟其利。", "犧象非不珍，金罍豈不貴。", "設之于楹階，十目肯注視。", "幸因左右容，反見爲奇異。", "人之于才性，夫豈遠于是。", "性雖有不善，在教之揉勵。", "才亡不可用，由上所措置。", "飾陋就其長，皆得爲良士。", "執一以廢百，衆功何由備。", "是惟聖人心，能通天下志。"]'),
('404b65b2-752f-4341-bf47-dd9864e54255','天津晚步','呂公著','宋','宋诗','song-poetry','','[]','芝蓋久稀疏，暮雲空坱北。',72,'全唐诗/poet.song.26000.json','["芝蓋久稀疏，暮雲空坱北。", "千年舊都城，一片閒宮闕。", "禁籞尚連延，觚稜猶巀嶭。", "橋勢橫雌霓，堤形偃初月。", "瀍澗岸已深，漢唐時既歇。", "危亭獨坐人，浪把興亡閱。"]'),
('564bf436-7d64-4118-9ab4-004eb114f5de','楊郎中新居和堯夫先生韵  其一','呂公著','宋','宋诗','song-poetry','','[]','高齋曠望極山川，却顧卑居不值錢。',64,'全唐诗/poet.song.26000.json','["高齋曠望極山川，却顧卑居不值錢。", "二室峰巒凝畫碧，萬家樓閣带輕烟。", "春濃繚繞環遊騎，地勝依稀寓列仙。", "唱發幽人丞相和，當時紙貴洛城傳。"]'),
('e2065f43-1e5a-4a65-9738-70cf88635bd4','楊郎中新居和堯夫先生韵  其二','呂公著','宋','宋诗','song-poetry','','[]','碧瓦朱門將相居，見嵩臨洛百家無。',64,'全唐诗/poet.song.26000.json','["碧瓦朱門將相居，見嵩臨洛百家無。", "登高此地還能賦，會老他年定入圖。", "花發四時排步障，鳥鳴終日勸提壺。", "何人遇賞偏留賞，逸士清風激鄙夫。"]'),
('d7737178-c57a-4b90-94b2-485ba1810eef','和魏教授見贈','呂公著','宋','宋诗','song-poetry','','[]','清世文章日月懸，無才惟幸樂豐年。',64,'全唐诗/poet.song.26000.json','["清世文章日月懸，無才惟幸樂豐年。", "遊山太室更少室，看水伊川又洛川。", "古有孟軻難語覺，時無顔子易爲賢。", "讀書每到天根處，長懼諸公問極前。"]'),
('9dcd6e62-8c40-4b68-af0c-3c9e44e67016','留題龍門二首  其一','呂公著','宋','宋诗','song-poetry','','[]','融結成來不記秋，斷崖蒼壁鎖烟愁。',64,'全唐诗/poet.song.26000.json','["融結成來不記秋，斷崖蒼壁鎖烟愁。", "中分洪造夏王力，橫截大山伊水流。", "八節灘聲長在耳，一川風景盡歸樓。", "行人莫動憑欄興，無限英雄浪白頭。"]'),
('b0759533-0119-4719-91d5-d94d70ce6a98','留題龍門二首  其二','呂公著','宋','宋诗','song-poetry','','[]','誰將長劍斬長蛟，斬斷長蛟劍復韜。',64,'全唐诗/poet.song.26000.json','["誰將長劍斬長蛟，斬斷長蛟劍復韜。", "爪尾蜿蜒凝華岳，角牙獰惡結嵩高。", "骨傷兩處嶄蒼壁，血出東流洶巨濤。", "此物猶難保身首，爲言讒口莫嗷嗷。"]'),
('c53e2e78-9d08-4e39-ae25-8a2ccbb46098','龍門石樓看伊川','呂公著','宋','宋诗','song-poetry','','[]','數朝從款走烟霞，縱意憑欄看物華。',64,'全唐诗/poet.song.26000.json','["數朝從款走烟霞，縱意憑欄看物華。", "百尺樓臺通鳥道，一川烟雨屬僧家。", "直須心逸方爲樂，始信官榮未足誇。", "此景得遊無事日，也宜知幸福無涯。"]'),
('6bf48b3f-012c-4340-92bb-dec465b19f65','二十二日晚步天津次日有詩','呂公著','宋','宋诗','song-poetry','','[]','溪翁昨晚步天津，步到天津佇立頻。',64,'全唐诗/poet.song.26000.json','["溪翁昨晚步天津，步到天津佇立頻。", "洛水只聞煎去棹，西風唯解促行人。", "山川慘淡籠寒雨，樓觀參差鎖暮雲。", "此景分明誰會得，欲霜時候雁來賓。"]'),
('e6e1e6b4-8bef-4b0a-94f7-7bfc3d43b4c1','和王常侍登郡樓望山','呂公著','宋','宋诗','song-poetry','','[]','四賢當日此盤桓，千百年人尚厚顔。',64,'全唐诗/poet.song.26000.json','["四賢當日此盤桓，千百年人尚厚顔。", "天下有名難避世，胸中無物漫居山。", "事觀今古興亡後，道在君臣進退間。", "若藴奇才必奇用，不然須負一生閒。"]'),
('a1728f48-4da5-4236-8125-a777098ccd74','和王安之六老詩  其一','呂公著','宋','宋诗','song-poetry','','[]','六老皤然鬢似霜，縱心年至又非狂。',64,'全唐诗/poet.song.26000.json','["六老皤然鬢似霜，縱心年至又非狂。", "園池共避何方勝，樽酒相歡未始忙。", "杖屨爛遊千載運，衣巾濃惹萬花香。", "過從見率添成七，况復秋來亦漸凉。"]'),
('1bbc1d3d-4bbf-4971-8a7b-be1e72f3334d','和王安之六老詩  其二','呂公著','宋','宋诗','song-poetry','','[]','六客同遊一醉鄉，又非流俗所言狂。',64,'全唐诗/poet.song.26000.json','["六客同遊一醉鄉，又非流俗所言狂。", "追遊共喜清平久，唱和爭尋警策忙。", "薦酒月坡林果熟，發茶金石井泉香。", "千年松下麾談麈，襟袖無風亦自凉。"]'),
('f54b5e84-92ab-4e09-beb0-9877d78ed0da','和王安之六老詩  其三','呂公著','宋','宋诗','song-poetry','','[]','林下狂歌不貼腔，貼腔安得謂之狂。',64,'全唐诗/poet.song.26000.json','["林下狂歌不貼腔，貼腔安得謂之狂。", "小車行處鶑花鬧，大筆落時神鬼忙。", "門掩紫荆闤闠遠，牆開甕牖薜蘿香。", "一般天下難尋物，洛浦清風拂面凉。"]'),
('3f7c287d-30e4-454f-8c23-6c2ced5a6e22','寄吳傳正寺丞','呂公著','宋','宋诗','song-poetry','','[]','敦篤情懷世所稀，昔年今日事難追。',64,'全唐诗/poet.song.26000.json','["敦篤情懷世所稀，昔年今日事難追。", "雪霜未始寒無甚，□桂何嘗色暫移。", "洛邑士人雖我信，天津風月只君知。", "夢魂不悟東都遠，依舊過從似舊時。"]'),
('8dfc05dc-f313-4301-b11a-c065ee2e6f02','延福坊李太博乞園池詩','呂公著','宋','宋诗','song-poetry','','[]','宣威十九次高牙，奕葉功臣舊將家。',64,'全唐诗/poet.song.26000.json','["宣威十九次高牙，奕葉功臣舊將家。", "清世辭榮歸里第，白頭行樂過年華。", "杯盈香醑浮春水，曲度新聲出靚花。", "如此園池如此壽，兒孫滿眼慶無涯。"]'),
('e2172cbc-c7fe-49f5-ba65-ea43e7578a7e','王安之同赴王宣徽洛社秋會','呂公著','宋','宋诗','song-poetry','','[]','後房深出會親賓，樂按新聲妙入神。',64,'全唐诗/poet.song.26000.json','["後房深出會親賓，樂按新聲妙入神。", "紅燭盛時翻翠袖，畫橈停處占青蘋。", "早年金殿舊遊客，此日鳳池將去人。", "宅冠名都號蝸隠，邵堯夫敢作西鄰。"]'),
('09d84691-8df1-4011-bc90-29c4a5e78263','歸洛寄祖擇之龍圖','呂公著','宋','宋诗','song-poetry','','[]','恩深骨髓謂慈親，義重邱山是故人。',32,'全唐诗/poet.song.26000.json','["恩深骨髓謂慈親，義重邱山是故人。", "歸過嵩陽舊遊地，□雲收得薜蘿身。"]'),
('35f6d600-5376-4843-9363-d717e703e7d9','送程給事知越州','鄭穆','宋','宋诗','song-poetry','','[]','菟符優寄寵清賢，邸吏相驚印紱鮮。',64,'全唐诗/poet.song.26000.json','["菟符優寄寵清賢，邸吏相驚印紱鮮。", "方面幾稱良太守，名區今作小神仙。", "夏王古穴幽藏怪，賀監明湖冷浸天。", "爲語錢塘二千石，詩筩頻發渡江船。"]'),
('fdba1989-6332-41a7-8f77-804b124c5ec0','贈仙居宰陳述古  其一','鄭穆','宋','宋诗','song-poetry','','[]','我愛仙居宰，隆時起四方。',48,'全唐诗/poet.song.26000.json','["我愛仙居宰，隆時起四方。", "青衿遊戶闥，逢掖在軒堂。", "自昔風蠻貊，于今邑校庠。", "賀衙聞勸學，耆耋涕彷徨。"]'),
('fa0d3c4a-59fb-4681-b537-8c4d59c9b8ab','贈仙居宰陳述古  其二','鄭穆','宋','宋诗','song-poetry','','[]','我愛仙居宰，渾渾政不拘。',48,'全唐诗/poet.song.26000.json','["我愛仙居宰，渾渾政不拘。", "縱民如野鹿，任道若荒蕪。", "訪境土皆闢，訂風惡亦無。", "平生志嚴整，伺隙莫操弧。"]'),
('b301a3b9-b76b-46a6-ba41-702a9d1526cf','贈仙居宰陳述古  其三','鄭穆','宋','宋诗','song-poetry','','[]','我愛仙居宰，巖巖氣宇寬。',48,'全唐诗/poet.song.26000.json','["我愛仙居宰，巖巖氣宇寬。", "百筳微出響，萬楫一生瀾。", "邑小天爲壽，民愚地與安。", "經年不相見，已見欲躋難。"]'),
('06aad3b7-3bd9-44be-8889-0506fea22f69','贈仙居宰陳述古  其四','鄭穆','宋','宋诗','song-poetry','','[]','我愛仙居宰，接人推至誠。',24,'全唐诗/poet.song.26000.json','["我愛仙居宰，接人推至誠。", "一官厓岸絕，百志惠慈生。"]'),
('06a14f28-bf9d-4189-aa66-24d7599e853f','桐竹君詠','陳翥','宋','宋诗','song-poetry','','[]','高桐凌紫霞，修篁拂碧雲。',60,'全唐诗/poet.song.26000.json','["高桐凌紫霞，修篁拂碧雲。", "吾常居其間，自號桐竹君。", "不解倣俗利，所希脫世紛。", "會交但文學，啟談皆典墳。", "吁嗟機巧徒，反道胡足云。"]'),
('d53abfb7-eebe-4f29-b944-be228526bcb2','西山桐十詠 桐栽','陳翥','宋','宋诗','song-poetry','','[]','吾有西山桐，栽之未盈握。',96,'全唐诗/poet.song.26000.json','["吾有西山桐，栽之未盈握。", "所得從野人，移來自喬嶽。", "節凝葉尚秘，根疏土自剝。", "匪爲待籬鷃，庸將栖鸑鷟。", "異日成茂林，論材誰見擢。", "巨則爲棟梁，微亦任楹桷。", "仍堪雅琴器，奏之反淳樸。", "大匠如顧憐，委軀願雕斲。"]'),
('563704ae-a7ea-4718-925a-ecfcdaa432e1','西山桐十詠 桐根','陳翥','宋','宋诗','song-poetry','','[]','吾有西山桐，密鄰桃與李。',96,'全唐诗/poet.song.26000.json','["吾有西山桐，密鄰桃與李。", "得地自行根，受芘逾高藟。", "上濯春雲膏，下滋醴泉髓。", "盤結侔循環，岐分類枝體。", "乘虛肌體大，墳漲土脈起。", "扶疏向山壤，蔓衍出林地。", "願偕久深固，無爲半生死。", "倘儀大厦材，合抱由茲始。"]'),
('a15a55bc-3745-40d7-ba06-bdfa5c57b350','西山桐十詠 桐花','陳翥','宋','宋诗','song-poetry','','[]','吾有西山桐，桐盛茂其花。',96,'全唐诗/poet.song.26000.json','["吾有西山桐，桐盛茂其花。", "香心自蝶戀，縹緲带無涯。", "白者含秀色，粲如凝瑶華。", "紫者吐芳英，爛若舒朝霞。", "素柰亦足擬，紅杏寧相加。", "世但貴丹藥，夭艷資驕奢。", "歌管繞庭檻，翫賞成矜誇。", "倘或求美材，爲爾長所嗟。"]'),
('523a2689-6c66-4dbe-b7d5-e18551bf105d','西山桐十詠 桐葉','陳翥','宋','宋诗','song-poetry','','[]','吾有西山桐，下臨百丈溪。',96,'全唐诗/poet.song.26000.json','["吾有西山桐，下臨百丈溪。", "布葉雖遲遲，庇根亦萋萋。", "密類張翠幄，青堪翦封圭。", "滑澤經日久，濡毳隨幹躋。", "近風带影動，墜雨向身低。", "寧隠凡鳥巢，自蔽儀鳳栖。", "松柏徒爾頑，蒲柳空思齊。", "但有知心時，應使常弗迷。"]'),
('5b03170b-2a73-418e-a9d5-602e100f8f27','西山桐十詠 桐乳','陳翥','宋','宋诗','song-poetry','','[]','吾有西山桐，厥實狀如乳。',96,'全唐诗/poet.song.26000.json','["吾有西山桐，厥實狀如乳。", "含房隠綠葉，致巢來翠羽。", "外滑自爲穗，中虛不可數。", "輕漸曝秋陽，重即濡綿雨。", "霜後威氣裂，隨風到烟塢。", "雖非松柏子，受命亦知土。", "誰能好琴瑟，種之向春圃。", "始知非凡材，諸木豈予伍。"]'),
('26db271a-57d6-42bc-9bb9-a5d86e26c112','西山桐十詠 桐孤','陳翥','宋','宋诗','song-poetry','','[]','高梧已繁盛，蕭蕭西山隴。',96,'全唐诗/poet.song.26000.json','["高梧已繁盛，蕭蕭西山隴。", "毳葉竟開展，孫枝自森聳。", "擅美推東南，滋榮藉萋菶。", "不能容燕雀，只許栖鸞鳳。", "寧入吳人爨，堪隨伯禹貢。", "雨露時加潤，霜雪胡爲凍。", "况有奇特材，足任雅琴用。", "中含太古音，可美清風頌。"]'),
('60b53dd6-23f1-4fe1-99ca-3ee11dda643a','西山桐十詠 桐風','陳翥','宋','宋诗','song-poetry','','[]','分材植梧桐，桐茂成翠林。',96,'全唐诗/poet.song.26000.json','["分材植梧桐，桐茂成翠林。", "日日來輕風，時時自登臨。", "拂幹動微毳，吹葉破圓陰。", "虛凉可解慍，輕鼓如調琴。", "莫傳獨鵠操，願述栖鳳吟。", "豈羞楚襄王，蘭臺堪披襟。", "亦陋陶隠居，高閣聽松音。", "無爲摇落意，慰我休閒心。"]'),
('9d5f383c-e808-4171-9a2c-c8760ff1f263','西山桐十詠 桐陰','陳翥','宋','宋诗','song-poetry','','[]','枝軟自相交，葉榮更分茂。',96,'全唐诗/poet.song.26000.json','["枝軟自相交，葉榮更分茂。", "所得成清陰，仍宜當白晝。", "蔭疑翠帟展，翳若繁雲覆。", "日午密影疊，風摇碎花漏。", "冷不蔽空井，高堪在庭甃。", "吾本閑野人，受樂忘煢疚。", "亭亭類張蓋，翼翼如層構。", "月夕獨裴回，猶思一重復。"]'),
('c4042609-b385-4d53-a8de-1203c408a932','西山桐十詠 桐徑','陳翥','宋','宋诗','song-poetry','','[]','時人羨桃李，下自成蹊徑。',96,'全唐诗/poet.song.26000.json','["時人羨桃李，下自成蹊徑。", "而我愛梧桐，亦以成乎性。", "中平端隊道，還往非遼敻。", "直入無欹斜，橫延亦徑挺。", "月夕葉影碎，春暮花光映。", "清朝濛露濕，落日隨烟暝。", "不使草蔓滋，任從根裂迸。", "堪詣蔣詡徒，惟任蓬蒿盛。"]'),
('d2ba5c5f-3243-43d6-acae-61fda09ece68','峴山','范微之','宋','宋诗','song-poetry','','[]','南□會要地，山水控雄壯。',102,'全唐诗/poet.song.26000.json','["南□會要地，山水控雄壯。", "峨峨峙峴首，濃綠疊千嶂。", "群峰相迤邐，頑□厠□□。", "漢流紀東麓，汪汪□□漲。", "原隰錯綺組，雲□織纖纊。", "景物革四時，眺聽增萬狀。", "羊公昔鎮撫，平吳啟霸王。", "經國有餘裕，□□此登訪。", "表表□形勢。"]'),
('e9aace1d-3fd2-4351-910f-2db44feb451b','偶書','黄庶','宋','宋诗','song-poetry','','[]','此心爲地把書耕，若問生涯指六經。',32,'全唐诗/poet.song.26000.json','["此心爲地把書耕，若問生涯指六經。", "欲語世人真富貴，胸中珠玉又無形。"]'),
('798599a3-e141-45b8-82ae-7c55c03bbc8a','讀赦書','黄庶','宋','宋诗','song-poetry','','[]','詔書一尺洗寰瀛，舒卷雷霆萬物驚。',64,'全唐诗/poet.song.26000.json','["詔書一尺洗寰瀛，舒卷雷霆萬物驚。", "天祇無私均雨露，地緣强半是榛荆。", "人間疾苦言堪療，塞外豺狼腹未盈。", "不是朝廷用桑孔，丁寧渾只念蒼生。"]'),
('c3ecd797-5457-4be1-bd16-f351064ea34e','遣懷','黄庶','宋','宋诗','song-poetry','','[]','六載紅蓮客，差池又一年。',48,'全唐诗/poet.song.26000.json','["六載紅蓮客，差池又一年。", "無人和白雪，有意補青天。", "肝膽論興廢，詩書謁聖賢。", "尊中古日月，窮達付陶甄。"]'),
('8cb16362-ae62-4a6d-8435-f7ae4f5201e4','山居獨酌','黄庶','宋','宋诗','song-poetry','','[]','山寒未放春消息，獨把單醪慰寂寥。',64,'全唐诗/poet.song.26000.json','["山寒未放春消息，獨把單醪慰寂寥。", "書對聖賢爲客主，竹兼風雨似咸韶。", "醉鄉城郭燈前到，愁賊戈矛盞底銷。", "野菜溪魚隨分有，不堪回首叫簞瓢。"]'),
('3017f9bb-3731-4e58-9b4f-627091861362','春日閑居','黄庶','宋','宋诗','song-poetry','','[]','韁鎖身閑似未名，方愚情性被春輕。',64,'全唐诗/poet.song.26000.json','["韁鎖身閑似未名，方愚情性被春輕。", "酒教筆硯因花廢，路爲亭臺與草爭。", "野客笋邀煨短茁，鄰僧茶約煮新萌。", "無時杖屨穿林去，真是尋芳戶一丁。"]'),
('e7f3c792-4da2-4b51-9c33-d4a006f4314a','贈山寺僧','黄庶','宋','宋诗','song-poetry','','[]','慵飽浮圖世共憎，蓬蒿師獨養牛耕。',64,'全唐诗/poet.song.26000.json','["慵飽浮圖世共憎，蓬蒿師獨養牛耕。", "田驅白石年常過，林印青薪歲旋生。", "竹似子孫憐笋茁，樹添松柏補風聲。", "眉頭怪得春來喜，雨起蔬苗粒粒成。"]'),
('a609f763-2fa7-4935-950d-e06c1cd9f5c1','寄子蒙授常寧令','黄庶','宋','宋诗','song-poetry','','[]','疏率君堪愛，無心宦又高。',48,'全唐诗/poet.song.26000.json','["疏率君堪愛，無心宦又高。", "身思眠白屋，人勉著青袍。", "號隠疑名福，貪歸似姓陶。", "常寧邑雖小，應合得牛刀。"]'),
('2dd0ab99-0597-427c-8be2-6f48102476e7','靈竹','黄庶','宋','宋诗','song-poetry','','[]','綠陰清韵竹蕭然，歷歷當年泣淚痕。',32,'全唐诗/poet.song.26000.json','["綠陰清韵竹蕭然，歷歷當年泣淚痕。", "千古舜妃湘水底，必應憔悴有慚魂。"]'),
('39b767e1-28b6-4ef8-a7e5-d1355b89d640','山水卧屏','黄庶','宋','宋诗','song-poetry','','[]','林泉生長厭應難，更寫方屏幾曲間。',32,'全唐诗/poet.song.26000.json','["林泉生長厭應難，更寫方屏幾曲間。", "仕宦東西苦無定，此心長似宿家山。"]'),
('807d1127-0b24-49ee-a598-84d281804deb','和劉卿材十咏 耕者','黄庶','宋','宋诗','song-poetry','','[]','四海兵今息，耕夫未得知。',24,'全唐诗/poet.song.26000.json','["四海兵今息，耕夫未得知。", "黄粱不敢吃，碗尚半蒿藜。"]'),
('f5cf286b-c177-41f9-be4c-226537b5238b','和劉卿材十咏 牧豎','黄庶','宋','宋诗','song-poetry','','[]','逐處隨青草，生來不識愁。',24,'全唐诗/poet.song.26000.json','["逐處隨青草，生來不識愁。", "旱田乾欲死，拍手也須謳。"]'),
('709173c5-3c20-46ae-9eda-ab70577985de','和劉卿材十咏 紅樹','黄庶','宋','宋诗','song-poetry','','[]','幾樹濃於茜，斜陽景最幽。',24,'全唐诗/poet.song.26000.json','["幾樹濃於茜，斜陽景最幽。", "忽因風雨盡，全減十分秋。"]'),
('d8208683-3ca8-49a9-b78f-b8020d9fef3a','和劉卿材十咏 野廟','黄庶','宋','宋诗','song-poetry','','[]','中國浮圖盛，祈禳漸不過。',24,'全唐诗/poet.song.26000.json','["中國浮圖盛，祈禳漸不過。", "吾民非獨困，山鬼恨尤多。"]'),
('5a00e1b1-fbd0-45ae-9cbb-f9c4cb20c602','和劉卿材十咏 堠子','黄庶','宋','宋诗','song-poetry','','[]','一堠居市廛，百堠居林莽。',24,'全唐诗/poet.song.26000.json','["一堠居市廛，百堠居林莽。", "土木若有情，山中亦惆悵。"]'),
('865acf01-8edc-4846-9e3c-ade05753eab6','和劉卿材十咏 水鴨','黄庶','宋','宋诗','song-poetry','','[]','憶在山中日，溪邊把釣鈎。',24,'全唐诗/poet.song.26000.json','["憶在山中日，溪邊把釣鈎。", "相逢恐驚起，招手却回舟。"]'),
('de577d4f-5d27-4c13-85bb-a7a1af0ff586','和劉卿材十咏 溪聲','黄庶','宋','宋诗','song-poetry','','[]','至音不可收，今人滯形器。',24,'全唐诗/poet.song.26000.json','["至音不可收，今人滯形器。", "欲知古樂心，山中此聲是。"]'),
('e43cf498-31f4-4526-9c84-a9877d1ea7e7','和劉卿材十咏 草市','黄庶','宋','宋诗','song-poetry','','[]','衝市柴魚集，應山鷄犬號。',24,'全唐诗/poet.song.26000.json','["衝市柴魚集，應山鷄犬號。", "問知人苦樂，米價不多高。"]'),
('fe0d93f5-2228-419f-8938-3f37958e9f52','和劉卿材十咏 龍潭','黄庶','宋','宋诗','song-poetry','','[]','寂寞真龍去，雩壇血不乾。',24,'全唐诗/poet.song.26000.json','["寂寞真龍去，雩壇血不乾。", "世情多冷暖，對此鼻辛酸。"]'),
('3a302809-2ceb-4921-ab19-1439b0cc5b26','和劉卿材十咏 溪橋','黄庶','宋','宋诗','song-poetry','','[]','憶得別離日，鄉橋柳脚斜。',24,'全唐诗/poet.song.26000.json','["憶得別離日，鄉橋柳脚斜。", "讀君詩一轉，全似到吾家。"]'),
('2b7fa642-41e3-4402-a2ae-c75b29a75e7e','觀雪','黄庶','宋','宋诗','song-poetry','','[]','疑是天公戲，都傾海作鹽。',48,'全唐诗/poet.song.26000.json','["疑是天公戲，都傾海作鹽。", "松筠知不變，丘壑見無厭。", "清爲詩家極，寒因酒戶添。", "冬溫成俗疫，得此勝針砭。"]'),
('472f307c-96fa-4d4b-a9ca-b163c259d03c','酒','黄庶','宋','宋诗','song-poetry','','[]','千載醇醲意，長隨麴糵新。',48,'全唐诗/poet.song.26000.json','["千載醇醲意，長隨麴糵新。", "解將今日月，轉入古乾坤。", "悶至勝良藥，愁來敵故人。", "幾杯聊酩酊，五斗趣還均。"]'),
('2d4143cd-d1b4-4fac-a491-80ddebfab86b','登鄭氏閣','黄庶','宋','宋诗','song-poetry','','[]','林泉無價自由身，韁鎖登臨趣未真。',64,'全唐诗/poet.song.26000.json','["林泉無價自由身，韁鎖登臨趣未真。", "望處好山俱得力，夜應明月不孤人。", "任從心外煩於蟻，長對樽中別有春。", "當日若知風物勝，定移鷄犬過江濱。"]'),
('59ee966b-1edb-498b-bd42-e867d2caaae2','立春','黄庶','宋','宋诗','song-poetry','','[]','此日春方到，春心亞舜堯。',48,'全唐诗/poet.song.26000.json','["此日春方到，春心亞舜堯。", "勾芒如稷契，大蔟似咸韶。", "衡柄三陽把，陶鎔萬物翹。", "家家助和氣，剪綵作花飄。"]'),
('1d657a21-4421-48c1-a461-57bf2f1863fd','題人移牡丹','黄庶','宋','宋诗','song-poetry','','[]','林上春來恰恰忙，安排顔色與春裝。',64,'全唐诗/poet.song.26000.json','["林上春來恰恰忙，安排顔色與春裝。", "栽培欲報應先發，根柢雖移不改芳。", "紅藥便隨心減價，黄蜂偷喜蜜添香。", "憑君剩釀看花酒，待插花枝滿首嘗。"]'),
('cfb36947-e8b8-40db-ad50-0609253dde99','探春','黄庶','宋','宋诗','song-poetry','','[]','雪裏猶能醉落梅，好營杯具待春來。',32,'全唐诗/poet.song.26000.json','["雪裏猶能醉落梅，好營杯具待春來。", "東風便試新刀尺，萬葉千花一手裁。"]'),
('cd8e79c8-2be7-49a4-95d0-0c82fdc72a4f','筇竹杖','黄庶','宋','宋诗','song-poetry','','[]','琴鶴爲友朋，出入常拂拭。',24,'全唐诗/poet.song.26000.json','["琴鶴爲友朋，出入常拂拭。", "生來節便高，故有扶危力。"]'),
('8a4d5cf2-2921-4406-8c0f-c08767e1aa4a','題東寺柱','黄庶','宋','宋诗','song-poetry','','[]','竹風松月牢於鎖，關閉人心物外情。',32,'全唐诗/poet.song.26000.json','["竹風松月牢於鎖，關閉人心物外情。", "燕雀聞經俱已慣，歸來不怕讀書聲。"]'),
('43d8c3f4-c784-4ccb-8dcc-feacb78e3f38','教繩權學書偶成','黄庶','宋','宋诗','song-poetry','','[]','文字有緣曾弄墨，見來官小免咨嗟。',64,'全唐诗/poet.song.26000.json','["文字有緣曾弄墨，見來官小免咨嗟。", "喜將筆硯傳生計，不失詩書作世家。", "字識姓名能指點，寫因梨栗不傾斜。", "著鞭莫落時人後，三十塵埃監汝爺。"]'),
('b63883b8-c3e1-49f5-9edc-c66640c640b2','次韵答王甫判官','黄庶','宋','宋诗','song-poetry','','[]','塵埃蹭蹬落麤官，頼有詩書可自安。',64,'全唐诗/poet.song.26000.json','["塵埃蹭蹬落麤官，頼有詩書可自安。", "人到聖賢由感激，國施鐘鼎爲艱難。", "須期燕骨千金價，莫動黄陂萬頃瀾。", "窮達功名無早晚，好山宜且醉吟看。"]'),
('3c9483c9-140d-4ea3-a570-37f7061a30a0','致政吳侍郎挽歌詞  其一','黄庶','宋','宋诗','song-poetry','','[]','千里資甘旨，凄凉一日遺。',48,'全唐诗/poet.song.26000.json','["千里資甘旨，凄凉一日遺。", "爲臣如廣受，生子似皋夔。", "筆硯諸孫哭，謳歌幾郡思。", "秦人失太守，翻有怨天辭。"]'),
('1085002f-1182-4825-8bff-6333944b1b67','致政吳侍郎挽歌詞  其二','黄庶','宋','宋诗','song-poetry','','[]','荆棘二疏路，幾人同敝衣。',48,'全唐诗/poet.song.26000.json','["荆棘二疏路，幾人同敝衣。", "仕塗師白髪，國老欲彤幃。", "遺稿詩書滿，行旌雨雪飛。", "陝民應淚落，不見板輿歸。"]'),
('e89f615b-0e77-46da-8ee0-9062ed5cd6b0','署中新栽竹','黄庶','宋','宋诗','song-poetry','','[]','移作亭園主，栽培霜雪姿。',48,'全唐诗/poet.song.26000.json','["移作亭園主，栽培霜雪姿。", "不辭桃李笑，只待鳳凰知。", "少已留風住，疏宜待月篩。", "相看時一醉，誰道小官卑。"]'),
('5b641ccd-eb6c-4cad-ad4c-7f5c033dd047','和題雲臺觀','黄庶','宋','宋诗','song-poetry','','[]','太華疑挨畢昴回，欲觀形勝上雲臺。',64,'全唐诗/poet.song.26000.json','["太華疑挨畢昴回，欲觀形勝上雲臺。", "雪中地把銀屏立，雨後天將畫軸開。", "景好更宜和月看，客忙常是愛山來。", "我知遊者登臨意，常恨西軒落日催。"]'),
('7f5f7577-8159-425e-8953-c7f221360cd2','都廳誦書偶成','黄庶','宋','宋诗','song-poetry','','[]','主人調鼎手，千里刃迎虛。',48,'全唐诗/poet.song.26000.json','["主人調鼎手，千里刃迎虛。", "暗使民如堵，能容吏似樗。", "莓苔眠杻械，燕雀聽詩書。", "刀筆慚無補，身爲白蠹魚。"]'),
('989f56ea-819d-4997-8424-a2747b9c9f00','題公美庭前蘆','黄庶','宋','宋诗','song-poetry','','[]','長安只說誰花好，君把青蘆砌下栽。',32,'全唐诗/poet.song.26000.json','["長安只說誰花好，君把青蘆砌下栽。", "鳴雁也知人好事，幾時銜得入關來。"]'),
('f81988f2-c575-477b-ab87-e8cbf04e320f','和公美季點書事','黄庶','宋','宋诗','song-poetry','','[]','知君行縣樂，經見飽朝昏。',48,'全唐诗/poet.song.26000.json','["知君行縣樂，經見飽朝昏。", "禾黍富年戶，牛羊落日村。", "趁雲看華沒，衝雨渡涇渾。", "頗得詩家助，聊應慰旅魂。"]'),
('2aa79259-3d7a-4648-b0d1-bb3350e203c8','送石都官赴闕','黄庶','宋','宋诗','song-poetry','','[]','爲郎四十者，堂有二親稀。',48,'全唐诗/poet.song.26000.json','["爲郎四十者，堂有二親稀。", "止仰官爲養，行應淚在衣。", "白雲偏佇立，黄犬好頻歸。", "去有山公啟，天心正似饑。"]'),
('3b86d0b4-3c6a-46c9-b8be-7827b8822b38','長安賀晏相公生辰','黄庶','宋','宋诗','song-poetry','','[]','衙鼓簪紳動，靈椿薦壽醪。',72,'全唐诗/poet.song.26000.json','["衙鼓簪紳動，靈椿薦壽醪。", "吾君合堯舜，此日降伊皋。", "盤誥文章老，丹青事業牢。", "乃朝尊柱石，千里輟鈞陶。", "民即謳歌借，霖應夢寐勞。", "秦人下車樂，遠邇賦崧高。"]'),
('35a52eb2-7629-484b-af3d-d99060bf591f','次韵和言懷','黄庶','宋','宋诗','song-poetry','','[]','五常爲種耕情性，天意寧分有與無。',64,'全唐诗/poet.song.26000.json','["五常爲種耕情性，天意寧分有與無。", "史解戮人惟戮古，地能埋死只埋愚。", "青雲易把詩書買，白髪難停日月驅。", "顧我無才背時俗，浮名早晚見歸途。"]'),
('50b1cee0-4f03-4b39-8085-6f66cf5e8e24','和子玉病起遊書齋','黄庶','宋','宋诗','song-poetry','','[]','蕭齋久不往，筋力試筇初。',48,'全唐诗/poet.song.26000.json','["蕭齋久不往，筋力試筇初。", "窗戶蝸涎鎖，塵埃鼠迹書。", "病魔雖已去，詩癖竟難除。", "苔地欣重掃，徘徊意有餘。"]'),
('2cc52244-d68d-41be-8bb6-406cc052004e','依韵和舞陽楊令九日羊川鄉同小飲之作','黄庶','宋','宋诗','song-poetry','','[]','青帘白屋得新醅，坐待村童買果迴。',64,'全唐诗/poet.song.26000.json','["青帘白屋得新醅，坐待村童買果迴。", "旋撚野花爲泛菊，更尋山路作登臺。", "世途已把灰心死，樽酒聊同笑口開。", "多謝晚禽知客意，歌吟來往勸餘杯。"]'),
('549576e5-9aa0-403d-8fee-d0992ef32c7e','謝趙太傅遺聚米圖經珣所作','黄庶','宋','宋诗','song-poetry','','[]','文武生賢子，羌圖帝所多。',48,'全唐诗/poet.song.26000.json','["文武生賢子，羌圖帝所多。", "始欣知馬援，終嘆失廉頗。", "蒼鼠巢遺稿，黄埃鎖舊戈。", "遠人猶偃蹇，掩帙淚滂沱。"]'),
('4d9af88b-0b4f-49ff-9d02-0923cacb267d','哭水丘隨州','黄庶','宋','宋诗','song-poetry','','[]','卧理隨民欲問安，訃郵俄至廢朝餐。',64,'全唐诗/poet.song.26000.json','["卧理隨民欲問安，訃郵俄至廢朝餐。", "秦川舊會歡如在，漢水新書墨未乾。", "丹旐已歸人寂寞，素車徒有淚汍瀾。", "時情冷暖尤無味，一臂相知在肺肝。"]'),
('271ec591-a242-4137-9b8f-39402a88675d','席上送韋中舍歸襄陽','黄庶','宋','宋诗','song-poetry','','[]','如君七十少，梨栗有堅牙。',48,'全唐诗/poet.song.26000.json','["如君七十少，梨栗有堅牙。", "琴杖新行李，雲泉舊世家。", "講求栽樹法，拂拭釣魚車。", "獨美今歸去，青衫脫有涯。"]'),
('6c2d55a0-3e57-41d5-a933-92a2367165ef','次韵和真長新春偶書','黄庶','宋','宋诗','song-poetry','','[]','東風寂寞掩柴關，時苦刪文筆凍乾。',64,'全唐诗/poet.song.26000.json','["東風寂寞掩柴關，時苦刪文筆凍乾。", "只把詩情磨世態，更憑酒力禦春寒。", "塵埃不必頻彈鋏，巖石終期共挂冠。", "嘆息焚和名利者，乾坤未似斗筲寬。"]'),
('9c2f4be1-bcf7-45d6-a101-cba7c3127e6c','伊川喜雨','黄庶','宋','宋诗','song-poetry','','[]','尺雨乘春慰望深，家家倉廩一年心。',32,'全唐诗/poet.song.26000.json','["尺雨乘春慰望深，家家倉廩一年心。", "伊川父老還知否，此是隨車傅說霖。"]'),
('8dfcc7c9-9976-47b3-8082-08f7ca7a92d4','送真長書記知舞陽','黄庶','宋','宋诗','song-poetry','','[]','塵土淹沉客，詩書夢寐身。',48,'全唐诗/poet.song.26000.json','["塵土淹沉客，詩書夢寐身。", "又辭千里幕，去布一同春。", "路想多歸戶，庭應絕澇民。", "青衫莫嗟嘆，知已在陶鈞。"]'),
('862fee8c-4ab6-421d-9c80-d2a1c4219c47','和陪丞相聽蜀僧琴','黄庶','宋','宋诗','song-poetry','','[]','百年生計一張琴，敝軫枯弦抵萬金。',64,'全唐诗/poet.song.26000.json','["百年生計一張琴，敝軫枯弦抵萬金。", "世上幾人曾入耳，樽前此日是知音。", "清風明月虛無境，白雪陽春寂寞心。", "莫訝南薰沉聽久，致君基業用功深。"]'),
('6ff4dfde-41c4-4a01-9d3d-061c1afc14dc','飲張承制園亭','黄庶','宋','宋诗','song-poetry','','[]','小園豈是春來晚，四月花飛入酒杯。',32,'全唐诗/poet.song.26000.json','["小園豈是春來晚，四月花飛入酒杯。", "都爲主人尤好事，風光留住不教回。"]'),
('aca62802-06b6-4b38-b09d-be6ce17388a4','八日探菊','黄庶','宋','宋诗','song-poetry','','[]','行遶牆邊菊，躊躕賞物心。',48,'全唐诗/poet.song.26000.json','["行遶牆邊菊，躊躕賞物心。", "秋風應有意，明日是知音。", "酒惜浮花醉，詩留把葉吟。", "兒童欣佳節，撚蕊試黄金。"]'),
('85303f64-5026-476d-ac7f-820b2a3f459a','市得笛竹簟因成詩','黄庶','宋','宋诗','song-poetry','','[]','八尺枯冰簟一筒，小軒拂拭趣誰同。',64,'全唐诗/poet.song.26000.json','["八尺枯冰簟一筒，小軒拂拭趣誰同。", "樽前聲負千杯月，窗下光贏一枕風。", "易向曲肱增舊意，詩因仰看有新功。", "蠹書圍遶高眠處，夢與塵埃路不通。"]'),
('d1735705-7a85-4a5b-865f-47815571dcf0','廬山道中遇黄介夫因寄四十字','黄庶','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','冷日蒼山下，相逢笑又顰。',48,'全唐诗/poet.song.26000.json','["冷日蒼山下，相逢笑又顰。", "文章已膾炙，名位尚埃塵。", "昔見纓嘗請，今言雉欲馴。", "腥膻滿南郡，忍醉解池春。"]'),
('831e9a5c-9a27-43fb-8f91-e1867bd90c9c','次韵和雪霽遊西湖','黄庶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪會遊人意，元朝變物華。',48,'全唐诗/poet.song.26000.json','["雪會遊人意，元朝變物華。", "醉鄉銀作界，詩客玉爲家。", "魚影紋冰縠，禽蹤篆霰沙。", "餘英恐銷盡，目斷夕陽霞。"]'),
('2c92d005-3c6b-42e5-ba5e-8d7e88b9c483','次韵向元伯春晚有作','黄庶','宋','宋诗','song-poetry','','[]','好花未得千場醉，風雨飄零又一春。',32,'全唐诗/poet.song.26000.json','["好花未得千場醉，風雨飄零又一春。", "自是勞生無暇日，芳菲何處解孤人。"]'),
('5e79dbbc-0981-4ca9-b93a-c10461aee092','次韵居正暮春感事','黄庶','宋','宋诗','song-poetry','','[]','物報春光去已深，殘紅滿地綠成陰。',64,'全唐诗/poet.song.26000.json','["物報春光去已深，殘紅滿地綠成陰。", "晚花便好吟詩惜，餘景應須載酒尋。", "歡意莫教時節挫，窮愁自倚歲寒禁。", "亭園况是登臨勝，何必流年動素心。"]'),
('ccacd09e-0be1-4aa1-b50e-40b90367135f','次韵元伯西軒桃李','黄庶','宋','宋诗','song-poetry','','[]','李白桃紅氣味奢，早須分付醉吟家。',32,'全唐诗/poet.song.26000.json','["李白桃紅氣味奢，早須分付醉吟家。", "春風春雨難期信，便是無言做落花。"]'),
('e62ec0d8-2347-4ee1-90d7-160d59f7115b','望春偶書','黄庶','宋','宋诗','song-poetry','','[]','信馬尋春上古原，天工一幅繡平川。',32,'全唐诗/poet.song.26000.json','["信馬尋春上古原，天工一幅繡平川。", "花應笑我將詩句，便當遊人費萬錢。"]'),
('97d7fbb1-8bff-4f21-b2a9-6e58df62a930','次韵居正四月牡丹','黄庶','宋','宋诗','song-poetry','','[]','四月殘紅日日稀，平陽園檻正芳菲。',32,'全唐诗/poet.song.26000.json','["四月殘紅日日稀，平陽園檻正芳菲。", "春知東館酣賓客，應是陽和未放歸。"]'),
('1e853fe7-897b-4e04-bbc3-8eb7096e9591','和元伯走馬看牡丹','黄庶','宋','宋诗','song-poetry','','[]','城中走馬趁殘春，詩別餘花句句新。',32,'全唐诗/poet.song.26000.json','["城中走馬趁殘春，詩別餘花句句新。", "何似園家不吟醉，姚黄魏紫屬遊人。"]'),
('d4cefd33-f8cb-40b3-b71e-1f69e2105f77','次韵元伯初夏南洋河即事','黄庶','宋','宋诗','song-poetry','','[]','芳菲已去絕音塵，臨水踟躕景又新。',32,'全唐诗/poet.song.26000.json','["芳菲已去絕音塵，臨水踟躕景又新。", "應是溪源來最遠，落花流水洞中春。"]'),
('fa3583ee-2ac3-47d0-a16c-7b8a12091d7a','次韵子儀初夏偶作','黄庶','宋','宋诗','song-poetry','','[]','醉紅方寂寞，吟綠又裝成。',48,'全唐诗/poet.song.26000.json','["醉紅方寂寞，吟綠又裝成。", "急雨荷宜聽，清風簟可迎。", "燕忙諳物態，花盡見時情。", "獨有無言意，不知枯與榮。"]'),
('d782cfac-79ef-4a9d-bfb3-074804eeb172','看春牓偶成','黄庶','宋','宋诗','song-poetry','','[]','每看春牓獨嗟咨，蹭蹬塵埃已十期。',32,'全唐诗/poet.song.26000.json','["每看春牓獨嗟咨，蹭蹬塵埃已十期。", "韓老有知應笑我，歸時無計只癡兒。"]'),
('986ba617-4449-41d2-8360-3c870a8d16a8','陪丞相遊石子澗  其一','黄庶','宋','宋诗','song-poetry','','[]','賓吏親携澗底行，潺湲風遞似相迎。',32,'全唐诗/poet.song.26000.json','["賓吏親携澗底行，潺湲風遞似相迎。", "只應山鬼知公意，乞雨新添瀑布聲。"]'),
('ff5bd38a-377f-4cc3-b051-aa3d21dce480','陪丞相遊石子澗  其二','黄庶','宋','宋诗','song-poetry','','[]','澗下禽魚識上台，聽泉履迹遍蒼苔。',32,'全唐诗/poet.song.26000.json','["澗下禽魚識上台，聽泉履迹遍蒼苔。", "巖邊不欲踟躕久，只恐商王夢遠來。"]'),
('3c290b2c-512e-4750-a680-982b28e2eacf','次韵和真長四季牧童  其一','黄庶','宋','宋诗','song-poetry','','[]','怯雨宜晴不識愁，去隨青草牧春牛。',32,'全唐诗/poet.song.26000.json','["怯雨宜晴不識愁，去隨青草牧春牛。", "無人古路歌兼笑，歸去山花插滿頭。"]'),
('caa1d26e-7074-47ae-a436-097ba43b408f','次韵和真長四季牧童  其二','黄庶','宋','宋诗','song-poetry','','[]','曉牧侵星大暑天，晝尋芳樹綠陰眠。',32,'全唐诗/poet.song.26000.json','["曉牧侵星大暑天，晝尋芳樹綠陰眠。", "惜牛不使衝殘日，歸带黄昏飲小川。"]'),
('478650ce-31e6-4625-b9a4-d55a2e017e16','次韵和真長四季牧童  其三','黄庶','宋','宋诗','song-poetry','','[]','角穿黄穗手橫笳，不省人間有鬢華。',32,'全唐诗/poet.song.26000.json','["角穿黄穗手橫笳，不省人間有鬢華。", "落日西風歸去路，枯桑黄葉兩三家。"]'),
('0def8956-1598-42d7-8556-6eababc96d8b','次韵和真長四季牧童  其四','黄庶','宋','宋诗','song-poetry','','[]','枯笛手持無律呂，清風曲調逐時新。',32,'全唐诗/poet.song.26000.json','["枯笛手持無律呂，清風曲調逐時新。", "數竿冬日渾無價，暖靠牛眠不教人。"]'),
('97e037d2-9ec3-4be3-b1da-be3e88930929','次韵元伯曉出白門','黄庶','宋','宋诗','song-poetry','','[]','山形雲染翠屏曲，溪色練鋪銀漢東。',32,'全唐诗/poet.song.26000.json','["山形雲染翠屏曲，溪色練鋪銀漢東。", "樓臺一軸古今本，行者往來圖畫中。"]'),
('b3247777-6b1d-416d-b955-5ac04c930553','栽竹','黄庶','宋','宋诗','song-poetry','','[]','小檻栽培得此君，綠陰疏韵似相親。',32,'全唐诗/poet.song.26000.json','["小檻栽培得此君，綠陰疏韵似相親。", "從來風月爲三友，吟社新添客一人。"]'),
('5eb8e368-0ad3-48fd-87ba-7376627cdc0b','嵩山','黄庶','宋','宋诗','song-poetry','','[]','峨峨鎮中夏，峻極萬尋隮。',96,'全唐诗/poet.song.26000.json','["峨峨鎮中夏，峻極萬尋隮。", "突兀磨天頂，窈窕入地臍。", "中林興夏雹，半壑卧秋霓。", "泉恐連清漢，峰疑擁碧圭。", "雲高四夷見，雨到八方齊。", "渤澥看如带，青冥上是梯。", "醉堪捫日月，吟可摘婁奎。", "翠蓋何時動，金爲玉檢泥。"]'),
('fdf227c8-2388-4e48-a298-e428b422edbe','隠真齋庭多怪石小詩求數株','黄庶','宋','宋诗','song-poetry','','[]','曾經禹貢清泉骨，今是莓苔幾世孫。',32,'全唐诗/poet.song.26000.json','["曾經禹貢清泉骨，今是莓苔幾世孫。", "知君突兀滿庭下，乞我雨中雲數根。"]'),
('b2e4cbdf-fd1c-4b68-992b-e8dcda7b0860','和元伯中伏夜雨南洋河水泛','黄庶','宋','宋诗','song-poetry','','[]','雨洗三齊中伏月，乖龍連夜起雲門。',32,'全唐诗/poet.song.26000.json','["雨洗三齊中伏月，乖龍連夜起雲門。", "溪聲斗似銀河落，驚斷詩書一夢魂。"]'),
('252f0885-cc7e-4e74-adeb-1ad76915b204','登鄆州溪堂','黄庶','宋','宋诗','song-poetry','','[]','仁智模來物狀親，登臨宜入古圖身。',32,'全唐诗/poet.song.26000.json','["仁智模來物狀親，登臨宜入古圖身。", "慣看韓老詩中景，樹色泉聲似故人。"]'),
('961d68b4-9124-4243-adc3-e26014bc95e9','中秋夜月','黄庶','宋','宋诗','song-poetry','','[]','人間共賞中秋月，酒社詩家意味長。',32,'全唐诗/poet.song.26000.json','["人間共賞中秋月，酒社詩家意味長。", "天上必應霜露早，桂叢凋盡飽青光。"]'),
('0daa4454-fe3a-4ece-ad0c-8b39df3568be','輦下會里人子蒙飲','黄庶','宋','宋诗','song-poetry','','[]','秋風吹客衣，歸思入夢寐。',96,'全唐诗/poet.song.26000.json','["秋風吹客衣，歸思入夢寐。", "相逢在千里，一飲勝百醉。", "果脯隨分列，不減到家味。", "平生金石心，顛倒獨莫棄。", "何時不搔首，共話醫國計。", "恨未得杞梓，欲把斤斧試。", "塵埃鞋履穿，各走車馬地。", "唯茲栖栖懷，酒碗可以慰。"]'),
('f5d9c6df-434a-4e92-b081-02312367f501','探春','黄庶','宋','宋诗','song-poetry','','[]','春色若有價，黄金量山丘。',72,'全唐诗/poet.song.26000.json','["春色若有價，黄金量山丘。", "幾擬把酒吟，浪欲開口酬。", "今朝庭柳枝，拗折絲已柔。", "東風弄五色，漸落草木稠。", "我營賞春資，甕盎蟻已浮。", "山川天開畫，祇擬酩酊遊。"]'),
('18bd1293-e972-4ded-865f-ecf462d9fd72','對花','黄庶','宋','宋诗','song-poetry','','[]','詩昔甫白在，造化困刀尺。',132,'全唐诗/poet.song.26000.json','["詩昔甫白在，造化困刀尺。", "我生幾年後，浪自鎸頑石。", "對花雖把筆，好句恨莫得。", "耒陽與采石，孤墳沒荆棘。", "幾欲肉白骨，再插風雅翼。", "海爲一杯酒，地爲一領席。", "醉坐吟萬物，語出埋霹靂。", "乾坤髓可掬，鬼神淚可滴。", "人生貴適意，身是天地客。", "糟床不可乾，吟紙須强擘。", "花落若解醫，有金費千鎰。"]'),
('de037950-7cf4-49bc-9853-49cabcfd3686','和白雲庵七首 白雲庵','黄庶','宋','宋诗','song-poetry','','[]','白雲無種滿地生，有時出山爲雨露。',32,'全唐诗/poet.song.26000.json','["白雲無種滿地生，有時出山爲雨露。", "老僧惆悵望雲歸，盡日庵前自來去。"]'),
('819a1085-599a-45ee-836b-85f4d135a904','和白雲庵七首 清風軒','黄庶','宋','宋诗','song-poetry','','[]','老僧拂榻人不知，獨與清風事來去。',32,'全唐诗/poet.song.26000.json','["老僧拂榻人不知，獨與清風事來去。", "朝昏宴坐向軒中，此身便是清風主。"]');
